VALUES ('d2920010-0000-0000-0000-000000000001', 'd2920000-0000-0000-0000-000000000000', 'Welcome & Course Overview', '', ARRAY['Describe the elements of boundary law and the different sources of law.','Interpret legal doctrines and principles in property law.','Analyze metes-and-bounds descriptions and construct sequential & simultaneous descriptions.','Distinguish between riparian and littoral rights.']::text[], 1, 15, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, NULL, ARRAY[]::text[]);
