VALUES ('d2920010-0000-0000-0000-000000000003', 'd2920000-0000-0000-0000-000000000000', 'Grading Policy & Expectations', '', ARRAY['Read the slides/handouts and watch the provided videos for each module.','Use the flashcards to master terminology before each quiz.','Work the practice problems — quizzes include randomized computational questions.','Submit homework on time; you may submit a draft 48 hours early for feedback.']::text[], 3, 15, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, NULL, ARRAY[]::text[]);

-- ===== Module 1: Module 1: Historical and Current Common-Law Principles =====
