INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920020-0001-0000-0000-000000000000', 'd2920010-0000-0000-0000-000000000001', 'text', '{"html":"<h2>Welcome to Legal Principles and Boundary Law I</h2><p>This course explores the principles, methods, and legal foundations of surveying property boundaries. Over seven modules you will gain a working knowledge of boundary law, learn to interpret and write legal descriptions, and understand the role of the professional surveyor in boundary determination. The course follows <em>Brown''s Boundary Control and Legal Principles, 7th edition</em> (Robillard &amp; Wilson) and is tailored to <strong>Texas</strong> law.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920020-0001-0000-0000-000000000001', 'd2920010-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Student Outcomes","items":["Describe the elements of boundary law and the different sources of law.","Interpret legal doctrines and principles in property law.","Analyze metes-and-bounds descriptions and construct sequential & simultaneous descriptions.","Distinguish between riparian and littoral rights."]}'::jsonb, 1);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920020-0002-0000-0000-000000000000', 'd2920010-0000-0000-0000-000000000002', 'text', '{"html":"<p>The course is organized into a Getting Started module plus seven content modules. Each module pairs with one or more chapters of Brown''s Boundary Control.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920020-0002-0000-0000-000000000001', 'd2920010-0000-0000-0000-000000000002', 'table', '{"headers":["Module","Topic","Brown Chapters"],"rows":[["1","Historical & current common-law principles","Ch. 1–3"],["2","Sources of laws & related presumptions","Ch. 4"],["3","Legal doctrines / principles in property law","Ch. 8"],["4","Locating sequential conveyances","Ch. 9"],["5","Locating simultaneous conveyances","Ch. 11"],["6","Water rights","Ch. 12"],["7","Creation of metes-and-bounds descriptions","Ch. 5"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920020-0002-0000-0000-000000000002', 'd2920010-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"Required texts: Brown’s Boundary Control and Legal Principles, 7th ed. (Robillard & Wilson, Wiley); and Writing Legal Descriptions, 4th ed. (Wattles)."}'::jsonb, 2);
