INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0001-0000-0000-000000000000', 'd2920110-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why boundaries have a history</h3><p>Boundaries are one of the oldest legal ideas in human society. They appear throughout mythology and Judeo-Christian history; in Roman religion <em>Terminus</em> was the god who protected boundary markers, and disturbing a boundary stone was a sacrilege. Numerous wars, from international conflicts down to neighborhood disputes, have been fought over the location of a line. The instinct to mark territory is so basic that, as Brown wryly notes, animals do it too, but humans formalized it into <strong>law</strong>.</p><p>Medieval England gave us two practices that survive conceptually in modern surveying. <strong>Livery of seisin</strong> was a ceremony that transferred land from one party to another, often by handing over a clod of earth or a twig on the land itself, before written deeds were common. <strong>Beating the bounds</strong> (the Ritual of Perambulation) was an annual walk of a parish''s boundaries so that the community collectively remembered where the lines ran, an oral and physical record-keeping system that predated reliable written descriptions.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0001-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Common law, statute law, and equity</h3><p>Three streams of law govern land. <strong>Common (case) law</strong> is judge-made law built up case by case; under the doctrine of <em>stare decisis</em> (\"to stand by things decided\") courts follow prior decisions, giving boundary law its stability and predictability. <strong>Statute (legislative) law</strong> is enacted by legislatures and may restrict or define rights, such as the federal PLSS enabling acts or the Texas codes. <strong>Equity</strong> supplies remedies when money damages are inadequate.</p><ul><li><strong>Equitable remedy (relief):</strong> a court-ordered action directing a party to do or not do something, such as an <em>injunction</em> or <em>specific performance</em>, obtained when a legal remedy like money damages cannot adequately redress the injury.</li><li><strong>Ejectment:</strong> a lawsuit brought to remove a party who is wrongfully occupying real property.</li></ul><p>In the United States there are, in most instances, no federal laws describing real-property rights. Real property is governed by the law of the place where the land lies, the <em>lex loci</em>, and English common law is the predominant background law in most states.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0001-0000-0000-000000000002', 'd2920110-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Lex loci: real property is exclusively subject to the laws and jurisdiction of the state in which it is located. Transactions are governed by that state''s law, except where title is held by the United States or is specifically under federal jurisdiction."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0001-0000-0000-000000000003', 'd2920110-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Texas is a common-law state, but its original land titles never came from the United States. Every Texas chain of title traces to one of four ''sovereigns of the soil'' - Spain, Mexico, the Republic of Texas, or the State of Texas. Because Texas land was never federal public domain, Texas has no PLSS township-range grid (covered in Lesson 2)."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0001-0000-0000-000000000004', 'd2920110-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Surveyors and lawyers: who decides what</h3><p>Brown draws a sharp division of labor that frames this entire course. <strong>Boundaries do not determine rights in land; they determine the limits of rights in land.</strong> Surveyors determine those limits. Lawyers and courts determine the rights themselves. A useful pair of maxims: <em>where</em> a boundary is located is a question of fact (the surveyor''s domain), while <em>what</em> the boundary is, the legal meaning of the words, is a question of law (the court''s domain). The surveyor must understand the law well enough to find the facts correctly, but may not rewrite the parties'' intent.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0001-0000-0000-000000000005', 'd2920110-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Boundary law is ancient; livery of seisin and beating the bounds show how transfer and boundary memory worked before reliable written deeds.","Three streams of law govern land: common (case) law under stare decisis, statute law, and equity.","Real property is governed by the lex loci - the law of the state where the land lies.","Boundaries determine the limits of rights, not the rights themselves; surveyors find facts (where), courts decide law (what).","Texas is a common-law state, but its titles flow from four sovereigns, not the U.S. federal government."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0002-0000-0000-000000000000', 'd2920110-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Three methods of creating a boundary</h3><p>Brown organizes boundary creation into three methods. A landowner has broad freedom to lay out lines, subject only to the rights of adjoiners and senior owners.</p><ul><li><strong>By action (ground survey):</strong> so long as a person does not go beyond their own exterior boundaries, a parcel may be subdivided in any manner the law permits by physically establishing lines on the ground.</li><li><strong>By words (in a deed):</strong> a boundary may be created by words in a legal document - aliquot parts (East 1/2, West 200 feet, North 20 acres) or a metes-and-bounds description. A line created by words is <strong>as binding and as legal as if it had been run on the ground</strong> by a surveyor.</li><li><strong>By law:</strong> this includes statute law (the federal PLSS, and the systems of Texas and Georgia) and common law.</li></ul><p>Under common law there is no requirement that a survey ever be performed to create a valid boundary.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0002-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Texas differs (no PLSS): On annexation in 1845 Texas retained all its vacant and unappropriated public lands (over 200 million acres), administered by the General Land Office (GLO). Because the land was never federal public domain, Texas has no PLSS township-range grid; its tracts are irregular metes-and-bounds parcels identified by original survey name plus a GLO abstract number."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0002-0000-0000-000000000002', 'd2920110-0000-0000-0000-000000000002', 'table', '{"headers":["Method","How the boundary is fixed","Example"],"rows":[["By action","Lines physically run/marked on the ground within the owner''s exterior limits","A field survey subdividing a tract into lots"],["By words","A written description in a deed or will; binding as if run on the ground","Aliquot parts; a metes-and-bounds call"],["By law","Statute law (PLSS, Texas, Georgia) or common law","PLSS section lines; statutory subdivision rules"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0002-0000-0000-000000000003', 'd2920110-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Corners and monuments</h3><p>Two terms are easy to confuse. A <strong>corner</strong> is any end or change of direction in a boundary; it is a point, a legal concept that exists whether or not anything physical marks it. A <strong>monument</strong> is the physical object at or near a corner that serves as a witness to it.</p><ul><li><strong>Natural monuments:</strong> streams, rivers, roads (as physical features), trees, and the like. A natural feature can evidence a line.</li><li><strong>Artificial monuments:</strong> objects placed by people - a brass cap, an iron pipe, a wooden hub.</li></ul><p>For a corner and its monument to be <strong>controlling</strong> in a description, the corner must be called for in the written conveyance and the monument must have been identified at the time the conveyance was made. A property corner should not be placed on a curved line in a metes-and-bounds description.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0002-0000-0000-000000000004', 'd2920110-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Boundaries are fixed; property lines may move</h3><p>A foundational distinction: a <strong>boundary line remains fixed forever where it was originally located</strong>, but a <strong>property line may change</strong> by operation of certain legal doctrines. The original surveyor <em>creates</em> boundaries; all later surveyors <em>ascertain</em> (retrace) them. Once boundaries are created and rights have been distributed according to them, neither the landowner nor a surveyor may alter or modify them.</p><p>The recognized doctrines that may modify or change a property line are:</p><ul><li><strong>Agreement</strong> (written or oral)</li><li><strong>Estoppel</strong></li><li><strong>Acquiescence</strong></li><li><strong>Adverse possession</strong></li><li><strong>Judicial action</strong></li></ul><p>The law does not provide for two original descriptions of the same parcel. Multiple descriptions may exist, but only one is controlling: there is one original boundary survey and description, and every later one is a retracement.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0002-0000-0000-000000000005', 'd2920110-0000-0000-0000-000000000002', 'callout', '{"type":"success","text":"Memory hook: The original surveyor CREATES boundaries. Every other surveyor ASCERTAINS them. Words and meanings in a description are interpreted as of the date the description was written, not as of the date of the retracement."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0002-0000-0000-000000000006', 'd2920110-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Boundaries are created three ways: by action (ground survey), by words (deed), and by law (statute/common).","A boundary created by words is as binding as one run on the ground.","A corner is a point (any end or change of direction); a monument is the physical witness at or near it.","A boundary is fixed forever at its original location, but a property line may change by agreement, estoppel, acquiescence, adverse possession, or judicial action.","Texas uses metes-and-bounds keyed to GLO survey + abstract number, not the PLSS township-range grid."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0003-0000-0000-000000000000', 'd2920110-0000-0000-0000-000000000003', 'text', '{"html":"<h3>What is an estate?</h3><p>An <strong>estate in land</strong> is a right or interest in property - it may be a fee ownership interest, a lease for a period of years, or some other category. There are two basic ways to acquire a real-property interest: by <strong>deed</strong> (purchase) and by <strong>possession</strong> (unwritten methods, such as adverse possession). Estates are traditionally divided into <strong>freehold</strong> estates (of uncertain duration and historically associated with seisin - fee simple, fee tail, life estate) and <strong>non-freehold</strong> estates (of fixed or determinable duration - the leasehold/tenancy estates).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0003-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Fee simple absolute and fee tail</h3><p><strong>Fee simple absolute</strong> is the highest interest in land a person can hold in the United States. The word <em>fee</em> (from <em>fief</em>) means a freehold estate that can be inherited or devised; <em>simple</em> means without limitation to any particular class of heirs; <em>absolute</em> means without conditions or limitations in time. The holder owns everything except what is reserved by deed, by the U.S. Constitution, or by legislative action. Even fee simple absolute remains subject to four governmental limitations: <strong>eminent domain, escheat, the police power, and taxation</strong>.</p><p><strong>Fee tail</strong> is a freehold estate limited by the grantor to the heirs of the grantee''s body (or to a specific class, male or female). If the limiting condition is breached, the land returns to the grantor or the grantor''s heirs.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0003-0000-0000-000000000002', 'd2920110-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Life estate and the defeasible fees</h3><p>A <strong>life estate</strong> is an estate whose duration is measured by the life of one or more persons, created by deed or will. (Historic spousal forms: <em>curtesy</em>, a husband''s right in his deceased wife''s real estate, and <em>dower</em>, the corresponding right of a surviving wife.)</p><p><strong>Defeasible fees</strong> are created when a grantor transfers land conditionally:</p><ul><li><strong>Fee simple determinable</strong> - ownership continues only <em>as long as</em> a situation continues; created by words like \"<em>so long as</em>,\" \"<em>until</em>,\" \"<em>while</em>.\" The grantor keeps a <strong>possibility of reverter</strong>; the land returns <strong>automatically</strong> if the stated event occurs or fails to occur - even after several later changes in title.</li><li><strong>Fee upon condition subsequent</strong> - created by conditional language like \"<em>but if</em>,\" \"<em>provided that</em>,\" \"<em>may enter</em>.\" The estate does <strong>not</strong> end automatically; only the grantor holds a <strong>right of re-entry</strong> and must affirmatively exercise it to retake title.</li></ul>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0003-0000-0000-000000000003', 'd2920110-0000-0000-0000-000000000003', 'table', '{"headers":["Estate","Triggering words","Future interest","Ends automatically?"],"rows":[["Fee simple determinable","so long as, until, while","Possibility of reverter (grantor)","Yes - reverts automatically"],["Fee on condition subsequent","but if, provided that, may enter","Right of re-entry / power of termination (grantor)","No - grantor must act"],["Life estate, then back to grantor","(natural end of life)","Reversion (grantor)","Yes - at end of measuring life"],["Life estate, then to third party","(natural end of life)","Remainder (third party)","Yes - at end of measuring life"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0003-0000-0000-000000000004', 'd2920110-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Present interests vs. future interests</h3><p>Every grant of a lesser estate leaves something behind in the future. A <strong>reversion</strong> is the residue of an estate left in the grantor (or the grantor''s successors); it is the right to repossess and resume full ownership after a temporary separation. A <strong>remainder</strong> is a future interest created in a third party <em>at the same time</em> and by the <em>same grant</em> as the preceding estate; it takes effect when the prior estate ends. Example: \"to A for life, then to B\" gives A a present life estate and B a remainder; \"to A for life\" alone leaves the grantor a reversion.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0003-0000-0000-000000000005', 'd2920110-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Texas differs: Tex. Prop. Code Section 5.001 presumes a conveyance passes the ENTIRE estate (fee simple) unless a lesser estate is expressly limited or conveyed. Texas also abolished several old common-law canons by Section 5.042 - the Rule in Shelley''s Case and the Doctrine of Worthier Title - giving effect to such limitations according to the grantor''s intent. (Note: Section 5.042 does NOT abolish destructibility of contingent remainders; Texas rejected that by case law instead.)"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0003-0000-0000-000000000006', 'd2920110-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Freehold estates (fee simple, fee tail, life estate) historically carried seisin; non-freehold estates are the leaseholds/tenancies.","Fee simple absolute is the greatest estate but still bows to eminent domain, escheat, police power, and taxation.","Fee simple determinable (''so long as'') reverts automatically (possibility of reverter); fee on condition subsequent (''but if'') requires the grantor to exercise a right of re-entry.","A reversion stays with the grantor; a remainder goes to a third party created by the same grant.","Texas presumes a conveyance passes the whole fee unless a lesser estate is expressly limited (Section 5.001)."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0004-0000-0000-000000000000', 'd2920110-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Three related but distinct concepts</h3><p>Brown carefully separates three ideas students tend to merge:</p><ul><li><strong>Ownership:</strong> the collection of rights to use and enjoy property, including the right to transmit it to others. Land is often described as a <em>bundle of rights</em>, and those rights may be divided among many people.</li><li><strong>Possession:</strong> the detention and control - the actual or ideal custody - of something for one''s use and enjoyment. Possession is about use or control, not paper ownership.</li><li><strong>Title:</strong> the right to, or ownership in, land, and also the <em>evidence</em> of that ownership. Title is the combination of physical and written evidence that vests ownership in a person.</li></ul><p>Title and interest are <strong>not</strong> synonymous: a lienholder has an interest in the land but not title.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0004-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Rights, ownership, and interest</h3><p>A practical hierarchy distinguishes who can do what with a parcel:</p><ul><li><strong>Ownership</strong> - can permanently occupy; the owner pays the taxes.</li><li><strong>Right</strong> - can use but not occupy (e.g., an easement); the use cannot be hindered by the owner.</li><li><strong>Interest</strong> - financial stake with no right to use or occupy (e.g., a mortgage or lien).</li></ul><p>A person can legally convey only the quantity and quality of interest to which they hold title: if you own a half interest, you can sell only a half interest.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0004-0000-0000-000000000002', 'd2920110-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Sources of title and the chain of title</h3><p>Title can arise from many sources: a <strong>patent</strong> from the state or the United States, a deed, descent or private grant, a will, adverse possession, eminent domain, escheat, dedication, a court judgment, prior appropriation, and water activities. The <strong>chain of title</strong> is the continuous, sequential evidence of title. Here Brown flags a crucial difference in scope: <strong>attorneys</strong> may only have to search back a statutory number of years to perfect marketable title, but <strong>surveyors must research all the way back to the original patent</strong> to perfect the boundary description.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0004-0000-0000-000000000003', 'd2920110-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"Color of title: a written instrument that appears to transfer ownership but, due to some defect (such as a lack of title in the grantor), does not actually do so - it passes only the appearance, or ''color,'' of title. This becomes important for adverse possession in Module 3."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0004-0000-0000-000000000004', 'd2920110-0000-0000-0000-000000000004', 'table', '{"headers":["Instrument / interest","What it is"],"rows":[["Lien","A charge, security, or encumbrance on property to secure a debt."],["Lease","A contract conveying an estate for a limited period in exchange for value, while the owner retains ownership."],["License","Permission by competent authority to do an act that would otherwise be illegal; not an interest in land."],["Mortgage","A conditional conveyance of an estate as a pledge to secure a debt (mortgagee = lender)."],["Deed of trust","A three-party security device: trustor (borrower), trustee (holds the deed), and beneficiary (lender)."],["Escrow","A deed delivered to a third person to hold until a condition is met, then delivered to the grantee."]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0004-0000-0000-000000000005', 'd2920110-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas differs (BFP / recording): Texas is a pure ''notice'' jurisdiction (Tex. Prop. Code Section 13.001-13.002). A subsequent purchaser for value without notice of a prior unrecorded conveyance takes free of it - and prevails even if the prior grantee records first. Possession charges a purchaser with constructive notice only if it is ''visible, open, exclusive, and unequivocal'' (Madison v. Gordon). The bona fide purchaser doctrine is developed fully in Module 2."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0004-0000-0000-000000000006', 'd2920110-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Ownership is the bundle of rights; possession is custody/control; title is ownership plus the evidence of it.","Title is not the same as interest - a lienholder has interest but not title.","You can convey only the quantity and quality of interest you hold (own half, sell half).","Surveyors research the chain of title back to the original patent; attorneys may stop at a statutory number of years.","Color of title is an instrument that looks like it conveys title but, due to a defect, does not."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000000', 'd2920110-0000-0000-0000-000000000005', 'text', '{"html":"<h3>What a deed is</h3><p>A <strong>deed</strong> is a written, signed (and historically sealed) legal instrument used to grant a right in land. The person transferring the property is the <strong>grantor</strong>; the person receiving it is the <strong>grantee</strong>. Title is the bundle of rights conveyed - a party may hold either a legal or an equitable interest. Any oral agreement by the conveying party that purports to change fixed boundaries is, at best, voidable; the Statute of Frauds requires interests in land to be conveyed in writing.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Types of deeds and their warranties</h3><p>Deeds differ chiefly in how much the grantor warrants the title:</p><ul><li><strong>(General) warranty deed:</strong> the grantor warrants the title against defects arising at <em>any</em> time, before or after the grantor''s connection to the land - clear title back to the property''s origins, with no hidden liens or encumbrances. The broadest protection for the grantee.</li><li><strong>Special (specialty) warranty deed:</strong> warrants the title <em>only</em> against defects arising during the grantor''s own period of ownership.</li><li><strong>Quitclaim deed:</strong> conveys whatever interest the grantor possesses, <em>if any</em>, with <strong>no warranty of title</strong>.</li><li><strong>Grant deed:</strong> conveys the fee title owned by the grantor; if the grantor later acquires a better title (after-acquired title), it passes automatically to the grantee without new documents. In most states the word \"grant\" implies certain statutory covenants unless stated otherwise.</li><li><strong>Easement deed:</strong> grants the right of a particular use of a property, not the fee.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000002', 'd2920110-0000-0000-0000-000000000005', 'table', '{"headers":["Deed type","Scope of warranty","Grantee protection"],"rows":[["General warranty","Against all defects, entire chain of title","Greatest"],["Special warranty","Only defects arising during grantor''s ownership","Moderate"],["Grant deed","Implied statutory covenants; after-acquired title passes","Moderate"],["Quitclaim","None - conveys grantor''s interest, if any","Least"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000003', 'd2920110-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"Texas differs (deed covenants): A Texas general warranty deed gets its broad protection from express ''grant, sold, and conveyed... warrant and forever defend'' language (Tex. Prop. Code Section 5.022). Section 5.023 narrows the IMPLIED covenants of ''grant''/''convey'' to only two - that the grantor has not previously conveyed the estate and that it is free from encumbrances. Unlike common law, ''grant'' in Texas does NOT imply a covenant of seisin (that the grantor actually owns the estate)."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000004', 'd2920110-0000-0000-0000-000000000005', 'accordion', '{"sections":[{"title":"The Texas quitclaim peculiarity - grantee usually NOT a bona fide purchaser","content":"<p>Classic Texas rule: a grantee under a <strong>quitclaim</strong> (and its successors) is generally <strong>not</strong> a bona fide purchaser. The quitclaim is treated as <em>notice</em> that the grantor''s title may be defective, so the grantee takes subject to prior outstanding claims even if value was paid without actual notice (<em>Woodward v. Ortiz</em>, 1951). A quitclaim ''is not a conveyance or a muniment of title'' (<em>Rogers v. Ricane Enterprises</em>, 1994). Courts examine the whole instrument, not the label: a deed conveying the <em>property itself</em> can support BFP status, while one conveying only the grantor''s <em>right, title, and interest</em> cannot (<em>Geodyne v. Newton</em>, 2005).</p><p><strong>2021 softening:</strong> Tex. Prop. Code Section 13.006 (eff. Sept. 1, 2021) provides that after the <em>fourth anniversary</em> of recording, a quitclaim no longer affects the good faith of a subsequent purchaser and is not notice of unrecorded conveyances. So for quitclaims recorded on/after that date there is a four-year cleansing window - but the classic rule still binds the immediate grantee and during the first four years.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000005', 'd2920110-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Required elements of a valid deed</h3><p>A valid deed generally requires:</p><ul><li><strong>Competent parties and proper subject matter</strong> - a named grantor and a grantee capable of taking title (a deed to a dead person, or to a fictitious person, is void; a deed using an assumed name is valid).</li><li><strong>Consideration</strong> - a sum may be recited to validate the deed in some jurisdictions and need not reflect actual value; at early common law it was required, but in many states it no longer is.</li><li><strong>A written or printed form</strong> - the Statute of Frauds requires a conveyance of any interest in land to be in writing, reasonably explicit as to essential terms.</li><li><strong>Sufficient and legal wording</strong> - a description sufficient to identify the land, meaning one capable of being located by a competent surveyor. Parol evidence may help establish sufficiency or resolve a <em>latent</em> ambiguity, but may never cure a <em>patent</em> ambiguity.</li><li><strong>Delivery</strong> - title does not pass until the deed is delivered; delivery turns on the grantor''s <em>intent</em> that the deed be in force, not merely physical handover.</li><li><strong>Acceptance</strong> - completed by the grantee''s acceptance, which is presumed when the conveyance benefits the grantee.</li></ul>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000006', 'd2920110-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Standard clauses, and what is NOT required</h3><p>A typical deed contains a date, the names of the parties, <strong>recitals</strong> (statements of fact, often beginning \"Whereas,\" \"Witnesseth,\" or \"Know all men by these presents\"), the <strong>operative words of conveyance</strong> with consideration and receipt, the property <strong>description</strong> with any exceptions or reservations, the <strong>habendum</strong> clause (\"To have and to hold\"), conditions and covenants, execution/signatures/seals, and an acknowledgment.</p><ul><li><strong>Reservation:</strong> a clause creating a <em>new</em> interest in the grantor that had no prior existence (e.g., a reserved easement or rent) - a taking back of an interest.</li><li><strong>Exception:</strong> excludes from the conveyance an <em>already existing</em> part of the thing described (e.g., a house or orchard on the land).</li><li><strong>Habendum:</strong> defines the extent of ownership; it may lessen, explain, or qualify the estate granted, but may not contradict it.</li></ul><p><strong>Not required</strong> for a valid deed: consideration (generally), a date, attestation by witnesses, and notarial acknowledgment. Acknowledgment may be required to <em>record</em> the deed, but recordation itself is not required for the deed to be valid between the parties.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000007', 'd2920110-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"Ambiguities: A PATENT ambiguity is obvious on the face of the document (e.g., a township that does not exist in the named county); it cannot be cured by extrinsic evidence and may make the conveyance void or voidable. A LATENT ambiguity does not appear in the words but arises when the description is applied to the ground (e.g., ''to the NE corner of John Smith''s corral'' when there are two such corrals); parol/extrinsic evidence is admissible to apply, but not to complete, the description."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0005-0000-0000-000000000008', 'd2920110-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["Deeds differ by warranty: general warranty (all defects) > special warranty (grantor''s ownership period) > quitclaim (no warranty).","A grant deed passes after-acquired title automatically and implies statutory covenants.","Required elements: competent parties, written form, sufficient description, delivery (turns on intent), and acceptance.","NOT required for validity: consideration (generally), a date, witnesses, or notarial acknowledgment; recordation is not required for validity.","Texas: warranty comes from express ''warrant and forever defend'' language; ''grant'' implies only no-prior-conveyance and no-encumbrances (no covenant of seisin)."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000001', 'Stare decisis', 'The common-law doctrine of standing by prior decided cases; courts follow precedent, giving boundary law stability and predictability.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000002', 'Lex loci', 'The law of the place; real property is governed exclusively by the law of the state where the land is located.', 'Latin for ''law of the place''.', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000003', 'Livery of seisin', 'A medieval English ceremony that effected the transfer of land from one party to another, typically before written deeds were common.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000004', 'Beating the bounds', 'The Ritual of Perambulation - an annual community walk of a parish''s boundaries to perpetuate the memory of where the lines ran.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000005', 'Ejectment', 'A lawsuit brought to remove a party who is wrongfully occupying real property.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000006', 'Corner', 'Any end or change of direction in a boundary; a point that exists in law whether or not it is physically marked.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000007', 'Monument', 'A physical object at or near a corner that witnesses it; either natural (stream, tree) or artificial (iron pipe, brass cap).', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000008', 'Creating vs. ascertaining a boundary', 'The original surveyor creates boundaries; all subsequent surveyors merely ascertain (retrace) them.', 'Only one survey is ''original''; the rest are retracements.', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000009', 'Boundary line vs. property line', 'A boundary line is fixed forever at its original location; a property line may change by agreement, estoppel, acquiescence, adverse possession, or judicial action.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000010', 'Vara (Texas)', 'The Spanish/Mexican unit of length used in Texas surveys, legally fixed at 33 1/3 inches (2.7778 ft); 36 varas = exactly 100 ft.', 'About 33.33 inches.', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000011', 'Texas League and Labor', 'Spanish/Mexican grant units: a labor is about 177.1 acres (farmland) and a league/sitio about 4,428.4 acres (grazing); a standard married-head-of-family grant was one league plus one labor (~4,605.5 acres).', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000012', 'Fee simple absolute', 'The highest estate in U.S. land: inheritable, without limitation to a class of heirs, and without time conditions; still subject to eminent domain, escheat, police power, and taxation.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000013', 'Freehold vs. non-freehold estate', 'Freehold estates (fee simple, fee tail, life estate) are of uncertain duration and historically carried seisin; non-freehold estates are leaseholds/tenancies of fixed or determinable duration.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000014', 'Fee simple determinable', 'A defeasible fee that lasts only ''so long as''/''until'' a stated situation continues; leaves a possibility of reverter and reverts to the grantor automatically.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000015', 'Fee simple on condition subsequent', 'A defeasible fee created by ''but if''/''provided that'' language; does not end automatically - the grantor must exercise a right of re-entry to retake title.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000016', 'Reversion', 'The residue of an estate left in the grantor (or successors) - the right to repossess after a temporary separation, e.g., after a life estate.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000017', 'Remainder', 'A future interest created in a third party by the same grant as the preceding estate, taking effect when that prior estate ends.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000018', 'Title', 'The right to or ownership in land, and the evidence of that ownership - the combination of physical and written evidence that vests ownership in a person.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000019', 'Possession', 'The detention and control, or actual or ideal custody, of property for one''s use and enjoyment; concerned with use/control, not paper ownership.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000020', 'Bundle of rights', 'The concept that land ownership is a collection of separable rights (use, exclude, convey, mineral, water) that may be divided among many holders.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000021', 'Chain of title', 'The continuous sequential evidence of title; surveyors must research it back to the original patent to perfect the boundary description.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000022', 'Color of title', 'A written instrument that purports to convey ownership but, due to a defect such as the grantor''s lack of title, does not - passing only the appearance of title.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000023', 'Lien', 'A charge, security, or encumbrance on property to secure a debt; an interest in the land but not title.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000024', 'General warranty deed', 'A deed in which the grantor warrants title against all defects arising at any time, back through the entire chain of title; the broadest grantee protection.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000025', 'Special (specialty) warranty deed', 'A deed warranting title only against defects arising during the grantor''s own period of ownership.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000026', 'Quitclaim deed', 'A deed conveying whatever interest the grantor possesses, if any, with no warranty of title; in Texas the grantee is generally not a bona fide purchaser.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000027', 'Grantor vs. grantee', 'The grantor is the person conveying (transferring) the property; the grantee is the person receiving it.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000028', 'Reservation vs. exception', 'A reservation creates a NEW interest in the grantor that had no prior existence; an exception excludes an ALREADY EXISTING part of the thing described.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000029', 'Habendum clause', 'The ''To have and to hold'' clause that defines the extent of ownership; it may lessen, explain, or qualify the estate granted but may not contradict it.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920140-0000-0000-0000-000000000030', 'Patent vs. latent ambiguity', 'A patent ambiguity is obvious on the face of the deed and cannot be cured by extrinsic evidence; a latent ambiguity appears only when the description is applied to the ground and may be explained by parol evidence.', NULL, 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000001', 'Under the common-law doctrine of stare decisis, what are courts expected to do?', 'multiple_choice', '["Follow prior decided cases (precedent) so the law remains stable and predictable","Apply only statutes enacted by the legislature, ignoring earlier rulings","Re-decide each boundary dispute from scratch without regard to past cases","Defer entirely to the surveyor''s opinion on the meaning of the deed"]'::jsonb, 'Follow prior decided cases (precedent) so the law remains stable and predictable', 'Stare decisis (''to stand by things decided'') directs courts to follow precedent, which gives boundary law stability. It is not limited to statutes (that is statute law), it does not require re-deciding from scratch, and courts - not surveyors - decide the legal meaning of deed language.', 'easy', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000002', 'Brown states that ''boundaries do not determine rights in land; they determine the limits of rights in land.'' Which professional, by this division of labor, ultimately determines the rights themselves?', 'multiple_choice', '["The lawyer or the court","The original surveyor","The retracing surveyor","The county recorder"]'::jsonb, 'The lawyer or the court', 'Surveyors determine the limits of rights (where the line is - a question of fact); lawyers and courts determine the rights and the legal meaning of words (what the line is - a question of law). The recorder merely files instruments.', 'easy', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000003', 'The principle of lex loci means that real property is governed by the law of the United States as a whole, uniformly across all states.', 'true_false', '["True","False"]'::jsonb, 'False', 'Lex loci means ''law of the place'': real property is governed by the law of the particular state where the land is located, except where title is in the United States or the matter is specifically under federal jurisdiction. There is generally no uniform federal law of real-property rights.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000004', 'A landowner writes a boundary into a deed using a metes-and-bounds description but never has the line physically staked on the ground. What is the legal status of that boundary?', 'multiple_choice', '["It is as binding and legal as if it had been run on the ground by a surveyor","It is invalid until a licensed surveyor monuments it on the ground","It creates only an equitable interest, not a legal boundary","It is voidable at the option of any adjoining landowner"]'::jsonb, 'It is as binding and legal as if it had been run on the ground by a surveyor', 'A boundary may be created by words in a legal document, and Brown states that such a line is as binding and as legal as if it were run on the ground. Common law imposes no requirement that a survey ever be performed.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000005', 'Which statement correctly distinguishes a corner from a monument?', 'multiple_choice', '["A corner is any end or change of direction in a boundary; a monument is the physical object at or near that corner","A monument is any end or change of direction in a boundary; a corner is the physical object marking it","A corner and a monument are interchangeable terms for the same physical marker","A corner must always be a natural feature; a monument must always be artificial"]'::jsonb, 'A corner is any end or change of direction in a boundary; a monument is the physical object at or near that corner', 'A corner is a point - any end or change of direction in the boundary - that exists in law whether or not marked. A monument is the physical witness (natural or artificial) at or near it.', 'easy', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000006', 'Which of the following is NOT one of the recognized doctrines by which a property line may be modified or changed after boundaries are created?', 'multiple_choice', '["Recordation of the deed","Agreement","Acquiescence","Adverse possession"]'::jsonb, 'Recordation of the deed', 'Brown lists the boundary-modification doctrines as agreement, estoppel, acquiescence, adverse possession, and judicial action. Recordation merely gives public notice; it does not modify a property line.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000007', 'Why does Texas have no PLSS township-range grid, unlike most western states?', 'multiple_choice', '["On annexation in 1845 Texas retained its public lands; the land was never federal public domain, so it was never surveyed into the federal PLSS","The federal government surveyed Texas late, after the PLSS program had ended","Texas adopted the PLSS but renamed townships as ''leagues''","Texas surveyors could not measure accurately enough to lay out a grid"]'::jsonb, 'On annexation in 1845 Texas retained its public lands; the land was never federal public domain, so it was never surveyed into the federal PLSS', 'Texas was an independent republic and kept its vacant and unappropriated public lands at annexation. Because the land was never federal public domain, the federal PLSS never applied; Texas tracts are metes-and-bounds keyed to a GLO survey and abstract number.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000008', 'In Texas surveying units, the vara is legally fixed at how many inches?', 'numeric_input', '[]'::jsonb, '33.333', 'The vara was legally fixed at 33 1/3 inches (33.333... in, or 2.7778 ft). A handy check: 36 varas equal exactly 100 feet. (Answers of 33.33 or 33 1/3 are equivalent.)', 'easy', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000009', 'Which set of words, used in a conveyance, creates a fee simple determinable?', 'multiple_choice', '["''so long as,'' ''until,'' ''while''","''but if,'' ''provided that,'' ''may enter''","''to have and to hold forever''","''grant, sold, and conveyed''"]'::jsonb, '''so long as,'' ''until,'' ''while''', 'Durational words (''so long as,'' ''until,'' ''while'') create a fee simple determinable, which reverts automatically and leaves the grantor a possibility of reverter. Conditional words (''but if,'' ''provided that'') create a fee on condition subsequent. The other phrases are habendum and granting language.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000010', 'A grant reads: ''to the City, but if the land is ever used for commercial purposes, the grantor may re-enter and retake the property.'' Twenty years later the City opens a store on the land. What happens to title?', 'multiple_choice', '["Nothing automatically; the grantor must affirmatively exercise the right of re-entry to retake title","Title reverts to the grantor automatically the instant the store opens","Title is void and escheats to the State","The City keeps absolute title because the condition is unenforceable"]'::jsonb, 'Nothing automatically; the grantor must affirmatively exercise the right of re-entry to retake title', 'The ''but if ... may re-enter'' language creates a fee simple on condition subsequent, which does not end automatically. Only the grantor holds the right of re-entry and must exercise it. By contrast, a fee simple determinable (''so long as'') would revert automatically.', 'hard', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000011', 'In the grant ''to A for life, then to B,'' what future interest does B hold?', 'multiple_choice', '["A remainder","A reversion","A possibility of reverter","A right of re-entry"]'::jsonb, 'A remainder', 'B holds a remainder - a future interest created in a third party by the same grant as the preceding (life) estate, taking effect when the life estate ends. A reversion would be retained by the grantor; the other two interests follow defeasible fees.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000012', 'Even fee simple absolute - the greatest estate in U.S. land - remains subject to four governmental limitations. Which list states them correctly?', 'multiple_choice', '["Eminent domain, escheat, police power, and taxation","Mortgage, lien, lease, and license","Dower, curtesy, reversion, and remainder","Agreement, estoppel, acquiescence, and adverse possession"]'::jsonb, 'Eminent domain, escheat, police power, and taxation', 'Brown lists the four limitations on fee simple absolute as eminent domain, escheat, the police power, and taxation. The other options are security/interest devices, future interests, or boundary-modification doctrines.', 'easy', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000013', 'Under Tex. Prop. Code Section 5.001, a conveyance is presumed to pass only a life estate unless the grantor expressly states that fee simple is intended.', 'true_false', '["True","False"]'::jsonb, 'False', 'It is the opposite. Texas presumes a conveyance passes the ENTIRE estate (fee simple) unless a lesser estate is expressly limited or conveyed. This is a key Texas divergence reinforcing grantor intent.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000014', 'Explain the difference between a freehold estate and a non-freehold estate, giving one example of each.', 'short_answer', '[]'::jsonb, 'A freehold estate is of uncertain duration and historically carried seisin (e.g., fee simple absolute, life estate); a non-freehold estate is of fixed or determinable duration (e.g., a leasehold/tenancy for a term of years).', 'Freehold estates (fee simple, fee tail, life estate) are the inheritable/uncertain-duration estates that historically carried seisin; non-freehold estates are the leasehold/tenancy estates of fixed or determinable duration. Any correct example of each earns credit.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000015', 'A surveyor researching a boundary must trace the chain of title back to which point, and how does this differ from an attorney''s typical search?', 'multiple_choice', '["Back to the original patent; an attorney may stop after a statutory number of years to perfect marketable title","Back only the statutory number of years; an attorney must go to the original patent","Back to the most recent deed only; an attorney searches the full chain","Both must go back exactly 60 years in every state"]'::jsonb, 'Back to the original patent; an attorney may stop after a statutory number of years to perfect marketable title', 'Surveyors must research to the original patent to perfect the boundary description, while attorneys may only need to search back a statutory number of years to perfect marketable title.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000016', 'Maria owns a one-half undivided interest in a tract. She signs a deed purporting to convey the entire fee to a buyer. What can she legally convey?', 'multiple_choice', '["Only her one-half interest, because a person can convey only the quantity and quality of interest to which she holds title","The entire fee, because the deed says so","Nothing, because a co-owner can never convey without the others'' signatures","The entire fee, but only if the buyer pays full market value"]'::jsonb, 'Only her one-half interest, because a person can convey only the quantity and quality of interest to which she holds title', 'A person can legally convey only the quantity and quality of interest owned. Maria holds a half interest, so she can pass only a half interest regardless of what the deed recites.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000017', 'Which best distinguishes ownership, possession, and title?', 'multiple_choice', '["Ownership is the bundle of rights; possession is custody/control of the property; title is ownership plus the evidence of it","Ownership and title are identical; possession is a synonym for both","Possession is the bundle of rights; title is mere custody; ownership is only the written evidence","Title is custody of the land; ownership is the written deed; possession is the right to exclude"]'::jsonb, 'Ownership is the bundle of rights; possession is custody/control of the property; title is ownership plus the evidence of it', 'Ownership is the collection (bundle) of rights; possession is the detention/control of the property for use and enjoyment; title is the right to/ownership in land together with the evidence of that ownership. Title and interest are also not synonymous - a lienholder has interest but not title.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000018', 'A deed has a defect - the grantor lacked title - so it does not actually transfer ownership, yet it appears on its face to do so. What is this called?', 'multiple_choice', '["Color of title","A muniment of title","Marketable title","Equitable title"]'::jsonb, 'Color of title', 'Color of title is the appearance of a legally enforceable right of ownership created by a written instrument that, due to a defect (such as the grantor''s lack of title), does not actually transfer ownership. It becomes important in adverse-possession analysis.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000019', 'In Texas, a subsequent purchaser for value without notice of a prior unrecorded deed will lose to the prior grantee if the prior grantee records first.', 'true_false', '["True","False"]'::jsonb, 'False', 'Texas is a pure ''notice'' jurisdiction. A bona fide purchaser for value without notice takes free of a prior unrecorded conveyance and prevails even if the prior grantee records first (or the BFP never records). Recording order does not decide the contest.', 'hard', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000020', 'Which type of deed warrants title against ALL defects arising at any time, back through the entire chain of title?', 'multiple_choice', '["General warranty deed","Special warranty deed","Quitclaim deed","Easement deed"]'::jsonb, 'General warranty deed', 'A general warranty deed warrants against all defects, before or after the grantor''s connection to the land. A special warranty deed covers only the grantor''s period of ownership; a quitclaim gives no warranty; an easement deed grants a use, not the fee.', 'easy', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000021', 'Which of the following is NOT required for a deed to be valid?', 'multiple_choice', '["Notarial acknowledgment","Competent parties capable of taking title","A description sufficient to identify the land","Delivery and acceptance"]'::jsonb, 'Notarial acknowledgment', 'Acknowledgment by a notary is generally NOT required for a deed''s validity (it may be required to record the deed). Competent parties, a sufficient description, and delivery with acceptance are required. Consideration, a date, and witnesses are also generally not required.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000022', 'A deed describes land ''lying in Nye County, Nevada,'' but the township and range cited actually fall in Clark County. The conflict is obvious from the words of the document itself. What kind of ambiguity is this, and may extrinsic evidence cure it?', 'multiple_choice', '["A patent ambiguity, which cannot be cured by extrinsic evidence and may render the conveyance void or voidable","A latent ambiguity, which extrinsic evidence may cure","A patent ambiguity, which extrinsic evidence may freely cure","No ambiguity at all; the surveyor simply picks the correct county"]'::jsonb, 'A patent ambiguity, which cannot be cured by extrinsic evidence and may render the conveyance void or voidable', 'A patent ambiguity is obvious on the face of the document (here, the county/township mismatch). It cannot be explained by extrinsic evidence and may make the conveyance void or voidable. A latent ambiguity, by contrast, appears only when the description is applied to the ground and may be explained by parol evidence.', 'hard', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000023', 'Distinguish a reservation from an exception in a deed.', 'short_answer', '[]'::jsonb, 'A reservation creates a new interest in the grantor that had no prior existence (e.g., a reserved easement or rent) - a taking back of an interest; an exception excludes from the conveyance an already-existing part of the thing described (e.g., a house or orchard on the land).', 'A reservation calls a new interest into being in the grantor (it did not exist before the deed). An exception simply withholds an already-existing portion of the described property from the conveyance.', 'medium', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000024', 'Under Texas law, the broad protection of a general warranty deed comes from the implied covenant of seisin attached to the word ''grant.''', 'true_false', '["True","False"]'::jsonb, 'False', 'In Texas the broad protection comes from EXPRESS ''warrant and forever defend'' language (Section 5.022). Section 5.023 narrows the implied covenants of ''grant''/''convey'' to just two - no prior conveyance and no encumbrances - and does NOT imply a covenant of seisin that the grantor actually owns the estate.', 'hard', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920130-0000-0000-0000-000000000025', 'In Texas, a person who takes land by quitclaim deed is generally treated how with respect to bona fide purchaser (BFP) status?', 'multiple_choice', '["Generally NOT a bona fide purchaser, because the quitclaim is treated as notice that the grantor''s title may be defective","Always a bona fide purchaser, exactly like any warranty-deed grantee","A bona fide purchaser only if the grantor was solvent","Never able to take any interest at all in the land"]'::jsonb, 'Generally NOT a bona fide purchaser, because the quitclaim is treated as notice that the grantor''s title may be defective', 'The classic Texas rule is that a quitclaim grantee is generally not a BFP - the quitclaim itself is notice that title may be defective, so the grantee takes subject to prior claims. (A 2021 statute, Section 13.006, softens this after four years of recording, but the classic rule still binds the immediate grantee and the first four years.)', 'hard', 'd2920000-0000-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('d2920110-0000-0000-0000-000000000006', 'd2920000-0000-0000-0000-000000000001', 'Homework & Practice', '', ARRAY[]::text[], 6, 45, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, 'Module homework assignment(s) and practice problems.', ARRAY[]::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0006-0000-0000-000000000000', 'd2920110-0000-0000-0000-000000000006', 'text', '{"html":"<h2>Homework &amp; Practice</h2><p>Complete the homework below. You may submit a draft up to 48 hours before the deadline for instructor feedback. Use the randomized practice problems to prepare for the quiz.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0006-0000-0000-000000000001', 'd2920110-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 1 - Reading deeds: estates, deed type, and clauses</h3><p><em>Type: written</em></p><div>Answer each part in a short paragraph; cite the specific rule or doctrine from Module 1 (and the relevant Texas statute where noted).<br/><br/>**Part A - Identify the estate (3 pts each).** For each conveyance, name the estate created in the grantee AND the future interest (if any) retained by or created in another, and identify the triggering language:<br/>1. ''Grantor conveys to the School District so long as the premises are used for school purposes.''<br/>2. ''Grantor conveys to A for life, then to B and B''s heirs.''<br/>3. ''Grantor conveys to the County, but if alcohol is ever sold on the land, Grantor may re-enter and retake the property.''<br/><br/>**Part B - Pick the deed (6 pts).** A seller is willing to convey but refuses to make any promises whatsoever about the condition of the title - she will pass only ''whatever interest, if any'' she owns. (1) Which deed type fits, and what warranty (if any) does it carry? (2) Under classic Texas law, why might the buyer NOT qualify as a bona fide purchaser, and (3) how does Tex. Prop. Code Section 13.006 (eff. 2021) change that result over time?<br/><br/>**Part C - Validity check (6 pts).** A deed is signed by a competent grantor, names a real grantee, contains a description a surveyor can locate, and is delivered and accepted - but it recites no consideration, bears no date, has no witnesses, and was never notarized or recorded. Is the deed valid to pass title between the parties? Explain which of these missing items are required and which are not.<br/><br/>**Part D - Texas covenant (5 pts).** Explain how a Texas general warranty deed obtains its broad protection (Section 5.022) and why the word ''grant'' in Texas implies only two narrow covenants (Section 5.023) rather than a common-law covenant of seisin.</div>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920120-0006-0000-0000-000000000002', 'd2920110-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 2 - Methods of boundary creation and the surveyor''s role</h3><p><em>Type: written</em></p><div>Write a 400-600 word memo to a new survey technician explaining the foundational principles from Module 1. Your memo must address all of the following, citing the relevant rule from Brown and noting Texas-specific differences where they apply:<br/><br/>1. **The three methods of creating a boundary** (by action, by words, by law) - give a concrete example of each, and explain why a boundary ''created by words'' in a deed is as binding as one run on the ground.<br/>2. **Corner vs. monument**, and the rule that for a corner/monument to be controlling in a retracement it must have been called for in the written conveyance and identified when the conveyance was made.<br/>3. **''Boundaries are fixed; property lines may move.''** Explain this distinction, list the doctrines (agreement, estoppel, acquiescence, adverse possession, judicial action) by which a property line may later change, and explain the maxim that the original surveyor CREATES boundaries while all others ASCERTAIN them.<br/>4. **Questions of fact vs. law.** Explain why ''where a boundary is'' is a question of fact for the surveyor while ''what a boundary is'' is a question of law for the court, and why the surveyor may not change the intent expressed in the deed.<br/>5. **Texas overlay.** Briefly explain why Texas has no PLSS township-range grid, what a GLO patent and abstract number are, and what the vara is (give its value in inches).<br/><br/>End with a one-paragraph reflection on why a surveyor must research the chain of title back to the original patent even though an attorney may only search a statutory number of years.</div>"}'::jsonb, 2);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000000', 'd2920210-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why a surveyor must understand sources of law</h3><p>A boundary is ultimately a <em>legal</em> line, not just a measured one. When two descriptions conflict, or a fence sits across a record line, the surveyor must know <strong>which rule of law governs</strong> and <strong>where that rule comes from</strong>. Law in the United States flows from several distinct sources, arranged in a hierarchy. Higher sources control lower ones, and a surveyor who can place a rule in that hierarchy can predict how a court will resolve a conflict. This lesson lays out those sources — constitutions, statutes, administrative rules, local ordinances, and the common/case law built by judges — and then shows how Texas organizes them.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000001', 'd2920210-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The five principal sources</h3><ul><li><strong>Constitutional law</strong> — the highest law. The U.S. Constitution is supreme over all other American law; each state also has its own constitution (Texas''s current constitution dates to <strong>1876</strong>), supreme within the state but subordinate to the federal Constitution.</li><li><strong>Statutory law</strong> — enactments of a legislative body (Congress or a state legislature). A <em>statute</em> is a written law adopted through the legislative process and organized into topical <em>codes</em>.</li><li><strong>Administrative law</strong> — regulations issued by a state or federal agency acting under authority delegated by statute. In Texas these are collected in the Texas Administrative Code (TAC).</li><li><strong>Common law</strong> — law developed by judges through the decisions of courts and similar tribunals, where no constitution or statute supplies the rule. It governs core property powers: to dispose of property, to have exclusive use, to control resources within it (water, minerals), and to segregate and sell rights.</li><li><strong>Case law</strong> — the collected history of cases decided by judges. Appellate opinions interpret the other sources and, through precedent, themselves become binding law.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', 'table', '{"headers":["Rank","Source","Made by","Example relevant to surveying"],"rows":[["1","Constitution (federal, then state)","Constitutional convention / amendment","Tex. Const. art. V (court structure); navigability principles"],["2","Statutes / codes","Legislature (Congress, Tex. Legislature)","Tex. Property Code §§13.001–13.002 (recording)"],["3","Administrative rules","Agencies (TBPELS, GLO, federal agencies)","22 TAC Ch. 138 (surveyor standards of practice)"],["4","Local ordinances","City / county governing body","Municipal subdivision & platting ordinances"],["5","Common / case law","Courts (appellate precedent)","Stafford v. King (dignity of calls; footsteps)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000003', 'd2920210-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Ordinances are local statutory law — rules adopted by a city council or county commissioners court (e.g., subdivision platting and zoning). They are valid only within that jurisdiction and only to the extent state law authorizes them."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000004', 'd2920210-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Supremacy, jurisdiction, and sovereign immunity</h3><p><strong>Supremacy</strong> means a conflict is resolved in favor of the higher source: federal over state, constitution over statute, statute over administrative rule. <strong>Jurisdiction</strong> is “the right and power of a court to adjudicate concerning the subject matter in a given case.” For boundaries, jurisdiction tracks title history: a dispute over land that has <em>always</em> been in federal ownership (unpatented public domain) is tried under <strong>federal law</strong>; once land has passed to private parties by patent, jurisdiction over its boundaries passes to the <strong>state courts</strong> under state law. <strong>Sovereign immunity</strong> holds that the government can be sued only when it consents (by statute); common-law remedies such as adverse possession and acquiescence generally <strong>cannot be applied against the government</strong>. Courts may also take <strong>judicial notice</strong> of matters of common knowledge (for example, that water flows downhill) without requiring proof.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000005', 'd2920210-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Texas land was never federal public domain. Title traces to one of four sovereigns — Spain, Mexico, the Republic of Texas, or the State of Texas — so the original grant is a State (or pre-statehood) patent, never a federal patent. There is no PLSS township-range grid; Texas land is described by metes-and-bounds keyed to an original GLO survey and abstract number."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000006', 'd2920210-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Texas codes a surveyor lives in</h3><p>Texas statutes are organized into topical codes. The ones most relevant to boundary practice are:</p><ul><li><strong>Texas Property Code</strong> — estates, conveyances, deeds, easements, restrictive covenants, and the <strong>recording acts</strong> (Lesson 4).</li><li><strong>Texas Natural Resources Code</strong> — public lands, the General Land Office (GLO), Permanent School Fund lands, and surveys of state land. Once a survey and its field notes are accepted by the GLO, they are legally <strong>presumed correct</strong>.</li><li><strong>Texas Civil Practice &amp; Remedies Code, Ch. 16</strong> — adverse possession (§§16.021–16.028) and the limitations period for <em>suits against surveyors</em> (§16.011). <em>A common trap: adverse possession is NOT in the Property Code.</em></li><li><strong>Texas Occupations Code, Ch. 1071</strong> (Professional Land Surveying Practices Act) — the licensing enabling act for surveyors.</li></ul><p>Administrative rules for surveyors come from <strong>TBPELS</strong> (the Texas Board of Professional Engineers and Land Surveyors), in <strong>22 TAC, Part 6</strong> — notably <strong>Ch. 138</strong> (“Compliance and Professionalism for Surveyors”).</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000007', 'd2920210-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Texas wrinkle: In 2019 (HB 1523, 86th Leg.) Texas merged its separate engineering and surveying boards into one agency — TBPELS. Many states still keep a stand-alone surveying board. Older TAC chapters (661/663) were repealed and merged into the current Chs. 134/136/138."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0001-0000-0000-000000000008', 'd2920210-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Law has a hierarchy: constitution > statute > administrative rule > ordinance, with common/case law filling the gaps and interpreting the rest.","Supremacy resolves conflicts in favor of the higher source; federal over state.","Boundary jurisdiction follows title: federal law for never-patented land, state law once patented.","Sovereign immunity bars common-law boundary remedies (adverse possession, acquiescence) against the government.","Texas surveyors mainly work in the Property Code, Natural Resources Code, Civ. Prac. & Rem. Code Ch. 16, and Occupations Code Ch. 1071, with TBPELS rules in 22 TAC Ch. 138."]}'::jsonb, 8);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000000', 'd2920210-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Three tiers: trial, appellate, supreme</h3><p>American court systems — federal and state — share a three-tier shape. A case is born in a <strong>trial court</strong>, may be reviewed by an <strong>appellate (intermediate) court</strong>, and may finally reach a <strong>court of last resort</strong> (a supreme court). Understanding this ladder matters to surveyors because only the upper rungs make <em>binding precedent</em>, and a boundary dispute can be appealed only on certain grounds.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000001', 'd2920210-0000-0000-0000-000000000002', 'table', '{"headers":["Court level","What it does","Key parties / terms"],"rows":[["Trial court","Hears a case for the first time; finds the facts and applies the law. Federal trial courts are called district courts.","Plaintiff (initiates the suit); Defendant (party sued)"],["Appellate court","Reviews a lower court''s decision; cannot re-try the facts — only questions of law and procedure. Its opinion binds all courts in its jurisdiction.","Appellant (aggrieved party); Appellee (party appealed against); Respondent"],["Supreme court","May accept or deny a petition for review; if it accepts and issues an opinion, that opinion binds all courts under its jurisdiction.","Petitioner; Respondent"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"A critical limit on appeals: an appellate court reviews questions of LAW and PROCEDURE, not questions of FACT. In a boundary suit, where a survey line actually lies on the ground is a question of fact decided by the trial court''s factfinder — so it is hard to overturn on appeal."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000003', 'd2920210-0000-0000-0000-000000000002', 'text', '{"html":"<h3>The federal court system</h3><p>The federal judiciary has three levels: the <strong>U.S. District Courts</strong> (94 districts — the trial courts, each with a bankruptcy court), the <strong>U.S. Courts of Appeals</strong> (organized into <strong>13 circuits</strong> — 12 regional plus the Federal Circuit), and the <strong>U.S. Supreme Court</strong> at the apex (one court). Specialized federal courts (the Court of International Trade, the Court of Federal Claims) feed into this structure. Federal courts hear boundary disputes over land that has always been federally owned, plus federal questions and diversity cases.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000004', 'd2920210-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: The federal court system — district courts (trial), courts of appeals (13 circuits), and the U.S. Supreme Court."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000005', 'd2920210-0000-0000-0000-000000000002', 'text', '{"html":"<h3>The Texas court system</h3><p>Texas mirrors the three-tier shape but with a famous twist. Its trial courts include <strong>District Courts</strong> (general jurisdiction — boundary and title disputes, trespass-to-try-title, and quiet-title suits start here; Tex. Const. art. V §8), plus <strong>County Courts</strong> (constitutional and statutory “county courts at law”), <strong>Justice (JP) Courts</strong>, and <strong>Municipal Courts</strong>. Intermediate appeals go to the <strong>Texas Courts of Appeals</strong>. At the top, Texas splits its court of last resort into <strong>two co-equal high courts</strong>: the <strong>Supreme Court of Texas</strong> (final authority for <em>civil</em> and juvenile cases — so boundary and title cases end here; 9 members) and the <strong>Texas Court of Criminal Appeals</strong> (final authority for <em>criminal</em> cases; 9 members).</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000006', 'd2920210-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Texas differs (and it matters for surveyors): Most states and the federal system have ONE court of last resort for both civil and criminal appeals. Texas splits this into two — a design shared only with Oklahoma. Because boundary and title disputes are CIVIL, the apex authority for boundary precedent is the Supreme Court of Texas; the Court of Criminal Appeals never touches boundary law."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000007', 'd2920210-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"2026 update on the appellate count: Texas historically had 14 Courts of Appeals. As of 2024 there are effectively 15 — the 14 regional districts plus a statewide Fifteenth Court of Appeals (S.B. 1045, 88th Leg. 2023) that hears appeals from the new Texas Business Court and most civil appeals where the State or a state agency/official is a party. Ordinary private boundary appeals still go to the regional court of appeals; older texts say ''14.''"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000008', 'd2920210-0000-0000-0000-000000000002', 'link_reference', '{"links":[{"url":"https://statutes.capitol.texas.gov/Docs/CN/htm/CN.5.htm","title":"Tex. Const. art. V (Judicial Department)","type":"website","description":"Establishes Texas''s court structure, including the two highest courts and the district courts'' jurisdiction over title/boundary suits."}]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0002-0000-0000-000000000009', 'd2920210-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Courts run in three tiers: trial (finds facts), appellate (reviews law/procedure only), and supreme (discretionary final review).","Federal: U.S. District Courts -> 13 Courts of Appeals circuits -> U.S. Supreme Court.","Texas boundary/title suits begin in District Court (general jurisdiction).","Texas uniquely has TWO highest courts: the Supreme Court of Texas (civil — controls boundary law) and the Court of Criminal Appeals (criminal).","Texas now has effectively 15 courts of appeals (14 regional + the statewide Fifteenth), but private boundary appeals still go to the regional court."]}'::jsonb, 9);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0003-0000-0000-000000000000', 'd2920210-0000-0000-0000-000000000003', 'text', '{"html":"<h3>From a single suit to binding precedent</h3><p>Case law is built one decision at a time. The process is the same whether the dispute is a fence line or a contract: a <strong>suit is filed in the proper trial court</strong>; the judge rules on the legal issues; that <strong>trial ruling binds only the parties to that case</strong> and is merely <em>advisory</em> in other cases. If a party believes the trial court erred on a question of <strong>law or procedure</strong> (but not on the facts), it may appeal. When an <strong>appellate court issues an opinion, that opinion binds all courts in its jurisdiction</strong> — it becomes <em>precedent</em>. A further appeal may reach the supreme court, whose opinion binds every court beneath it.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0003-0000-0000-000000000001', 'd2920210-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Stare decisis and the dignity of precedent</h3><p>The engine that turns opinions into law is <strong>stare decisis</strong> — “to stand by things decided.” Courts follow their own prior decisions and those of higher courts in the same jurisdiction so the law stays predictable. Two distinctions matter:</p><ul><li><strong>Binding (mandatory) authority</strong> — a decision a court <em>must</em> follow (a higher court in the same jurisdiction).</li><li><strong>Persuasive authority</strong> — a decision a court <em>may</em> consider but need not follow (a trial-court ruling, an opinion from another jurisdiction, or a treatise).</li></ul><p>This is why a single Texas Supreme Court boundary opinion — such as <em>Stafford v. King</em> on the dignity of calls — governs every Texas surveyor''s retracement, while a district court''s ruling in a neighbor''s fence dispute does not.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0003-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', 'accordion', '{"sections":[{"title":"The parts of a legal brief (anatomy of a case)","content":"<p>When a surveyor or attorney ''briefs'' a case to understand its rule, the standard parts are: <strong>(1) case name and citation; (2) facts; (3) procedural posture</strong> (what happened at trial and on appeal); <strong>(4) issue</strong> (the question the appellate court must answer); <strong>(5) rule applied; (6) holding</strong> (the court''s decision specific to this case); <strong>(7) reasoning; (8) result;</strong> and <strong>(9) concurrences and dissents.</strong> The <em>holding</em> is the part that becomes precedent.</p>","open":false}]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0003-0000-0000-000000000003', 'd2920210-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Finding the law: primary vs. secondary sources</h3><p>Effective research first asks whether the issue is <strong>federal or state</strong> and what type of primary law applies. A <strong>primary source</strong> is a statement of the law itself from a governmental entity — a court, legislature, or agency. A <strong>secondary source</strong> discusses, explains, or interprets the law: treatises, law reviews, legal encyclopedias (Corpus Juris Secundum, American Jurisprudence 2d), and annotations. Because secondary sources are rich with citations to primary law, many researchers begin there. The major online services are <strong>Westlaw</strong> and <strong>LexisNexis</strong>. For surveyors, <em>Brown''s Boundary Control and Legal Principles</em> is itself a secondary (treatise) source that points to the controlling cases and statutes.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0003-0000-0000-000000000004', 'd2920210-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Where opinions live: reporters and citations</h3><p>Published opinions are collected in <strong>reporters</strong>. Only <strong>appellate-level</strong> opinions designated for publication are reported — <em>trial-level decisions are not reported</em>. Federal reporters carry federal opinions; the <strong>United States Reports</strong> is the official record of the U.S. Supreme Court; the <strong>Federal Reporter</strong> carries the U.S. Courts of Appeals; the <strong>Federal Supplement</strong> carries select U.S. District Court opinions. West''s <strong>regional reporters</strong> collect state appellate opinions by region — <strong>Texas opinions appear in the South Western Reporter (S.W.)</strong>. A <strong>citation</strong> identifies the parties (the style), the volume and reporter, the page, and the year — e.g., <em>Madison v. Gordon</em>, 39 S.W.3d 604 (Tex. 2001) means volume 39 of the South Western Reporter, 3d series, page 604, decided by the Supreme Court of Texas in 2001.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0003-0000-0000-000000000005', 'd2920210-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"Reporter geography matters for retracement research. Texas is in the South Western Reporter (S.W./S.W.2d/S.W.3d). New Mexico — and most western states — fall in the Pacific Reporter (P./P.2d/P.3d). Knowing the right regional reporter speeds finding the controlling boundary precedent for the state where the land lies."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0003-0000-0000-000000000006', 'd2920210-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["A trial ruling binds only its own case; an appellate opinion binds all courts in its jurisdiction and becomes precedent.","Stare decisis makes higher-court decisions binding (mandatory) and other decisions merely persuasive.","Only appellate opinions are reported; trial-court decisions are not published as precedent.","Primary sources state the law (cases, statutes, agency rules); secondary sources (treatises like Brown, encyclopedias, law reviews) explain it and cite to it.","Texas appellate opinions are published in the South Western Reporter; a citation gives parties, volume, reporter, page, court, and year."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000000', 'd2920210-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Why recording acts exist</h3><p>When the same grantor conveys the same land twice, who wins? At early common law the rule was simply <strong>“first in time, first in right”</strong> — the earlier deed prevailed. That punished an innocent later buyer who had no way of knowing about a hidden prior deed. <strong>Recording acts</strong> fix this by giving buyers a public record to search and a set of priority rules that reward those who record (and those who buy without notice). For a surveyor, recording rules explain why the <em>recorded</em> chain of title — not just the deed in the client''s hand — controls what was actually conveyed.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000001', 'd2920210-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Notice: actual and constructive</h3><p>Recording statutes turn on <strong>notice</strong>. A purchaser has:</p><ul><li><strong>Actual notice</strong> — real, personal knowledge of a prior claim.</li><li><strong>Constructive notice</strong> — knowledge the law charges a buyer with whether or not they actually have it. A properly recorded instrument is constructive notice <em>to all persons</em>. Open and visible <strong>possession</strong> of the land can also be constructive notice, putting a buyer on a duty to inquire.</li></ul><p>The three statutory regimes that resolve double conveyances are: <strong>race</strong> (whoever records first wins, even if they knew of the prior deed), <strong>notice</strong> (a later buyer without notice wins, regardless of recording order), and <strong>race-notice</strong> (a later buyer wins only if both without notice <em>and</em> first to record).</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', 'table', '{"headers":["Regime","Who wins the double conveyance","Recording race required?"],"rows":[["Race","First to record (even with notice)","Yes"],["Notice (Texas)","Later bona fide purchaser without notice","No"],["Race-notice","Later BFP without notice AND who records first","Yes"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000003', 'd2920210-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas is a PURE NOTICE state. A subsequent purchaser for valuable consideration without notice of a prior unrecorded conveyance takes free of it — and prevails even if the prior grantee records first, or even if the bona fide purchaser never records at all. There is NO recording-priority (race) requirement for the BFP. (In a race-notice state like California, that same buyer would lose without winning the race to the courthouse.)"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000004', 'd2920210-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The Texas recording statutes</h3><p>Two Property Code sections carry the rule:</p><ul><li><strong>§13.001 (Validity of Unrecorded Instrument)</strong> — a conveyance, mortgage, or deed of trust is <strong>“void as to a creditor or to a subsequent purchaser for a valuable consideration without notice”</strong> unless it is acknowledged and filed for record — but it is still <strong>binding on the parties</strong>, their heirs, and on a purchaser who does not pay value or who has notice.</li><li><strong>§13.002 (Effect of Recording)</strong> — a properly recorded instrument is <strong>“notice to all persons”</strong> (constructive notice).</li><li><strong>§11.001 (Place of Recording)</strong> — instruments are recorded in the <strong>county where the land lies</strong>.</li></ul>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000005', 'd2920210-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The bona fide purchaser (BFP) doctrine</h3><p>The buyer protected by the notice statute is the <strong>bona fide purchaser</strong>. Texas requires three elements: <strong>(1) valuable consideration</strong> (not nominal — a gift, or a quitclaim-only taker, generally fails); <strong>(2) good faith</strong>; and <strong>(3) without notice</strong>, neither actual nor constructive. Constructive notice arises from the <em>records</em> (§13.002) and from <em>possession</em> of the land. The leading Texas case on possession is <em>Madison v. Gordon</em>, 39 S.W.3d 604 (Tex. 2001): possession charges a purchaser with constructive notice <strong>only if</strong> it is <strong>“visible, open, exclusive, and unequivocal.”</strong> There, a tenant occupying one unit of a fourplex was not exclusive or unequivocal, so it gave no constructive notice and the purchaser prevailed.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000006', 'd2920210-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas differs on possession and on quitclaims. Texas''s four-adjective possession test — ''visible, open, exclusive, and unequivocal'' — is stricter than the looser ''open and notorious'' standard used elsewhere, so ambiguous or shared possession often fails to defeat BFP status. Separately, a grantee under a quitclaim deed is generally NOT a bona fide purchaser, because the quitclaim itself puts them on notice that the grantor''s title may be defective."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000007', 'd2920210-0000-0000-0000-000000000004', 'link_reference', '{"links":[{"url":"https://statutes.capitol.texas.gov/Docs/PR/htm/PR.13.htm","title":"Tex. Property Code Ch. 13 (Effects of Recording)","type":"website","description":"§13.001 (validity of unrecorded instrument) and §13.002 (effect of recording = notice to all persons) — the heart of Texas''s pure notice recording act."}]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0004-0000-0000-000000000008', 'd2920210-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Recording acts replace common-law ''first in time'' with a public-record system keyed to notice.","Notice can be actual (real knowledge) or constructive (the record, or open possession).","Texas is a PURE NOTICE state: a BFP without notice wins even if the prior grantee records first or the BFP never records (Prop. Code §§13.001–13.002).","A bona fide purchaser needs valuable consideration, good faith, and no notice; record in the county where the land lies.","Madison v. Gordon: possession is constructive notice only if ''visible, open, exclusive, and unequivocal'' — a stricter Texas test; quitclaim grantees are generally not BFPs."]}'::jsonb, 8);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000000', 'd2920210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>What a presumption is — and is not</h3><p>A <strong>presumption</strong> is a conclusion the law <em>directs</em> be drawn from certain established facts. Presumptions are <strong>not evidence</strong>, but they may <strong>substitute for evidence where evidence is lacking</strong> — which is exactly the surveyor''s situation when original monuments are gone and the record is thin. A presumption is conditional on the existence of certain facts; a party who relies on one carries the job of <strong>eliminating contrary possibilities</strong>. Presumptions may be established by either common law or statute.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000001', 'd2920210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Conclusive vs. rebuttable; and inferences</h3><ul><li><strong>Conclusive (irrebuttable) presumptions</strong> are absolute — no contrary evidence is allowed to defeat them.</li><li><strong>Rebuttable presumptions</strong> hold <em>until</em> contrary evidence overcomes them. These constitute <strong>most of the rules of law that control boundaries</strong> — they set the default, but better evidence (a found original monument, the surveyor''s footsteps) can override them.</li></ul><p>An <strong>inference</strong> is different. An inference is <strong>NOT a presumption</strong>; it is a <em>deduction of fact</em> that may be logically and reasonably drawn from another fact or group of facts. A presumption is <em>imposed by law</em>; an inference is <em>reasoned by the factfinder</em> from the evidence.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"Practical mnemonic: a PRESUMPTION is a rule the law hands you (''treat X as true unless disproven''); an INFERENCE is a conclusion you reason out yourself (''these blazed trees and this old fence suggest the original line ran here''). Most boundary presumptions are rebuttable — they yield to superior evidence."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000003', 'd2920210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Common surveying presumptions</h3><p>Courts extend a strong set of presumptions to original government surveys and old descriptions. Among the most important for retracement:</p><ul><li>The original (government) surveyor performed the work <strong>competently and according to the laws in effect</strong> at the time, and the work was <strong>accurate</strong>.</li><li>The survey was <strong>made as stated in the field notes</strong>, the lines were <strong>actually run on the ground</strong>, and the corners were <strong>established and marked</strong> as returned.</li><li>The <strong>field notes and plats are correct</strong>, and corners exist at the places the field notes indicate.</li><li>An <strong>ancient survey is presumed correct</strong> when so accepted and treated by the interested parties.</li><li><strong>Land abutting a highway, street, or non-navigable watercourse extends to the center</strong> of that feature (the centerline presumption).</li><li>When a description contains <strong>courses and monuments, a survey was actually conducted.</strong></li></ul>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000004', 'd2920210-0000-0000-0000-000000000005', 'accordion', '{"sections":[{"title":"A caution on the ''unassailable GLO survey'' presumption","content":"<p>Lists of surveying presumptions sometimes include that ''an approved U.S. GLO survey is unassailable by any court'' and that government corners are presumed correct. These are powerful but they describe the <strong>federal PLSS</strong> world. <strong>In Texas they apply only to the limited federal land in the state.</strong> Texas''s own original surveys are GLO (General Land Office of <em>Texas</em>) surveys, and the Natural Resources Code gives accepted state surveys and field notes a legal presumption of correctness. The deeper Texas principle, developed in Modules 4-5, is that these presumptions are all subordinate to the <strong>intent of the grant</strong> and the <strong>footsteps of the original surveyor</strong> on the ground.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000005', 'd2920210-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Texas boundary presumptions (dignity of calls and more)</h3><p>Texas boundary law runs on rebuttable presumptions of <em>reliability</em>. The best known is the <strong>dignity (priority) of calls</strong>: when calls conflict, higher-dignity calls control — <strong>(1) natural monuments &gt; (2) artificial monuments &gt; (3) course (bearing) &gt; (4) distance &gt; (5) quantity/area.</strong> The foundational Texas case is <em>Stafford v. King</em>, 30 Tex. 257 (1867) (full treatment in Modules 4-5). Other Texas presumptions a surveyor uses: the <strong>centerline / center-of-road presumption</strong> (land bounded “by” or “along” a road or non-navigable stream carries title to the center, subject to the public easement, unless clearly excluded) and the <strong>strip-and-gore doctrine</strong> (a grantor conveying land abutting a narrow strip is presumed <em>not</em> to retain that strip if it has no practical use apart from the conveyed tract).</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000006', 'd2920210-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"Texas key point: The dignity-of-calls hierarchy is only a RULE OF CONSTRUCTION — a set of rebuttable reliability presumptions. It always yields to (i) the intent of the parties (paramount) and (ii) the footsteps of the original surveyor where they can be found on the ground. A found, identified original monument controls over a conflicting field-note call."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0005-0000-0000-000000000007', 'd2920210-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["A presumption is a conclusion the law directs from established facts; it is not evidence but can substitute for it when evidence is missing.","Conclusive presumptions are absolute; rebuttable presumptions (most boundary rules) yield to superior evidence.","An inference is a fact-deduction reasoned by the factfinder — not a presumption imposed by law.","Surveys, field notes, corners, and ancient surveys carry strong presumptions of correctness; land abutting a road/non-navigable stream is presumed to run to the center.","The Texas dignity of calls (natural > artificial > course > distance > quantity) is a rebuttable rule of construction subordinate to grant intent and the original surveyor''s footsteps."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000001', 'Jurisdiction', 'The right and power of a court to adjudicate concerning the subject matter in a given case.', 'Right and POWER of a court.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000002', 'Sovereign immunity', 'The doctrine that the government may be sued only when it consents; common-law remedies like adverse possession cannot be used against it.', 'You can''t sue the king without permission.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000003', 'Trial court', 'The court where a case is heard for the first time; it finds the facts and applies the law. Federal trial courts are called district courts.', 'Where the case starts.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000004', 'Appellate court', 'A court with jurisdiction to review a lower court''s decision; it cannot re-try the facts and reviews only questions of law and procedure. Its opinion binds all courts in its jurisdiction.', 'Reviews, does not re-try.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000005', 'Supreme Court of Texas', 'The final authority for civil and juvenile cases in Texas (9 members); the apex court for boundary and title precedent.', 'Civil court of last resort — not criminal.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000006', 'Texas Court of Criminal Appeals', 'Texas''s separate, co-equal highest court for criminal cases (9 members); never decides boundary law.', 'The other Texas high court.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000007', 'Stare decisis', 'Latin for ''to stand by things decided''; the doctrine that courts follow prior decisions of higher courts in the same jurisdiction to keep the law consistent.', 'To stand by things decided.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000008', 'Binding vs. persuasive authority', 'Binding (mandatory) authority must be followed (a higher court in the same jurisdiction); persuasive authority may be considered but need not be followed (trial rulings, other jurisdictions, treatises).', 'Must follow vs. may follow.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000009', 'Primary vs. secondary source', 'A primary source is the law itself from a governmental entity (court, legislature, agency); a secondary source discusses or interprets it (treatises, encyclopedias, law reviews).', 'The law itself vs. commentary on it.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000010', 'Reporter', 'A published set of volumes collecting appellate court opinions; Texas opinions appear in the South Western Reporter (S.W.).', 'Where published opinions are collected.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000011', 'Recording act', 'A statute that establishes priority among competing claims to the same land based on recording and notice, replacing the common-law ''first in time, first in right'' rule.', 'Public-record priority rules.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000012', 'Constructive notice', 'Knowledge the law charges a buyer with regardless of actual awareness; arises from a properly recorded instrument (notice to all persons) and from open possession of the land.', 'Notice the law imputes to you.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000013', 'Bona fide purchaser (BFP)', 'A buyer who acquires land for valuable consideration, in good faith, and without notice (actual or constructive) of a prior claim; protected by the recording act.', 'Value + good faith + no notice.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000014', 'Madison v. Gordon (Tex. 2001)', 'Leading Texas case holding that possession is constructive notice only if it is ''visible, open, exclusive, and unequivocal.''', 'Four adjectives for possession-as-notice.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000015', 'Presumption (at law)', 'A conclusion the law expressly directs to be drawn from certain established facts; not evidence, but it may substitute for evidence where evidence is lacking.', 'A rule of law, not proof.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000016', 'Conclusive vs. rebuttable presumption', 'A conclusive presumption is irrebuttable and absolute; a rebuttable presumption holds until overcome by contrary evidence and accounts for most boundary rules.', 'Absolute vs. defeasible.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000017', 'Inference', 'A deduction of fact that may be logically and reasonably drawn from another fact or group of facts; it is NOT a presumption.', 'You reason it; the law doesn''t impose it.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920240-0000-0000-0000-000000000018', 'Dignity of calls', 'The Texas priority of conflicting calls: natural monuments > artificial monuments > course (bearing) > distance > quantity/area; a rebuttable rule of construction.', 'Natural over artificial over course over distance.', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000001', 'Which source of law sits at the top of the American legal hierarchy and is supreme over all others?', 'multiple_choice', '["A state statute","The U.S. Constitution","An administrative regulation","A county ordinance"]'::jsonb, 'The U.S. Constitution', 'The U.S. Constitution is the highest law of the land; all statutes, rules, and ordinances are subordinate to it. State statutes, agency regulations, and local ordinances each rank below it.', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000002', 'Law developed by judges through the decisions of courts, where no constitution or statute supplies the rule, is called:', 'multiple_choice', '["Statutory law","Administrative law","Common law","Constitutional law"]'::jsonb, 'Common law', 'Common law is judge-made law from court decisions. Statutory law comes from legislatures, administrative law from agency regulations, and constitutional law from constitutions.', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000003', 'A boundary dispute concerns land that has always been in federal ownership and was never patented. Whose law governs the dispute?', 'multiple_choice', '["State law, because boundaries are always a state matter","Federal law, because the land was never severed from federal ownership","Local ordinance, because the county records the survey","International law"]'::jsonb, 'Federal law, because the land was never severed from federal ownership', 'Jurisdiction tracks title history. Unpatented (never-private) land is tried under federal law; once land passes to private parties by patent, boundary jurisdiction passes to the state courts under state law.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000004', 'True or False: Under sovereign immunity, common-law remedies such as adverse possession and acquiescence can generally be applied against the government to gain title to its land.', 'true_false', '["True","False"]'::jsonb, 'False', 'Sovereign immunity means the government can be sued only when it consents. Common-law remedies like adverse possession and acquiescence generally cannot be used to take title from the government.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000005', 'In Texas, which code contains the adverse-possession statutes — a frequent point of confusion?', 'multiple_choice', '["The Texas Property Code","The Texas Natural Resources Code","The Texas Civil Practice & Remedies Code, Chapter 16","The Texas Occupations Code, Chapter 1071"]'::jsonb, 'The Texas Civil Practice & Remedies Code, Chapter 16', 'Adverse possession is in Civ. Prac. & Rem. Code Ch. 16 (§§16.021–16.028) — NOT the Property Code, a common trap. The Property Code covers conveyances and recording; the Natural Resources Code covers public lands; Occupations Code Ch. 1071 covers surveyor licensing.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000006', 'Texas''s surveyor standards of practice are administrative rules adopted by TBPELS. Where are they found?', 'multiple_choice', '["The Texas Constitution, art. V","The South Western Reporter","22 Texas Administrative Code, Chapter 138","The U.S. Code"]'::jsonb, '22 Texas Administrative Code, Chapter 138', 'TBPELS rules, including ''Compliance and Professionalism for Surveyors,'' are in 22 TAC Ch. 138. The Constitution is higher-tier law; the South Western Reporter holds case opinions; the U.S. Code is federal statutes.', 'hard', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000007', 'A surveyor''s client lost at trial and wants to appeal because the judge believed the opposing surveyor''s testimony about where the line lies on the ground. What is the main obstacle to that appeal?', 'multiple_choice', '["Appellate courts can only review questions of law and procedure, not re-decide questions of fact","Boundary cases cannot be appealed at all","Only the losing surveyor, not the client, may appeal","The appeal must go first to the Court of Criminal Appeals"]'::jsonb, 'Appellate courts can only review questions of law and procedure, not re-decide questions of fact', 'Where a line lies on the ground is a question of FACT for the trial factfinder. Appellate courts review only questions of law and procedure, so factual findings are hard to overturn. Boundary cases can be appealed (on law/procedure); the aggrieved party (the client) appeals; and civil appeals never go to the Court of Criminal Appeals.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000008', 'Why is the Supreme Court of Texas — not the Texas Court of Criminal Appeals — the apex authority for boundary precedent?', 'multiple_choice', '["Because boundary disputes are civil cases, and the Supreme Court of Texas is the final authority for civil cases","Because the Court of Criminal Appeals has fewer judges","Because boundary cases skip the intermediate courts","Because the Court of Criminal Appeals only hears federal questions"]'::jsonb, 'Because boundary disputes are civil cases, and the Supreme Court of Texas is the final authority for civil cases', 'Texas splits its court of last resort: the Supreme Court of Texas decides civil (including boundary/title) cases, and the Court of Criminal Appeals decides criminal cases. Since boundary disputes are civil, they end at the Supreme Court of Texas. Both high courts have 9 members.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000009', 'True or False: Texas and Oklahoma are unusual because each has two separate highest courts — one for civil cases and one for criminal cases.', 'true_false', '["True","False"]'::jsonb, 'True', 'Most states and the federal system have a single court of last resort. Only Texas and Oklahoma split it into two co-equal high courts: a civil supreme court and a criminal court of appeals.', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000010', 'In the federal court system, which courts are the trial courts where a boundary case over federal land would first be heard?', 'multiple_choice', '["U.S. Courts of Appeals","U.S. District Courts","The U.S. Supreme Court","U.S. Courts of Criminal Appeals"]'::jsonb, 'U.S. District Courts', 'U.S. District Courts (94 districts) are the federal trial courts. The U.S. Courts of Appeals (13 circuits) are intermediate appellate courts, and the U.S. Supreme Court is the apex. There is no federal ''Court of Criminal Appeals.''', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000011', 'In which Texas trial court do title and boundary disputes (trespass-to-try-title, quiet title) generally begin?', 'multiple_choice', '["Justice (JP) Court","Municipal Court","District Court (general jurisdiction)","The Fifteenth Court of Appeals"]'::jsonb, 'District Court (general jurisdiction)', 'Texas District Courts have general jurisdiction, including title and boundary suits (Tex. Const. art. V §8). JP and municipal courts are limited-jurisdiction courts; the Fifteenth Court of Appeals is an appellate court, not a trial court.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000012', 'A trial court in a neighboring county ruled on a fence-line dispute much like your client''s. How does that trial ruling affect your client''s separate case?', 'multiple_choice', '["It is binding precedent that the court must follow","It binds only the parties to that case and is merely advisory (persuasive) in other cases","It automatically reverses any conflicting appellate opinion","It must be ignored entirely"]'::jsonb, 'It binds only the parties to that case and is merely advisory (persuasive) in other cases', 'A trial ruling binds only its own parties and is only advisory elsewhere. Binding precedent comes from appellate opinions within the jurisdiction. Trial rulings cannot reverse appellate opinions, but they may still be considered as persuasive authority.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000013', 'The doctrine that courts stand by prior decisions of higher courts in the same jurisdiction, keeping the law predictable, is called:', 'multiple_choice', '["Res judicata","Stare decisis","Sovereign immunity","Judicial notice"]'::jsonb, 'Stare decisis', 'Stare decisis (''to stand by things decided'') is the precedent-following doctrine. Res judicata bars relitigating a decided claim between the same parties; sovereign immunity protects the government from suit; judicial notice accepts common-knowledge facts without proof.', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000014', 'Which of the following is a SECONDARY legal source rather than a primary one?', 'multiple_choice', '["A Texas Supreme Court opinion","The Texas Property Code","Brown''s Boundary Control and Legal Principles (a treatise)","A TBPELS administrative rule"]'::jsonb, 'Brown''s Boundary Control and Legal Principles (a treatise)', 'A treatise discusses and interprets the law, so it is a secondary source. Court opinions, statutes (the Property Code), and agency rules are primary sources — statements of the law itself from governmental entities.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000015', 'True or False: Trial-level court decisions are routinely published in the regional reporters as binding precedent.', 'true_false', '["True","False"]'::jsonb, 'False', 'Only appellate-level opinions designated for publication appear in reporters. Trial-level decisions are generally not reported and do not serve as binding precedent.', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000016', 'In the citation Madison v. Gordon, 39 S.W.3d 604 (Tex. 2001), what does ''604'' indicate?', 'multiple_choice', '["The year the case was decided","The volume of the reporter","The page on which the opinion begins","The number of the court district"]'::jsonb, 'The page on which the opinion begins', 'In a citation, the number after the reporter abbreviation is the starting page. ''39'' is the volume, ''S.W.3d'' is the reporter (South Western Reporter, 3d series), ''604'' is the page, and ''(Tex. 2001)'' is the court and year.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000017', 'Texas appellate opinions are collected primarily in which West regional reporter?', 'multiple_choice', '["The Pacific Reporter","The South Western Reporter","The Atlantic Reporter","The North Eastern Reporter"]'::jsonb, 'The South Western Reporter', 'Texas (along with Arkansas, Kentucky, Missouri, and Tennessee) appears in the South Western Reporter (S.W.). New Mexico and most western states are in the Pacific Reporter; the Atlantic and North Eastern reporters cover other regions.', 'hard', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000018', 'What is the defining feature of a PURE NOTICE recording jurisdiction like Texas?', 'multiple_choice', '["The first party to record always wins, even with notice","A later purchaser for value without notice wins, even if the prior grantee records first or the buyer never records","A later purchaser wins only if they record before everyone else","Recording has no legal effect at all"]'::jsonb, 'A later purchaser for value without notice wins, even if the prior grantee records first or the buyer never records', 'In a pure notice state, the bona fide purchaser without notice prevails regardless of recording order — there is no race requirement. ''First to record wins'' describes a race state; ''must record first'' describes race-notice; and recording certainly has legal effect (it gives constructive notice).', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000019', 'A grantor deeds Blackacre to A, who does not record. The grantor then deeds the same land to B, who pays full value, has no knowledge of A''s deed, and finds nothing in the records. A records the next week, before B records. Under Texas law, who owns Blackacre?', 'multiple_choice', '["A, because A recorded first","B, because B is a bona fide purchaser without notice and Texas is a pure notice state","A, because A''s deed was first in time","Neither — the land reverts to the grantor"]'::jsonb, 'B, because B is a bona fide purchaser without notice and Texas is a pure notice state', 'Texas is a pure notice state. B paid value without notice of A''s unrecorded deed, so B prevails — and the fact that A records first is irrelevant because there is no race requirement. Under §13.001, A''s unrecorded deed is void as to a subsequent purchaser for value without notice.', 'hard', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000020', 'Under Tex. Property Code §13.002, what is the effect of properly recording an instrument?', 'multiple_choice', '["It makes the instrument valid even if forged","It is notice to all persons (constructive notice)","It transfers title automatically","It exempts the buyer from paying value"]'::jsonb, 'It is notice to all persons (constructive notice)', '§13.002 provides that a properly recorded instrument is notice to all persons — i.e., constructive notice. Recording does not cure forgery, does not by itself transfer title, and does not change the value requirement.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000021', 'Which set of elements must a buyer satisfy to be a bona fide purchaser in Texas?', 'multiple_choice', '["Valuable consideration, good faith, and without notice (actual or constructive)","Any consideration, first to record, and a quitclaim deed","Knowledge of the prior claim, value, and good faith","Possession of the land for ten years"]'::jsonb, 'Valuable consideration, good faith, and without notice (actual or constructive)', 'A BFP needs (1) valuable (not nominal) consideration, (2) good faith, and (3) no notice — actual or constructive. A buyer with knowledge of the prior claim cannot be a BFP, and a quitclaim-only taker generally fails the doctrine.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000022', 'In Madison v. Gordon (Tex. 2001), possession charges a purchaser with constructive notice only if the possession is described by which four adjectives?', 'short_answer', '[]'::jsonb, 'Visible, open, exclusive, and unequivocal', 'Madison v. Gordon, 39 S.W.3d 604 (Tex. 2001), holds that possession is constructive notice only if it is ''visible, open, exclusive, and unequivocal.'' This four-adjective test is stricter than the looser ''open and notorious'' standard used in many other states.', 'hard', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000023', 'True or False: In Texas, a grantee who receives land by quitclaim deed is generally treated as a bona fide purchaser entitled to full BFP protection.', 'true_false', '["True","False"]'::jsonb, 'False', 'A quitclaim grantee in Texas is generally NOT a bona fide purchaser, because the quitclaim itself puts the grantee on notice that the grantor''s title may be defective. This is stricter than many states, which treat a quitclaim grantee like any other purchaser.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000024', 'Which statement best describes a legal presumption?', 'multiple_choice', '["It is a form of direct evidence the surveyor must collect","It is a conclusion the law directs from established facts; it is not evidence but may substitute for evidence when evidence is lacking","It is a personal opinion of the surveyor with no legal weight","It is the same thing as an inference"]'::jsonb, 'It is a conclusion the law directs from established facts; it is not evidence but may substitute for evidence when evidence is lacking', 'A presumption is a legal conclusion drawn from established facts. It is not itself evidence, but it can stand in for evidence when none is available. It is distinct from an inference, which is reasoned by the factfinder rather than imposed by law.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000025', 'How does an inference differ from a presumption?', 'multiple_choice', '["An inference is imposed by law; a presumption is reasoned by the factfinder","An inference is a fact-deduction reasoned from other facts; a presumption is a conclusion the law directs","They are identical terms","An inference is always conclusive; a presumption is always rebuttable"]'::jsonb, 'An inference is a fact-deduction reasoned from other facts; a presumption is a conclusion the law directs', 'An inference is a logical deduction of fact the factfinder draws from the evidence; a presumption is a conclusion the law directs from established facts. They are not the same, and presumptions — not inferences — may be conclusive or rebuttable.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000026', 'Which kind of presumption accounts for most of the rules of law that control boundaries?', 'multiple_choice', '["Conclusive (irrebuttable) presumptions","Rebuttable presumptions","Statutory-only presumptions","No presumptions apply to boundaries"]'::jsonb, 'Rebuttable presumptions', 'Most boundary rules are rebuttable presumptions — they set the default but yield to superior evidence such as a found original monument or the surveyor''s footsteps. Conclusive presumptions are absolute and far less common in boundary work.', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000027', 'A deed describes land as bounded ''along an old county road'' (a non-navigable feature) with no express reservation of the roadbed. Which presumption typically applies in Texas?', 'multiple_choice', '["The grantor is presumed to have retained the entire roadbed","Title is presumed to extend to the center of the road, subject to the public easement","The deed is presumed void","Title is presumed to stop at the near edge of the road"]'::jsonb, 'Title is presumed to extend to the center of the road, subject to the public easement', 'The centerline presumption: land bounded by or along a road, street, or non-navigable watercourse is presumed to carry title to the center, subject to the public easement, unless clearly excluded. This is a rebuttable presumption.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000028', 'True or False: In Texas, the dignity-of-calls hierarchy (natural > artificial > course > distance > quantity) is an absolute rule that always controls, regardless of the grant''s intent or the original surveyor''s footsteps.', 'true_false', '["True","False"]'::jsonb, 'False', 'The dignity of calls is only a rebuttable rule of construction. It always yields to (i) the intent of the parties (paramount) and (ii) the footsteps of the original surveyor where they can be found on the ground. A found original monument controls over a conflicting field-note call.', 'medium', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920230-0000-0000-0000-000000000029', 'Under the common surveying presumptions, which of the following is presumed when a description contains courses and monuments?', 'multiple_choice', '["That no survey was ever performed","That a survey was actually conducted","That the description is automatically void","That the land must be re-platted before sale"]'::jsonb, 'That a survey was actually conducted', 'A standard surveying presumption is that when a description contains courses and monuments, a survey was actually conducted. Related presumptions hold that the lines were run on the ground and the corners were established and marked as returned.', 'easy', 'd2920000-0000-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('d2920210-0000-0000-0000-000000000006', 'd2920000-0000-0000-0000-000000000002', 'Homework & Practice', '', ARRAY[]::text[], 6, 45, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, 'Module homework assignment(s) and practice problems.', ARRAY[]::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0006-0000-0000-000000000000', 'd2920210-0000-0000-0000-000000000006', 'text', '{"html":"<h2>Homework &amp; Practice</h2><p>Complete the homework below. You may submit a draft up to 48 hours before the deadline for instructor feedback. Use the randomized practice problems to prepare for the quiz.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0006-0000-0000-000000000001', 'd2920210-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 1 — Trace a Texas Boundary Dispute Through the Court System and the Sources of Law</h3><p><em>Type: written</em></p><div>**Written assignment (non-computational). Answer in complete sentences; cite the relevant Texas code sections and the case from the lesson where appropriate.**<br/><br/>A landowner in a rural Texas county hires you to retrace a boundary. You discover that the neighbor''s recently recorded deed overlaps your client''s older (but previously **unrecorded**) deed by about 15 feet, and the neighbor''s fence sits on the disputed strip. The neighbor claims to have bought in good faith for full value with no knowledge of your client''s deed.<br/><br/>1. **Sources of law (Lesson 1).** List, in order of authority, the sources of law that could bear on this dispute (constitution, statutes, administrative rules, ordinances, case law). For each, give one concrete example relevant to *this* boundary problem (e.g., which Texas code governs recording, which governs surveyor conduct).<br/>2. **The court path (Lessons 2-3).** In which Texas trial court would a suit to resolve this dispute begin, and why? Trace the case up through the appellate level to the correct court of last resort. Explain *why* the Texas Court of Criminal Appeals is **not** the final authority here. Identify one issue in the case that is a **question of fact** (hard to appeal) and one that is a **question of law** (appealable).<br/>3. **Recording and the BFP (Lesson 4).** Texas is a pure **notice** jurisdiction. Apply **Tex. Property Code §§13.001 and §13.002** to decide, on these facts, whether the neighbor likely qualifies as a **bona fide purchaser** and what the consequence is for your client''s unrecorded deed. Then explain how the rule of **Madison v. Gordon** (possession as constructive notice) could change the outcome — specifically, what about the **fence/possession** might have charged the neighbor with constructive notice, defeating BFP status.<br/>4. **Reflection.** In two or three sentences, explain how a different recording regime (a **race-notice** state) might produce a different result on the same facts.<br/><br/>*Length: roughly 1.5-2 pages.*</div>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920220-0006-0000-0000-000000000002', 'd2920210-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 2 — Presumptions, Inferences, and the Dignity of Calls in Retracement</h3><p><em>Type: written</em></p><div>**Written assignment (non-computational). Answer in complete sentences.**<br/><br/>1. **Presumption vs. inference.** In your own words, define a legal **presumption** and a legal **inference**, and explain the key difference (which is imposed by law, and which is reasoned from facts). Give one boundary-surveying example of each. Then explain why a presumption is said to be ''not evidence'' yet can ''substitute for evidence.''<br/>2. **Conclusive vs. rebuttable.** Explain the difference between a conclusive and a rebuttable presumption, and state which type accounts for **most** of the rules that control boundaries. Why does that matter to a surveyor who finds a monument that conflicts with the record?<br/>3. **Apply the common surveying presumptions.** You are retracing an old survey. The original field notes describe courses and monuments, but several monuments are missing. List **four** of the ''common surveying presumptions'' from the lesson that you could rely on, and explain how each helps you reconstruct the original line. Address how the presumption that an **ancient survey is correct when accepted and treated as such by the parties** could support your work.<br/>4. **Dignity of calls and the Texas overrides.** A single Texas deed contains conflicting calls: a call to a **natural monument** (a creek), a **course** (a bearing), and a **distance**. State the order in which these calls control under the dignity-of-calls hierarchy. Then explain the **two things** that override the entire hierarchy in Texas (hint: one concerns the parties'' intent; the other concerns the original surveyor). Conclude by explaining, in two or three sentences, why a *found and identified* original monument on the ground will control over a conflicting field-note call.<br/><br/>*Length: roughly 1.5-2 pages.*</div>"}'::jsonb, 2);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000000', 'd2920310-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The Nature of an Easement</h3><p>An <strong>easement</strong> is an <em>incorporeal, nonpossessory</em> right (a hereditament) of one party to use the land of another for a specific, limited purpose. It is <strong>not ownership of the land</strong> &mdash; it is an interest <em>in</em> the land. Several consequences flow from this definition:</p><ul><li>An easement always burdens <strong>the land of another</strong>; you cannot hold an easement over your own land (the two interests merge).</li><li>It is limited to a <strong>special use and purpose</strong> &mdash; the holder may not exceed the scope granted.</li><li>The grantor can convey only the rights the landowner actually has, and <strong>no more</strong>.</li><li>When an easement is granted for a specific purpose, <strong>fee title to the burdened land remains with the grantor</strong>, their heirs, or assigns. The easement is a carve-out of use, not of ownership.</li></ul><p>Between private parties Texas presumes a deed conveys <em>fee simple</em> unless the writing shows a lesser estate was intended (Tex. Prop. Code &sect;5.001). For the public, unless a conveyance or statute says otherwise, the presumption is that the public acquires only an <strong>easement</strong> in highways, not the fee.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000001', 'd2920310-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Appurtenant Easements vs. Easements in Gross</h3><p>The single most important classification turns on whether the easement benefits <em>another parcel of land</em> or merely a <em>person/entity</em>.</p><ul><li><strong>Appurtenant easement</strong> &mdash; created to benefit other land. The benefited parcel is the <strong>dominant tenement (estate)</strong>; the burdened parcel is the <strong>servient tenement (estate)</strong>. Appurtenant easements <em>\"run with the land\"</em>: they pass automatically to later owners and do <strong>not</strong> disappear merely because a later deed fails to mention them or because the easement goes unused. A classic example is a private access driveway benefiting a back lot.</li><li><strong>Easement in gross</strong> &mdash; benefits no other land. There is a <strong>servient tenement but no dominant tenement</strong>. Common examples are <em>gas pipeline, electric, and other utility easements</em> held by a company rather than by a neighboring landowner.</li></ul><p>For the surveyor, the practical takeaway is that <strong>all easements involve three things to identify and describe</strong>: (1) the dominant parcel, (2) the servient parcel, and (3) the easement strip itself.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000002', 'd2920310-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Dominant tenement (land benefiting) and servient tenement (land burdened), with the easement site straddling the servient parcel."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', 'table', '{"headers":["Feature","Appurtenant","In Gross"],"rows":[["Dominant tenement","Yes (benefited land)","None"],["Servient tenement","Yes","Yes"],["Runs with the land?","Yes — passes to later owners","Traditionally personal (utility cos. an exception)"],["Typical example","Access driveway to a back lot","Gas pipeline / utility easement"],["Survives non-use / omission in later deed?","Yes","Depends on terms"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000004', 'd2920310-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Affirmative vs. Negative; Servitudes</h3><p>An <strong>affirmative easement</strong> permits the holder to <em>do</em> some physical act on the servient land (drive across it, run a pipeline). A <strong>negative easement</strong> lets the dominant holder <em>prevent</em> the servient owner from some use of the servient land (for example, an easement of light and air, or a scenic/conservation restriction). Negative easements are far less common and are narrowly recognized.</p><p>The civil-law term <strong>servitude</strong> describes essentially the same idea &mdash; a limited real right over another&rsquo;s property entitling the holder to certain powers of use and enjoyment. In surveying practice the words are used interchangeably with easement.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000005', 'd2920310-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Common Easement Types the Surveyor Encounters</h3><p>The <strong>right-of-way</strong> is the easement a land surveyor meets most often. Rights-of-way may serve ingress/egress, utility lines, pipelines, or highways, and may be acquired in <em>fee, by easement, by dedication, or by prescription</em>. A <strong>public</strong> right-of-way (highway, public road) may be used by every citizen; a <strong>private</strong> right-of-way serves a particular person, separate from the general public. Other recurring types include:</p><ul><li><strong>Utility easements</strong> &mdash; common in platted subdivisions for electric, telephone, cable, fiber, and pipelines (poles, wires, and underground lines).</li><li><strong>Drainage easements</strong> &mdash; carry runoff across the land of another.</li><li><strong>Flowage easements</strong> &mdash; the right to flood water onto another&rsquo;s land.</li><li><strong>Slope easements</strong> &mdash; shown on highway parcel maps; permit maintaining cut/fill slopes adjacent to the road. These may <em>terminate</em> when the slope no longer needs maintaining, if the deed so provides.</li></ul>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000006', 'd2920310-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Surveyor''s drafting duty: a legal description for an easement must avoid ambiguity. Include the parent (servient) parcel and easement location, the kind and manner of permitted uses, who the users are, and the purpose of the easement."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0001-0000-0000-000000000007', 'd2920310-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["An easement is a non-possessory right to use another''s land; fee title stays with the servient owner.","Appurtenant easements benefit a dominant estate and run with the land; easements in gross (utilities, pipelines) benefit a person/entity with no dominant estate.","Every easement involves three descriptions: dominant parcel, servient parcel, and the easement strip itself.","Affirmative easements permit an act; negative easements prevent a servient use and are narrowly recognized."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0002-0000-0000-000000000000', 'd2920310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Two Basic Routes to an Easement</h3><p>Because an easement is an interest in land, it falls under the <strong>Statute of Frauds</strong> (in Texas, Tex. Bus. &amp; Com. Code &sect;26.01 &mdash; a conveyance of an interest in land must be in writing and signed). Broadly, easements arise in only two ways:</p><ul><li><strong>Through writings</strong> (express grant, reservation, exception, dedication by written plat); and</li><li><strong>Created at law / by operation of law</strong> (implied by prior use, by necessity, by prescription, or by estoppel).</li></ul><p>For a written easement to be valid, the description must allow the two parcels <em>and</em> the easement to be identified <strong>without ambiguity</strong>.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0002-0000-0000-000000000001', 'd2920310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Express Easements</h3><p>The <strong>express easement</strong> is a deeded easement and is the <em>most commonly used</em> and most-favored method of creation. The instrument satisfies the Statute of Frauds and is recorded, giving constructive notice to subsequent purchasers. Because Texas courts <em>disfavor</em> the implied and prescriptive routes, Texas access rights are far more often documented <strong>expressly</strong> than created by operation of law &mdash; a recurring theme of this module.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0002-0000-0000-000000000002', 'd2920310-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Texas differs (practical point): Because Texas scrutinizes implied and prescriptive easements strictly, the safest and most common way to secure access in Texas is an express, recorded grant. When in doubt, get it in writing and record it."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0002-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Reservation vs. Exception</h3><p>A grantor conveying land can carve out an easement in two related but distinct ways:</p><ul><li><strong>Exception</strong> &mdash; the grantor <em>withholds from the conveyance</em> a part of the land (or interest) that otherwise would have passed. Nothing new is created; an existing thing is simply excluded.</li><li><strong>Reservation</strong> &mdash; the grantor creates and keeps a <em>new right or interest that did not exist before</em> the conveyance (for example, reserving an access easement across the parcel being sold).</li></ul><p>The distinction matters because a reservation creates a fresh interest in the grantor, while an exception merely removes something from the grant.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0002-0000-0000-000000000004', 'd2920310-0000-0000-0000-000000000002', 'table', '{"headers":["Mechanism","What happens","Creates a new interest?"],"rows":[["Express grant","Grantor conveys an easement to the grantee","Yes, in grantee"],["Reservation","Grantor keeps a new easement over land sold","Yes, in grantor"],["Exception","Grantor withholds existing land/interest from the conveyance","No — excludes existing"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0002-0000-0000-000000000005', 'd2920310-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Easement by Estoppel</h3><p>An <strong>easement by estoppel</strong> arises when one party leads another to reasonably believe an easement exists, and the second party relies on that belief to his detriment. The recognized elements are:</p><ul><li>One party <strong>knows the true situation</strong>;</li><li>That party <strong>remains silent or affirmatively encourages</strong> the other party in an innocent belief;</li><li>The other party <strong>relies</strong> on the actions/representations of the first; and</li><li>It would be inequitable to let the first party <strong>change the position</strong> he led the innocent party to believe.</li></ul><p>Estoppel is an equitable doctrine &mdash; it prevents a landowner from denying an easement after inducing reasonable, detrimental reliance.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0002-0000-0000-000000000006', 'd2920310-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Easements are interests in land governed by the Statute of Frauds; they arise through writings or by operation of law.","The express, recorded easement is the most common and most-favored method — especially important in Texas, which disfavors implied/prescriptive easements.","A reservation creates a new interest kept by the grantor; an exception merely withholds something that already existed.","Easement by estoppel bars a landowner from denying an easement after inducing another''s reasonable, detrimental reliance."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000000', 'd2920310-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Implied Easement by Prior Use (Quasi-Easement)</h3><p>An easement may be <em>implied</em> from a prior use existing before a tract is split. Classic example: a tract has a garage at the rear served by a driveway; the owner subdivides and sells the rear portion without mentioning the driveway. An easement is implied so the rear lot keeps its access. These easements are <strong>not recorded</strong>, so the surveyor must watch for their existence. The Texas elements are:</p><ul><li><strong>Unity of ownership</strong> before severance;</li><li>Use <strong>open and apparent</strong> at the time of severance;</li><li>Use <strong>continuous</strong> (so the parties must have intended it to pass); and</li><li>Use <strong>reasonably necessary</strong> &mdash; a <em>lower</em> bar than the strict necessity required for a necessity easement.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000001', 'd2920310-0000-0000-0000-000000000003', 'accordion', '{"sections":[{"title":"Case: Hamrick v. Ward, 446 S.W.3d 377 (Tex. 2014)","content":"<p>The Texas Supreme Court <strong>restricted prior-use for roadway/access claims</strong>. A party claiming an implied easement <em>for roadway access</em> to a landlocked, previously unified parcel must now proceed under <strong>easement-by-necessity, NOT prior use</strong>. Prior use still applies to non-access uses (utility lines, drainage) where it remains ''reasonably necessary.'' This narrows a doctrine that had been unsettled in Texas for roughly 125 years and pushes landlocked road-access claims into the stricter necessity framework.</p>","open":false}]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000002', 'd2920310-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Easement by Necessity</h3><p>This type of implied easement is necessary to the very use of the property and is one of the most difficult to obtain. It typically applies to <strong>landlocked parcels</strong>, and it <em>terminates when the necessity ceases</em> (for example, when alternative legal access becomes available). Texas requires <strong>all three</strong> elements:</p><ul><li><strong>Unity of ownership</strong> of the dominant and servient estates <em>prior to severance</em> &mdash; the grantor must have owned both as a single tract or unit;</li><li>Access is a <strong>present strict necessity, not a mere convenience</strong>; and</li><li>The necessity <strong>existed at the time of severance</strong>.</li></ul>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Texas differs: Texas demands STRICT necessity (a true landlock with no legal access), while many states accept mere ''reasonable'' necessity. Texas also enforces the unity-of-ownership element rigorously (Koonce v. Brite Estate, 663 S.W.2d 451 (Tex. 1984)) and terminates the easement when the necessity ends."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000004', 'd2920310-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Prescriptive Easements &mdash; and Why Texas Disfavors Them</h3><p>A <strong>prescriptive easement</strong> is acquired by long, continued use of another&rsquo;s land for the purpose of the intended easement. Its elements borrow from adverse possession (in Texas, the 10-year period of &sect;16.026): the use must be (1) <strong>open and notorious</strong>, (2) <strong>continuous and uninterrupted</strong>, (3) <strong>adverse/hostile</strong> (permissive use can <em>never</em> ripen), and (4) <strong>exclusive</strong>, for the full statutory period. <strong>Permission cancels the claim</strong>; so does a friendly &ldquo;neighborly accommodation,&rdquo; which is consent personal to those two neighbors and does not bind later owners. Payment of property taxes is not required for a prescriptive <em>easement</em> (as opposed to fee ownership).</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000005', 'd2920310-0000-0000-0000-000000000003', 'callout', '{"type":"error","text":"THE KEY TEXAS POINT — Exclusivity: In Texas, ''exclusive'' means use by the claimant and NOT by the landowner. JOINT or SHARED use DEFEATS the claim. Texas courts hold that ''joint use of a road, no matter how long, cannot ripen into a prescriptive easement.'' Under the general common-law/Restatement view an easement is non-possessory, so most states do NOT require exclusivity — Texas is the opposite. Because most driveway/road-sharing fact patterns involve some owner use, Texas prescriptive claims rarely succeed."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000006', 'd2920310-0000-0000-0000-000000000003', 'accordion', '{"sections":[{"title":"Case: Tran v. Macha, 213 S.W.3d 913 (Tex. 2006)","content":"<p>Neighbors shared a driveway under a mutual mistake about the boundary. The Texas Supreme Court <strong>reversed</strong> the easement, holding that mutual/joint use does <strong>not</strong> support an exclusive, hostile claim. There must be an ''unmistakable assertion of a claim of exclusive ownership.'' This is the headline authority for the proposition that Texas disfavors prescriptive easements and that joint use is normally fatal to the exclusivity element.</p>","open":true}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000007', 'd2920310-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Dedication: Statutory vs. Common-Law</h3><p><strong>Dedication</strong> gives the public a right of use (often passage). It does <strong>not</strong> burden the municipality with maintenance unless the public body <em>accepts</em> the dedication &mdash; acceptance is a <strong>separate event</strong>, which may be express (official action of the legislative body) or implied (years of public use plus repair by the proper authorities).</p><ul><li><strong>Statutory dedication</strong> &mdash; made by recording a <em>plat/map</em> marking streets/areas for public use under the platting statutes (Tex. Loc. Gov&rsquo;t Code Chs. 212/232; Tex. Prop. Code Ch. 12). Plat approval is <strong>not</strong> automatically acceptance.</li><li><strong>Common-law dedication</strong> &mdash; requires (1) the owner&rsquo;s acts showing <strong>donative intent</strong>, (2) <strong>public reliance/benefit</strong>, and (3) <strong>offer and acceptance</strong> (formal or informal, e.g., the authority grades/repairs the road or the public uses it).</li></ul><p>Note the related <em>implied dedication from a subdivision plat</em>: when an owner subdivides, a purchaser of any lot acquires an easement over the streets shown on the plat, and an implied dedication to the public has occurred.</p>"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000008', 'd2920310-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Texas differs (CRITICAL — the 1981 statute): Under Tex. Transp. Code Ch. 281 (eff. Aug. 1981), Texas ABOLISHED implied dedication of a public road on private property in counties of 50,000 or fewer. There, public road status can be acquired only by purchase, condemnation, an EXPRESS WRITTEN dedication communicated to the commissioners court, or a final adverse-possession judgment. ''Everyone has always used it'' is no longer enough. Not retroactive — roads impliedly dedicated before August 1981 survive."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0003-0000-0000-000000000009', 'd2920310-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Implied-by-prior-use needs unity of ownership, open/apparent + continuous use, and reasonable necessity; after Hamrick v. Ward, landlocked road access must go through necessity, not prior use.","Easement by necessity in Texas requires unity of ownership before severance, strict (not mere) necessity, and necessity at severance — and it ends when the necessity ends.","Texas disfavors prescriptive easements; the exclusivity element means joint/shared use defeats the claim (Tran v. Macha).","Statutory dedication is by recorded plat; common-law dedication needs donative intent, reliance, and acceptance. Texas abolished implied dedication of public roads in small counties (Transp. Code Ch. 281, 1981)."]}'::jsonb, 9);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000000', 'd2920310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The Elements of Adverse Possession</h3><p><strong>Adverse possession</strong> is a method of acquiring title by possession for a statutory period under certain conditions. The general common-law elements require that possession be:</p><ul><li><strong>Actual</strong> &mdash; the claimant physically acts as an owner; mere oral or written claims are not enough.</li><li><strong>Open &amp; notorious</strong> &mdash; possession obvious enough that an owner who investigates would notice the trespass.</li><li><strong>Exclusive</strong> &mdash; the possessor does not share possession with the true owner or the public.</li><li><strong>Hostile</strong> (adverse, under claim of right) &mdash; possession is in opposition to the true owner&rsquo;s rights; <em>permissive</em> use can never be adverse.</li><li><strong>Continuous &amp; uninterrupted</strong> &mdash; all elements must be met at all times throughout the statutory period.</li></ul><p>Government-owned (public) land is generally <strong>exempt</strong> from adverse possession.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000001', 'd2920310-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas differs — it is WHOLLY STATUTORY: Texas adverse possession lives in Tex. Civ. Prac. & Rem. Code Ch. 16, Subch. B — NOT the Property Code. Instead of one common-law test, Texas offers several distinct limitation periods (3/5/10/25 years), each with its own elements. A claimant pleads under the period whose elements it can meet."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000002', 'd2920310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Statutory Definitions (§16.021)</h3><p>The Texas statute defines its terms precisely:</p><ul><li><strong>&ldquo;Adverse possession&rdquo;</strong> = an actual and visible appropriation of real property, commenced and continued under a <em>claim of right</em> inconsistent with and hostile to the claim of another.</li><li><strong>&ldquo;Color of title&rdquo;</strong> = a consecutive chain of transfers to the possessor that is <em>not</em> a regular chain from the sovereign, or a regular chain with a missing or defective link.</li><li><strong>&ldquo;Title&rdquo;</strong> = a regular chain of transfers from or under the sovereignty of the soil.</li><li><strong>&ldquo;Peaceable possession&rdquo;</strong> = continuous possession not interrupted by an adverse suit to recover the property.</li></ul>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'table', '{"headers":["Statute","Period","Core requirement"],"rows":[["§16.024","3 yr","Peaceable & adverse possession under TITLE or COLOR OF TITLE (strongest paper basis → shortest period)"],["§16.025","5 yr","Cultivate/use/enjoy + PAY TAXES + claim under a duly registered deed (excludes quitclaim/forged). A single missed tax year is fatal."],["§16.026","10 yr","Peaceable & adverse, cultivating/using/enjoying; no instrument or taxes needed, but capped at 160 acres unless enclosed or under a recorded deed fixing the boundaries"],["§16.028","25 yr","Under a RECORDED instrument purporting to convey, EVEN IF VOID on its face or in fact (excludes quitclaim/forged); extends to the whole area described"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000004', 'd2920310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Reading the Scheme</h3><p>Notice the logic: the <strong>stronger the paper basis</strong>, the <strong>shorter the period</strong>. With title or color of title you may perfect in just <strong>3 years</strong> (&sect;16.024). With a registered deed plus tax payments and use, <strong>5 years</strong> (&sect;16.025). With nothing but naked possession and use, <strong>10 years</strong> &mdash; but capped at <strong>160 acres</strong> unless the larger area is enclosed or held under a recorded deed fixing the boundaries (&sect;16.026). A <em>recorded but void</em> instrument supports a <strong>25-year</strong> claim over the whole described area (&sect;16.028). A separate 25-year long-stop (&sect;16.027) runs regardless of legal disability such as minority or unsound mind.</p><p><strong>Tacking:</strong> successive possessors in <em>privity</em> (each transferring possession to the next) may add their periods together to reach the statutory total &mdash; but Texas&rsquo;s statutory prerequisites (taxes, registered deed, recorded instrument) make tacking more formalized than at common law.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000005', 'd2920310-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas differs (distinctive features): (1) The 5-year track (§16.025) requires PAYING PROPERTY TAXES — absent from traditional common law and a frequent claim-killer. (2) The 10-year track''s 160-ACRE CAP (absent enclosure or a recorded deed) has no general common-law analog. (3) The §16.028 VOID-INSTRUMENT track is broader than common-law ''color of title.''"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000006', 'd2920310-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Acquiescence &mdash; A Related but Different Doctrine</h3><p>If possession was <em>not</em> hostile, a boundary may still shift by <strong>acquiescence</strong>. In acquiescence cases <em>neither neighbor intends to take the other&rsquo;s land</em>; there is a <strong>mutual mistake</strong> about the true line. The requirements typically are good faith plus a long period of recognition: occupation must be visible up to a definite, marked line, and a long time must elapse. When satisfied, <strong>title passes silently</strong> &mdash; the occupied line becomes the boundary. Because acquiescence rests on mutual mistake rather than hostility, it is the counterpoint to adverse possession (which requires hostility).</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0004-0000-0000-000000000007', 'd2920310-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Common-law adverse possession requires actual, open & notorious, exclusive, hostile, and continuous possession for the statutory period; permissive use is never hostile.","Texas adverse possession is wholly statutory (Civ. Prac. & Rem. Code Ch. 16) with multiple tracks: 3 yr (color of title), 5 yr (deed + taxes + use), 10 yr (use; 160-acre cap), 25 yr (recorded-but-void instrument).","The stronger the paper/title basis, the shorter the period; the 5-year tax-payment requirement and 10-year acreage cap are distinctively Texan.","Acquiescence (mutual mistake, no hostility) can move a boundary line silently — contrast with hostile adverse possession."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000000', 'd2920310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>License vs. Easement</h3><p>A <strong>license</strong> is mere <em>permission</em> to use another&rsquo;s land &mdash; it is <strong>personal</strong>, generally <strong>revocable</strong> at the will of the landowner, and does <strong>not</strong> create an interest in land (so it is not subject to the Statute of Frauds and does not run with the land). An <strong>easement</strong>, by contrast, is an <em>interest in land</em>: it is generally irrevocable within its terms, must satisfy the Statute of Frauds if created expressly, and (if appurtenant) runs with the land. Recall that <strong>permissive</strong> use &mdash; the hallmark of a license &mdash; can never ripen into a prescriptive easement.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000001', 'd2920310-0000-0000-0000-000000000005', 'table', '{"headers":["Attribute","License","Easement"],"rows":[["Nature","Personal permission","Interest in land"],["Revocable?","Generally yes, at will","Generally no (within terms)"],["Statute of Frauds?","No","Yes (if express)"],["Runs with the land?","No","Yes, if appurtenant"],["Can ripen by prescription?","No (permissive)","—"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000002', 'd2920310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Encroachments</h3><p>An <strong>encroachment</strong> is an unauthorized physical intrusion of an improvement &mdash; a fence, building, eave, or driveway &mdash; onto a neighbor&rsquo;s land. Texas remedies include: <strong>trespass to try title / quiet title</strong> (Tex. Prop. Code Ch. 22), an <strong>injunction</strong> to remove the encroachment, or <strong>damages</strong>. A long-standing encroachment can mature into <em>title</em> via adverse possession or into a <em>use-right</em> via prescriptive easement &mdash; but both are hard in Texas because of the strict statutory elements and the exclusivity rule (joint use defeats prescription, <em>Tran v. Macha</em>).</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"Texas differs: Texas has no general ''innocent improver'' / relative-hardship statute that automatically lets a good-faith encroacher buy the strip. Title passes only through the statutory adverse-possession tracks (though courts may still balance equities for injunctive relief). The surveyor''s measured boundary location is typically dispositive, and acquiescence/agreed-boundary doctrines are applied narrowly."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000004', 'd2920310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Covenants and Restrictions</h3><p>A <strong>covenant</strong> is an agreement between parties that restricts the use of a freehold &mdash; in effect, a restriction on use by common agreement &mdash; and it is enforceable only if it is <strong>legal</strong>. Restrictive covenants (deed restrictions, subdivision CC&amp;Rs) differ from easements: a covenant <em>limits how the burdened owner may use his own land</em> (e.g., residential-use-only, setback, no commercial activity), whereas an easement <em>grants someone else a right to use</em> the burdened land. A covenant that &ldquo;runs with the land&rdquo; binds successors, much like an appurtenant easement, but its subject is land <em>use restriction</em>, not a right of physical use.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000005', 'd2920310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Eminent Domain and Condemnation</h3><p><strong>Eminent domain</strong> is the power of a sovereign to take, or authorize the taking of, private property for public use without the owner&rsquo;s consent, conditioned on payment of <strong>just compensation</strong>. The formal exercise is <strong>condemnation</strong>. Importantly for surveyors: when land is taken for public use, the condemnor acquires only an <strong>easement</strong> unless the fee is necessary for the purpose, or a statute or deed conveys the fee. So a road or utility taking often leaves <em>underlying fee</em> in the original owner, subject to the public easement.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000006', 'd2920310-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Reversion (Reversionary) Rights Along Vacated Streets</h3><p>A <strong>reversionary right</strong> permits an adjacent landowner to gain or regain property rights within a <em>vacated</em> easement (such as an abandoned street). When a public easement is vacated, the old underlying boundary lines revive. The general principle: <em>unless a deed or map creating the easement indicates otherwise, reversion rights extend from the street termini of the property lines to the centerline (or thread) of the street, in a direction at right angles to the centerline.</em> Practical rules:</p><ul><li><strong>Mid-block lots</strong> revert to the centerline; <strong>curved streets</strong> revert <em>radially</em>; <strong>angle points</strong> use the <em>bisection of the angle</em>.</li><li>You <strong>cannot</strong> extend reversion rights beyond the original boundaries.</li><li>Beware a <strong>private</strong> easement underlying a vacated <strong>public</strong> one, and note that some statutes automatically include a utility easement in a public road easement.</li><li>The surveyor should <em>document</em> apparent inconsistent use but <strong>not make legal use decisions</strong> &mdash; the obligation is to notify the client. (This connects to the Module 1&ndash;2 centerline/strip-and-gore presumptions: land bounded &ldquo;by&rdquo; or &ldquo;along&rdquo; a road is presumed to carry title to the center, subject to the public easement, unless clearly excluded.)</li></ul>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000007', 'd2920310-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Reversion rights extend from the street-side property termini to the centerline of a vacated street — perpendicular on tangents, radial on curves, and by angle bisection at angle points."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0005-0000-0000-000000000008', 'd2920310-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["A license is revocable personal permission and creates no interest in land; an easement is an interest in land that (if appurtenant) runs with the land.","Encroachments are remedied in Texas by trespass-to-try-title/quiet title, injunction, or damages; there is no general innocent-improver statute, and the surveyed boundary usually controls.","Covenants restrict how the burdened owner may use his own land; easements grant another a right to use it.","Eminent-domain takings usually acquire only an easement unless the fee is necessary; vacated-street reversion runs to the centerline (radial on curves, angle-bisected at corners) and cannot exceed original boundaries."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000001', 'Easement', 'An incorporeal, nonpossessory right to use the land of another for a specific, limited purpose; an interest in land, not ownership of it.', 'Use, not own.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000002', 'Dominant tenement (estate)', 'The parcel of land benefited by an appurtenant easement.', 'It ''dominates'' — it gets the benefit.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000003', 'Servient tenement (estate)', 'The parcel of land burdened by an easement.', 'It ''serves'' — it carries the burden.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000004', 'Appurtenant easement', 'An easement created to benefit other land; it runs with the land and passes to later owners even if a later deed omits it or it goes unused.', 'Attached to a benefited parcel.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000005', 'Easement in gross', 'An easement that benefits no other land — there is a servient tenement but no dominant tenement (e.g., utility and pipeline easements).', 'Personal/entity benefit, no dominant estate.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000006', 'Negative easement', 'An easement allowing the dominant holder to prevent the servient owner from some use of the servient land (e.g., light and air); narrowly recognized.', 'It stops a use rather than permitting one.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000007', 'Express easement', 'A deeded easement satisfying the Statute of Frauds; the most common and most-favored method of creating an easement.', 'Written and recorded.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000008', 'Reservation', 'A deed mechanism by which the grantor creates and retains a new right or interest (e.g., an easement) that did not exist before the conveyance.', 'Grantor keeps something NEW.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000009', 'Exception', 'A deed mechanism by which the grantor withholds from the conveyance land or an interest that otherwise would have passed.', 'Excludes something that already existed.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000010', 'Easement by estoppel', 'An equitable easement arising when a landowner induces another''s reasonable belief that an easement exists and that party detrimentally relies on it.', 'Silence + reliance = can''t take it back.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000011', 'Statute of Frauds (easements)', 'Rule (Tex. Bus. & Com. Code §26.01) requiring conveyances of interests in land, including easements, to be in writing and signed.', 'Land interests must be written.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000012', 'Implied easement by prior use', 'An easement implied when, before a tract is split, a use was open/apparent and continuous and is reasonably necessary to the conveyed parcel; requires prior unity of ownership.', 'Quasi-easement existing before the split.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000013', 'Easement by necessity (Texas)', 'An implied easement requiring unity of ownership before severance, STRICT necessity (true landlock), and that the necessity existed at severance; terminates when the necessity ends.', 'Landlocked + strict necessity at severance.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000014', 'Prescriptive easement', 'A use-right gained by open & notorious, continuous & uninterrupted, adverse/hostile, and exclusive use for the statutory period (10 yr in Texas); permission defeats it.', 'Like adverse possession, but a USE right.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000015', 'Exclusivity (Texas prescription)', 'In Texas, ''exclusive'' means use by the claimant and not by the owner; joint or shared use defeats a prescriptive-easement claim (Tran v. Macha).', 'Sharing the road is fatal in Texas.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000016', 'Neighborly accommodation', 'Friendly, implied permission to use one''s land; it is personal to those neighbors, does not bind later owners, and prevents the use from being adverse/hostile.', 'Permission = not hostile.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000017', 'Statutory dedication', 'Dedication of streets/areas to public use made by recording a plat or map under the platting statutes; plat approval is not automatic acceptance.', 'By recorded plat.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000018', 'Common-law dedication', 'Dedication requiring the owner''s donative intent, public reliance/benefit, and offer and acceptance (formal or informal).', 'Intent + reliance + acceptance.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000019', 'Tex. Transp. Code Ch. 281 (1981)', 'Texas statute abolishing implied dedication of public roads on private land in counties of 50,000 or fewer; public status there requires written dedication, purchase, condemnation, or an adverse-possession judgment.', 'Kills implied road dedication in small counties.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000020', 'Adverse possession', 'Acquisition of title by actual, open & notorious, exclusive, hostile, and continuous possession for the statutory period under certain conditions.', 'Possess like an owner long enough to own.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000021', 'Hostile possession', 'Possession in opposition to the true owner''s rights, under a claim of right; permissive use is not hostile and cannot ripen.', 'Against the owner''s rights, not by permission.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000022', 'Color of title', 'A consecutive chain of transfers to the possessor that is not a regular chain from the sovereign, or a regular chain with a missing or defective link.', 'A defective paper basis.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000023', '§16.024 (3-year statute)', 'Texas adverse-possession period for peaceable, adverse possession held under title or color of title — the shortest period because of the strong paper basis.', 'Best paper → shortest time.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000024', '§16.025 (5-year statute)', 'Texas adverse-possession period requiring use/cultivation/enjoyment, PAYMENT OF TAXES, and a duly registered deed (no quitclaim/forged); one missed tax year is fatal.', 'Deed + taxes + use = 5 years.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000025', '§16.026 (10-year statute)', 'Texas adverse-possession period for peaceable, adverse possession with use; no deed or taxes needed but capped at 160 acres unless enclosed or under a recorded deed fixing the boundaries.', 'Naked possession; 160-acre cap.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000026', '§16.028 (25-year statute)', 'Texas adverse-possession period under a recorded instrument purporting to convey, even if void on its face or in fact; extends to the whole described area.', 'Recorded but void instrument.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000027', 'Acquiescence', 'Boundary doctrine where neighbors, under a mutual mistake about the true line and with no hostility, recognize a marked line for a long period until title passes silently.', 'Mutual mistake, not hostility.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000028', 'Tacking', 'Adding the possession periods of successive possessors who are in privity to satisfy the statutory limitation period.', 'Chain the years together via privity.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000029', 'License (property)', 'Revocable, personal permission to use another''s land; creates no interest in land and does not run with the land.', 'Permission you can take back.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000030', 'Encroachment', 'An unauthorized physical intrusion of an improvement (fence, building, eave, driveway) onto a neighbor''s land.', 'A structure crossing the line.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000031', 'Covenant / restriction', 'An agreement restricting the use of a freehold by common agreement; enforceable only if legal. Limits how the burdened owner may use his own land.', 'A use restriction, not a use right.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000032', 'Eminent domain', 'The sovereign''s power to take private property for public use without consent, on payment of just compensation; exercised through condemnation.', 'Public take + just compensation.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000033', 'Condemnation', 'The formal legal process of exercising eminent domain to transfer title (or an easement) from a private owner to the government.', 'The procedure that effects the taking.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920340-0000-0000-0000-000000000034', 'Reversionary right', 'The right of an adjacent landowner to gain or regain property rights within a vacated easement (e.g., an abandoned street), generally extending to the street centerline.', 'Get the vacated street strip back to centerline.', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000001', 'Which statement best describes the legal nature of an easement?', 'multiple_choice', '["It is a possessory ownership interest equal to fee simple.","It is a nonpossessory right to use the land of another for a limited purpose.","It transfers fee title of the burdened land to the easement holder.","It can be held by an owner over that owner''s own land."]'::jsonb, 'It is a nonpossessory right to use the land of another for a limited purpose.', 'An easement is an incorporeal, nonpossessory interest in another''s land for a specific use; fee title remains with the servient owner. You cannot hold an easement over your own land (the interests merge), and it never conveys fee ownership.', 'easy', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000002', 'A back lot benefits from a driveway easement across a front lot. The benefited back lot is best described as the:', 'multiple_choice', '["Servient tenement","Dominant tenement","Easement in gross holder","Licensee"]'::jsonb, 'Dominant tenement', 'The parcel benefited by an appurtenant easement is the dominant tenement; the burdened front lot is the servient tenement. This is appurtenant (it benefits land), not in gross, and it is an easement, not a license.', 'easy', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000003', 'A gas pipeline company holds an easement crossing a ranch. This easement is in gross because:', 'multiple_choice', '["It benefits the adjoining ranch as a dominant estate.","There is a servient tenement but no dominant tenement.","It is revocable at the landowner''s will.","It cannot be recorded."]'::jsonb, 'There is a servient tenement but no dominant tenement.', 'An easement in gross benefits a person or entity (the pipeline company), not another parcel of land, so there is a servient tenement but no dominant tenement. It is not revocable like a license and is typically recorded.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000004', 'An appurtenant easement disappears automatically if a later deed of the dominant parcel fails to mention it.', 'true_false', '["True","False"]'::jsonb, 'False', 'Appurtenant easements run with the land. They do not disappear merely because a subsequent conveyance omits them or because they go unused.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000005', 'A slope easement shown on a highway parcel map permits the State to maintain a cut/fill slope. What feature is unique to this easement type as described in the source material?', 'multiple_choice', '["It can never be terminated.","It may terminate when the slope no longer needs maintaining, if the deed so provides.","It automatically conveys fee title to the State.","It is always an easement in gross held by a utility."]'::jsonb, 'It may terminate when the slope no longer needs maintaining, if the deed so provides.', 'Slope easements may terminate once the slopes no longer need to be maintained, depending on the specific wording of the deed.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000006', 'Why does the express, recorded easement remain the most-favored method of creating access rights in Texas in particular?', 'multiple_choice', '["Texas does not recognize any implied or prescriptive easements at all.","Texas courts disfavor implied/prescriptive routes, so documenting access expressly is safest.","Express easements are exempt from the Statute of Frauds.","Recording is impossible for any other easement type."]'::jsonb, 'Texas courts disfavor implied/prescriptive routes, so documenting access expressly is safest.', 'Because Texas strictly scrutinizes implied and prescriptive easements, access rights are far more often (and more safely) documented by an express, recorded grant. Express easements must satisfy the Statute of Frauds, and other easement types can also be recorded.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000007', 'A grantor sells a parcel but creates and keeps a new access easement across the land conveyed. This is an example of a(n):', 'multiple_choice', '["Exception","Reservation","License","Dedication"]'::jsonb, 'Reservation', 'A reservation creates a NEW right or interest retained by the grantor that did not exist before. An exception merely withholds something already existing; a license is revocable permission; dedication gives rights to the public.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000008', 'In a deed, an ''exception'' differs from a ''reservation'' in that an exception creates a brand-new interest in the grantor.', 'true_false', '["True","False"]'::jsonb, 'False', 'It is the reservation that creates a new interest in the grantor. An exception withholds from the conveyance land or an interest that already existed; it creates nothing new.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000009', 'Which is NOT an element of an easement by estoppel?', 'multiple_choice', '["One party knows the true situation.","That party remains silent or encourages the other''s innocent belief.","The other party relies on the first party''s actions.","The claimant pays property taxes for five years."]'::jsonb, 'The claimant pays property taxes for five years.', 'Tax payment is a feature of the 5-year adverse-possession statute, not estoppel. Easement by estoppel requires knowledge of the true situation, silence/encouragement, reliance, and detrimental change of position.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000010', 'After Hamrick v. Ward (Tex. 2014), a party claiming roadway access to a landlocked, previously unified parcel must proceed under which theory?', 'multiple_choice', '["Implied easement by prior use","Easement by necessity","Prescriptive easement","Easement by estoppel"]'::jsonb, 'Easement by necessity', 'Hamrick v. Ward channels landlocked road-access claims into the stricter easement-by-necessity framework rather than the easier ''reasonably necessary'' prior-use standard. Prior use still applies to non-access uses like utilities or drainage.', 'hard', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000011', 'Which set lists the Texas elements of an easement by necessity?', 'multiple_choice', '["Open & notorious, continuous, exclusive, hostile","Unity of ownership before severance, strict necessity, necessity at severance","Donative intent, reliance, acceptance","Writing, recording, tax payment"]'::jsonb, 'Unity of ownership before severance, strict necessity, necessity at severance', 'Texas requires all three: unity of ownership of dominant and servient estates before severance, strict (not mere) necessity, and that the necessity existed at the time of severance. The first option lists prescription elements; the third lists common-law dedication; the fourth describes the 5-year adverse-possession track.', 'hard', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000012', 'Two neighbors share a single driveway for over 20 years under a mutual mistake about the boundary. Under Texas law (Tran v. Macha), can one neighbor claim a prescriptive easement over the other''s portion?', 'multiple_choice', '["Yes — 20 years exceeds the 10-year period.","Yes — long use automatically creates the easement.","No — joint/shared use defeats the exclusivity element.","No — prescriptive easements do not exist in Texas."]'::jsonb, 'No — joint/shared use defeats the exclusivity element.', 'Tran v. Macha holds that in Texas ''exclusive'' means use by the claimant and not the owner; joint or shared use cannot ripen into a prescriptive easement no matter how long it lasts. Prescriptive easements do exist in Texas but are disfavored and strictly scrutinized.', 'hard', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000013', 'Texas requires a claimant to prove the exclusivity element for a prescriptive easement, which is the opposite of the general common-law/Restatement view.', 'true_false', '["True","False"]'::jsonb, 'True', 'Most jurisdictions do not require exclusivity for a prescriptive easement because an easement is non-possessory; shared use can still create one. Texas is the opposite — it requires exclusivity, so joint use is normally fatal.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000014', 'Under Tex. Transp. Code Ch. 281 (eff. 1981), how can the public acquire a road across private land in a county of 50,000 or fewer people?', 'multiple_choice', '["Only by long public use (''everyone has always used it'').","By purchase, condemnation, express written dedication, or an adverse-possession judgment.","Automatically when a plat is approved.","By oral dedication to any county employee."]'::jsonb, 'By purchase, condemnation, express written dedication, or an adverse-possession judgment.', 'Chapter 281 abolished implied dedication of public roads in small counties. Public road status there requires purchase, condemnation, an express written dedication to the commissioners court, or a final adverse-possession judgment. Mere public use is no longer sufficient.', 'hard', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000015', 'Permissive use (''neighborly accommodation'') can ripen into a prescriptive easement if it continues long enough.', 'true_false', '["True","False"]'::jsonb, 'False', 'Permission defeats the adverse/hostile element. A neighborly accommodation is consent personal to those neighbors; it can never ripen into a prescriptive easement no matter how long it lasts.', 'easy', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000016', 'Statutory dedication is accomplished primarily by which act?', 'multiple_choice', '["Recording a plat or map marking streets/areas for public use","Long-continued exclusive possession","Paying property taxes for five years","An oral promise to the public"]'::jsonb, 'Recording a plat or map marking streets/areas for public use', 'Statutory dedication is made by recording a plat/map under the platting statutes. Note that plat approval is not automatically acceptance — acceptance is a separate event.', 'easy', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000017', 'Which is NOT one of the common-law elements of adverse possession?', 'multiple_choice', '["Open and notorious","Hostile","Permissive","Continuous"]'::jsonb, 'Permissive', 'Adverse possession requires actual, open & notorious, exclusive, hostile, and continuous possession. Permissive use is the opposite of hostile and defeats a claim.', 'easy', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000018', 'In Texas, the law of adverse possession is found in:', 'multiple_choice', '["The Texas Property Code","The Texas Natural Resources Code","The Texas Civil Practice & Remedies Code, Chapter 16","The Texas Transportation Code"]'::jsonb, 'The Texas Civil Practice & Remedies Code, Chapter 16', 'A common trap: Texas adverse possession is wholly statutory and lives in Civ. Prac. & Rem. Code Ch. 16, Subch. B — NOT the Property Code.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000019', 'Which Texas adverse-possession statute requires the claimant to pay property taxes and hold under a duly registered deed?', 'multiple_choice', '["§16.024 (3-year)","§16.025 (5-year)","§16.026 (10-year)","§16.028 (25-year)"]'::jsonb, '§16.025 (5-year)', 'The 5-year track (§16.025) requires use/cultivation, payment of applicable taxes, and a duly registered deed (no quitclaim or forged deed). A single missed tax year is fatal.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000020', 'A claimant has only naked possession (no deed, no tax payments) and uses an unenclosed tract. Under Texas''s 10-year statute (§16.026), the area that can be claimed is generally capped at:', 'multiple_choice', '["40 acres","160 acres","640 acres","No cap"]'::jsonb, '160 acres', 'Section 16.026 caps the claim at 160 acres unless the larger area is enclosed or possession is under a recorded deed/memorandum fixing the boundaries.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000021', 'Under Texas''s statutory scheme, the stronger the claimant''s paper/title basis, the shorter the limitation period required to perfect.', 'true_false', '["True","False"]'::jsonb, 'True', 'The scheme rewards a stronger paper basis with a shorter period: title/color of title = 3 yr; registered deed + taxes + use = 5 yr; naked possession = 10 yr.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000022', 'Which Texas statute can support a 25-year adverse-possession claim based on a RECORDED instrument that is void on its face?', 'multiple_choice', '["§16.024","§16.025","§16.026","§16.028"]'::jsonb, '§16.028', 'Section 16.028 supports a 25-year claim under a recorded instrument purporting to convey, even if void on its face or in fact (excluding quitclaim/forged), extending to the whole described area. This is broader than common-law color of title.', 'hard', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000023', 'How does acquiescence differ fundamentally from adverse possession?', 'short_answer', '[]'::jsonb, 'Acquiescence rests on a mutual mistake about the true boundary with no intent to take and no hostility, whereas adverse possession requires hostile possession against the owner''s rights.', 'In acquiescence neither neighbor intends to take the other''s land; there is a mutual mistake about the line, good faith, and long recognition until title passes silently. Adverse possession, by contrast, requires hostility — possession in opposition to the true owner''s rights.', 'hard', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000024', 'Which feature most clearly distinguishes a license from an easement?', 'multiple_choice', '["A license is an interest in land that runs with the land.","A license is revocable personal permission that creates no interest in land.","A license must satisfy the Statute of Frauds.","A license can ripen into a prescriptive easement."]'::jsonb, 'A license is revocable personal permission that creates no interest in land.', 'A license is personal, generally revocable, and creates no interest in land (so it is not subject to the Statute of Frauds and does not run with the land). Permissive use under a license cannot ripen into a prescriptive easement.', 'easy', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000025', 'A neighbor''s new garage extends two feet over the surveyed property line. The remedies available in Texas for this encroachment include all of the following EXCEPT:', 'multiple_choice', '["Trespass to try title / quiet title","Injunction to remove the encroachment","Damages","An automatic statutory right for the good-faith encroacher to buy the strip"]'::jsonb, 'An automatic statutory right for the good-faith encroacher to buy the strip', 'Texas has no general ''innocent improver''/relative-hardship statute that automatically lets a good-faith encroacher buy the strip. Remedies are trespass-to-try-title/quiet title, injunction, or damages; title passes only through the statutory adverse-possession tracks.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000026', 'How does a restrictive covenant differ from an easement?', 'multiple_choice', '["A covenant grants another a right to physically use the burdened land; an easement restricts use.","A covenant restricts how the burdened owner may use his own land; an easement grants another a right to use it.","A covenant is always revocable at will; an easement never is.","There is no difference; the terms are interchangeable."]'::jsonb, 'A covenant restricts how the burdened owner may use his own land; an easement grants another a right to use it.', 'A covenant/restriction limits how the burdened owner may use his own land (e.g., residential-only). An easement grants someone else a right to use the burdened land. They are distinct, and covenants are not revocable at will like a license.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000027', 'When a public agency condemns land for a road, it acquires only an easement unless the fee is necessary for the purpose or a statute/deed conveys the fee.', 'true_false', '["True","False"]'::jsonb, 'True', 'When land is taken for public use, the condemnor acquires only an easement unless the fee is necessary for the purpose, or a statutory provision or deed conveys the fee. Thus underlying fee often remains in the original owner.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920330-0000-0000-0000-000000000028', 'Absent contrary language in the creating deed or map, reversion rights along a vacated straight (tangent) street extend from the street-side property termini to:', 'multiple_choice', '["The far side of the street","The centerline (thread) of the street, at right angles to it","A point 10 feet into the street","Nowhere — the entire street goes to the municipality"]'::jsonb, 'The centerline (thread) of the street, at right angles to it', 'Unless the creating deed or map says otherwise, reversion rights extend from the street termini of the property lines to the centerline (thread) of the street, in a direction at right angles to the centerline. On curves the lines are radial; at angle points they bisect the angle.', 'medium', 'd2920000-0000-0000-0000-000000000003', 'd2920310-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920360-0000-0000-0000-000000000001', 'A claimant began peaceable, adverse, and continuous possession of an unenclosed Texas tract in {{startYear}}, using it without any deed or tax payments. Proceeding under the 10-year statute (Tex. Civ. Prac. & Rem. Code §16.026), in what calendar year will the limitation period be satisfied so the claim can be perfected?', 'numeric_input', '[]'::jsonb, '0', 'Under §16.026, ten years of continuous adverse possession are required. Beginning in {{startYear}}, the period is satisfied in {{_answer}}. (If the tract were larger than 160 acres, the claim would be capped unless enclosed or held under a recorded deed fixing the boundaries.)', 'easy', 'd2920000-0000-0000-0000-000000000003', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920350-0000-0000-0000-000000000001', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920360-0000-0000-0000-000000000002', 'A utility easement runs as a uniform strip {{width}} ft wide along a property line for a length of {{length}} ft. What is the area of the easement, in square feet?', 'numeric_input', '[]'::jsonb, '0', 'A uniform strip easement is a rectangle, so its area is simply width × length = {{width}} × {{length:f2}} = {{_answer}} sq ft.', 'easy', 'd2920000-0000-0000-0000-000000000003', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920350-0000-0000-0000-000000000002', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920360-0000-0000-0000-000000000003', 'A pipeline easement is a uniform strip {{width}} ft wide and {{length}} ft long. Express the easement area in acres (1 acre = 43,560 sq ft).', 'numeric_input', '[]'::jsonb, '0', 'Compute the rectangular strip area ({{width}} × {{length:f2}} = {{areaSqFt:f2}} sq ft), then divide by 43,560 sq ft/acre to get {{_answer}} acres.', 'medium', 'd2920000-0000-0000-0000-000000000003', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920350-0000-0000-0000-000000000003', 0.005);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('d2920310-0000-0000-0000-000000000006', 'd2920000-0000-0000-0000-000000000003', 'Homework & Practice', '', ARRAY[]::text[], 6, 45, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, 'Module homework assignment(s) and practice problems.', ARRAY[]::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0006-0000-0000-000000000000', 'd2920310-0000-0000-0000-000000000006', 'text', '{"html":"<h2>Homework &amp; Practice</h2><p>Complete the homework below. You may submit a draft up to 48 hours before the deadline for instructor feedback. Use the randomized practice problems to prepare for the quiz.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0006-0000-0000-000000000001', 'd2920310-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 1 — Easements and Creation Methods (Applied Scenarios)</h3><p><em>Type: written</em></p><div>Answer each part in 3–6 sentences, citing the relevant Texas rule, statute, or case where appropriate.<br/><br/>**Part A — Classification.** A landowner grants the electric cooperative a recorded right to run a power line across the rear 15 ft of her lot. (1) Is this easement appurtenant or in gross? Explain. (2) Identify the servient tenement and whether there is a dominant tenement. (3) Is the easement affirmative or negative?<br/><br/>**Part B — Creation.** A rancher subdivides a large tract and sells a back parcel that is now completely landlocked, making no provision for access in the deed. The buyer wants a road across the rancher''s remaining front parcel. (1) Under *Hamrick v. Ward*, which doctrine must the buyer pursue, and why not implied easement by prior use? (2) List the three Texas elements the buyer must prove. (3) When would this easement terminate?<br/><br/>**Part C — Prescription (Texas).** For ten years, two adjoining owners have both driven over a shared gravel lane straddling their common line, each believing it was partly his. One now sues to establish a prescriptive easement over the other''s half. Apply *Tran v. Macha* and the Texas exclusivity rule to predict the outcome, and explain how Texas differs from the general common-law/Restatement view.<br/><br/>**Part D — Dedication.** A developer in a Texas county of 30,000 people claims a dirt road across private land became public because the public has used it for 25 years. Under Tex. Transp. Code Ch. 281 (1981), evaluate this claim and state what would have been required instead.</div>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920320-0006-0000-0000-000000000002', 'd2920310-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 2 — Adverse Possession Track Selection + Easement Area Computation</h3><p><em>Type: mixed</em></p><div>**Part A (written) — Match the statute.** For each fact pattern, state which Texas adverse-possession statute (§16.024, §16.025, §16.026, or §16.028) best fits and justify your choice in 2–3 sentences:<br/><br/>1. Claimant holds a regular chain of title with one defective link (color of title), and has possessed peaceably and adversely for 4 years.<br/>2. Claimant has used and cultivated the land for 6 years, paid every year''s property taxes, and holds under a duly registered (non-quitclaim) deed.<br/>3. Claimant has openly used an unenclosed 200-acre tract for 11 years with no deed and no tax payments.<br/>4. Claimant possesses under a recorded deed that turns out to be void on its face, and has done so for 26 years.<br/><br/>**Part B (written) — Distinguish.** In 4–5 sentences, explain the difference between *acquiescence* and *adverse possession*, and why a permissive ''neighborly accommodation'' can never support a prescriptive easement.<br/><br/>**Part C (computational) — Easement geometry.** A surveyor must describe a uniform access easement 24 ft wide running 412.50 ft from a county road to a back lot. (1) Compute the easement area in square feet. (2) Convert the area to acres (43,560 sq ft = 1 acre), rounded to three decimals. (3) Briefly list the four items the legal description of this easement should include to avoid ambiguity.</div>"}'::jsonb, 2);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0001-0000-0000-000000000000', 'd2920410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why deeds conflict</h3><p>A deed is a written attempt to describe a unique piece of ground using words, numbers, monuments, and references. Because the land is conveyed <strong>one parcel at a time over years and decades</strong>, by different scriveners using different instruments and different surveys, the calls in adjoining deeds frequently <em>overlap</em>, leave <em>gaps</em>, or contradict each other internally. The job of the retracing surveyor is not to redesign the boundary but to discover where it was <strong>originally created</strong> and to honor the rights that attached when each parcel was severed. To do that, courts and surveyors apply a settled set of priorities.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0001-0000-0000-000000000001', 'd2920410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The three elements courts use</h3><p>Courts have developed three basic elements for resolving conflicts in deeds, applied in this order of authority:</p><ul><li><strong>1. Unwritten / possession rights.</strong> An occupancy right that has ripened into a legal right (adverse possession, acquiescence, estoppel, agreement, acts of nature) can <em>alter or even overcome</em> a written conveyance.</li><li><strong>2. Senior rights.</strong> As between private parties, a senior right is superior to a junior right. The first parcel out of a common tract gets the full measure of its description; the later parcel takes the remainder.</li><li><strong>3. Written intentions of the parties.</strong> The expressed intent of the parties, found within the four corners of the instrument, is paramount in construing what the writing means.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0001-0000-0000-000000000002', 'd2920410-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"The surveyor''s lane: A surveyor does NOT determine the validity of occupancy or property rights, so a surveyor cannot apply element 1 (unwritten rights). A surveyor can and must apply elements 2 (senior rights) and 3 (written intent). When unwritten rights appear to exist, the surveyor discloses the facts and advises the client to seek legal advice — only a court can reform the boundary."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0001-0000-0000-000000000003', 'd2920410-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Following the footsteps of the original surveyor</h3><p>The cardinal rule of retracement is that the surveyor must <strong>follow in the footsteps of the original surveyor</strong> — locate the lines, corners, and monuments where they were <em>actually run and set</em> when the parcel was created. The retracing surveyor''s duty is to locate the boundaries <em>described in the operative muniments of title</em>, not to impose a mathematically perfect modern survey. As Hermansen puts it, the original surveyor''s marks and monuments are not by themselves determinative unless they are <em>given recognition in the operative description</em>. A more accurate modern measurement does not relocate an original corner that can still be identified on the ground.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0001-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"Case: Stafford v. King, 30 Tex. 257 (1867)","content":"<p>The foundational Texas authority on both the dignity of calls and the footsteps doctrine. The Texas Supreme Court held: <em>\"The actual identification of the survey, the footsteps of the surveyor upon the ground, should always be followed, by whatever rule they may be traced.\"</em> The court also stated the reliability order as natural objects, then artificial objects, then course and distance, while cautioning that the construction adopted must be the one most consistent with the intention apparent on the face of the patent.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0001-0000-0000-000000000005', 'd2920410-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Texas note: Because every Texas title traces to an original GLO survey/patent (Republic- or State-era), and the law required a survey before a patent could issue, Texas is an especially strong \"footsteps\" jurisdiction. Retracing the original Texas surveyor''s actual work is the dominant methodology, with dignity-of-calls and proportioning used as fallbacks."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0001-0000-0000-000000000006', 'd2920410-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Courts resolve deed conflicts with three elements, in order: unwritten/possession rights, senior rights, then written intent.","A surveyor may apply senior rights and written intent but may NOT decide unwritten/possession rights — that is for a court.","The footsteps of the original surveyor, where identifiable, control over later ''more accurate'' measurements.","Stafford v. King (1867) is the seminal Texas case for both the footsteps rule and the dignity of calls."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0002-0000-0000-000000000000', 'd2920410-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Two ways parcels come into being</h3><p>The method used to resolve a discrepancy depends entirely on <strong>how the parcels were created</strong>. There are two paradigms:</p><ul><li><strong>Sequential conveyances</strong> come into being because of a <em>time lapse</em> between conveyance instruments. A landowner carves off one tract, then later carves off another from the remaining land. These involve <strong>senior and junior rights</strong>.</li><li><strong>Simultaneous conveyances</strong> are several parcels created <em>at the same instant</em> from a common scheme — classically, the lots of a recorded subdivision plat. All lots have <strong>equal standing (no senior rights among them)</strong>.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0002-0000-0000-000000000001', 'd2920410-0000-0000-0000-000000000002', 'table', '{"headers":["Feature","Sequential (carve-outs over time)","Simultaneous (subdivision plat)"],"rows":[["Created","One after another, with a time lapse","All at one instant"],["Seniority","Senior/junior rights apply","No lot is senior to another"],["Overlaps","Belong to the senior parcel","Proportioned among affected lots"],["Gaps / shortage","Junior absorbs deficiency; gap belongs to seller (may be the State)","Proportioned among affected lots"],["Excess","Junior absorbs excess (senior made whole first)","Apportioned among affected lots"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0002-0000-0000-000000000002', 'd2920410-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Overlaps and gaps in sequential conveyances</h3><p>In a sequential scheme the rule is mechanical and not prorated: <strong>the senior is made whole first, and the junior takes whatever is left</strong>. Therefore an <em>overlap</em> (two deeds describing the same ground) belongs to the senior parcel. A <em>gap</em> or <em>hiatus</em> (ground described by neither deed) belongs to the original grantor/seller — and where the grantor was the sovereign, the gap may belong to the <strong>State</strong>. Excess or deficiency between controlling monuments is dumped entirely on the junior parcel; it is never split between senior and junior.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0002-0000-0000-000000000003', 'd2920410-0000-0000-0000-000000000002', 'callout', '{"type":"info","text":"Be careful: ''simultaneous'' lots can still hide a senior right. If an original tract that was senior to others later becomes a subdivision, the senior right from the original tract survives. A title search back to the original formation of the conveyance is necessary for a correct solution."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0002-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Apportionment in simultaneous conveyances</h3><p>Because no subdivision lot is senior, any excess or shortage found between <strong>controlling, undisputed monuments</strong> is distributed among the interior lots <em>in proportion to their record lengths</em>. No single lot absorbs the whole error. This is the PLSS/BLM idea of <strong>single proportionate measurement</strong> on a line, and <strong>double proportionate measurement</strong> for a corner controlled in two directions. Apportionment is a <em>last resort</em>: found monuments and original corners control first, and an isolable gross blunder is placed where it belongs rather than smeared across all lots.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0002-0000-0000-000000000005', 'd2920410-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Texas differs (PLSS): Single/double proportionate measurement are federal-PLSS/BLM constructs. Texas retained its own public lands and has no township-range grid, so Texas leans on original-survey footsteps and uses proportioning sparingly. There is no controlling Texas Supreme Court opinion adopting ''single/double proportionate measurement'' by name; in Texas it is established surveying practice introduced through expert testimony, not a marquee case."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0002-0000-0000-000000000006', 'd2920410-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Sequential = parcels carved out over time → senior/junior rights govern; junior absorbs excess/deficiency.","Simultaneous = subdivision lots created at one instant → no seniority; excess/deficiency apportioned proportionately.","Overlaps go to the senior parcel; gaps go to the seller (possibly the State).","A title search to the original conveyance is required because a ''simultaneous'' lot can carry a hidden senior right.","In Texas, proportioning is a genuine fallback behind original-survey footsteps."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0003-0000-0000-000000000000', 'd2920410-0000-0000-0000-000000000003', 'text', '{"html":"<h3>The senior-rights principle</h3><p>Where two parties are given title to the same parcel and possession is not a consideration, the party with <strong>senior rights has the right of possession</strong> under common law; the <strong>junior deed gets what is left over</strong>. The rationale is simple: once a grantor has sold land to the senior grantee, the grantor no longer owns it and <em>cannot resell the same rights</em> to a junior grantee. Seniority does not <em>expand</em> a grant beyond its own description — it only resolves overlaps and gaps in the senior''s favor.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0003-0000-0000-000000000001', 'd2920410-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Calls for an adjoiner and seniority</h3><p>An <strong>abutter (adjoiner) call</strong> — a call to the line of an adjoining tract — is normally considered senior, because the adjoining tract usually existed first. But a call for an adjoiner is <em>not always a correct criterion</em> for determining seniority. The adjoiner may itself be junior, or the call may be informational. Only a <strong>title search back to the original formation of the conveyance</strong> reliably establishes which parcel is senior.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0003-0000-0000-000000000002', 'd2920410-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"Worked logic: Grantor O owns a 400-ft frontage. In 2010 O deeds the west 250 ft to A (senior). In 2015 O deeds ''the remainder, being 150 ft, more or less'' to B (junior). A resurvey finds the true frontage is only 380 ft. A still gets the full 250 ft (senior). B is cut back to 380 - 250 = 130 ft. The 20-ft deficiency falls entirely on the junior, B."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0003-0000-0000-000000000003', 'd2920410-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Ambiguities in state patents</h3><p>A surprising reversal applies to grants from the State. <strong>Ambiguities in patents issued by a state are resolved in favor of the state</strong>, because patents are treated as quitclaim-type deeds that give no warranty. This is the <em>opposite</em> of the usual private-transaction rule, under which an ambiguous grant is construed against the grantor and in favor of the grantee.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0003-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Texas overlay: TBPELS rules (22 Tex. Admin. Code Ch. 138) affirmatively require Texas surveyors to honor junior/senior rights and the record chain during retracement. GLO patents create the senior title against which later subdivisions are junior. Confirm the exact section (≈ Subch. E) before citing it in writing."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0003-0000-0000-000000000005', 'd2920410-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Reservations and the grantor</h3><p>The general construction rule favors the grantee, but a <strong>reservation</strong> in a grant, and <em>every grant by a public officer or body to a private party</em>, is interpreted in favor of the grantor. Certain and definite statements prevail; erroneous or ambiguous terms may be rejected — but such rejections should be kept as few as possible so that the instrument is given effect.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0003-0000-0000-000000000006', 'd2920410-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["A grantor cannot resell rights already conveyed; the junior deed takes only the remainder.","Excess or deficiency falls entirely on the junior parcel, not prorated with the senior.","Abutter calls are normally senior but are not a conclusive test — search title to the original conveyance.","Ambiguities in state patents are resolved for the State (patents are quitclaim, no warranty) — the reverse of private deeds.","A reservation, and any public grant to a private party, is construed in favor of the grantor."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0004-0000-0000-000000000000', 'd2920410-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Why an order of importance exists</h3><p>When the calls inside one description conflict, the law ranks them by their relative <strong>reliability</strong> — their \"dignity.\" The logic is the <em>least-likely-mistake</em> principle: adopt the description element that is least likely to be affected by mistakes. A river is hard to misplace; a recorded distance is easy to mistype. The hierarchy is therefore a set of <strong>rebuttable presumptions of evidence</strong>, not iron rules.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0004-0000-0000-000000000001', 'd2920410-0000-0000-0000-000000000004', 'table', '{"headers":["Rank","Element","Examples / notes"],"rows":[["1","Unwritten rights & senior rights","Possession, agreement, prescription; senior rights in sequential conveyances (can overcome the writing)"],["2","Natural monuments","Rivers, creeks, lakes, mountains, rocks, marked trees of natural origin"],["3","Artificial monuments","Set iron pipes, concrete monuments, stakes, fence corners, centerlines of roads, rock piles"],["4","Calls for adjoiners","An already-established senior survey line called for and identified"],["5","Course (direction / bearing)","N 10° E"],["6","Distance","200.00 ft"],["7","Area / quantity","Acreage — weakest; ''of no description'' by itself"],["8","Coordinates","Computed/interpolated; inferior to the elements they were computed from"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0004-0000-0000-000000000002', 'd2920410-0000-0000-0000-000000000004', 'callout', '{"type":"info","text":"Brown / lecture ordering: 1) Rights of possession & unwritten transfer; 2) Senior rights (overlaps); 3) Written intentions — call for survey, natural monuments, then artificial monuments; 4) Distance or direction; 5) Area; 6) Coordinates and calculated/interpolated evidence. Note that the ''adjoiner'' tier is a modern Texas-treatise refinement inserted between artificial monuments and course."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0004-0000-0000-000000000003', 'd2920410-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Natural vs. artificial monuments</h3><p>Per <em>Stafford v. King</em>: <strong>\"Natural objects are mountains, lakes, rivers, creeks, rocks, and the like. Artificial objects are marked lines, trees, stakes, etc.\"</strong> Natural monuments outrank artificial ones because they are larger, more permanent, and less easily moved or fabricated. For any monument to be controlling it must be <strong>called for, identifiable, and undisturbed</strong>. A monument set <em>after</em> the deed was written (an uncalled-for monument) does not control the boundary, though it may be evidence of unwritten rights.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0004-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Intent overrides the hierarchy</h3><p>The hierarchy always yields to the <strong>intent of the parties</strong> and to the <strong>footsteps of the original surveyor</strong>. A call that would defeat the parties'' intentions is <em>rejected regardless of its comparative dignity</em>. A call to a monument, though normally controlling, may be rejected where all other terms in the deed show the monument call was inserted in error. Each term must be read in the light of all the other terms. Stafford''s own framing is conditional: adopt the construction \"most consistent with the intention apparent upon the face of the patent.\"</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0004-0000-0000-000000000005', 'd2920410-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas differs / emphasizes: Texas fully adopts the natural → artificial → adjoiner → course → distance → quantity → coordinates ordering, but Stafford v. King imposes two caveats that come first: (1) the intent of the parties is paramount, and (2) the footsteps of the original surveyor, where ascertainable on the ground, override even the field-note calls. The location of a survey line is ultimately a question of fact for the factfinder."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0004-0000-0000-000000000006', 'd2920410-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Order of dignity: senior/unwritten rights > natural monuments > artificial monuments > adjoiners > course > distance > area > coordinates.","The hierarchy reflects the least-likely-mistake principle and is rebuttable, not absolute.","A monument must be called for, identifiable, and undisturbed to control.","Intent and the original surveyor''s footsteps override the mechanical ranking — a call defeating intent is rejected regardless of its dignity.","Area/quantity and coordinates are the weakest elements."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0005-0000-0000-000000000000', 'd2920410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Construe the whole instrument</h3><p>When a conveyance is reduced to writing it is assumed to contain all the terms intended and is construed, if possible, to <strong>give effect to all the terms</strong>. The intentions of the parties as expressed by the writing are paramount. Several controlling maxims of jurisprudence recur in land disputes:</p><ul><li>Between rights otherwise equal, the <strong>earliest is preferred</strong> (the seniority principle).</li><li><strong>Particular expressions qualify general ones</strong> — a specific metes-and-bounds description controls over a vague general one.</li><li>An interpretation that <strong>gives effect</strong> is preferred to one that makes the deed void.</li><li>One who grants a thing is presumed to grant whatever is essential to its use.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0005-0000-0000-000000000001', 'd2920410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Controlling vs. informative terms</h3><p>Within a single call, some words <strong>control</strong> and others merely <strong>inform</strong>. In the call <em>\"North 200.00'' to a 2\" iron pipe\"</em>, the iron pipe controls (a found, called-for, undisturbed monument); the bearing and distance inform where to look for it. But if the pipe is lost, the bearing and distance <em>become controlling</em>. The word <strong>\"to\"</strong> is a word of exclusion: the call preceding \"to\" is informative and the call after \"to\" is controlling. General terms such as \"near\" are informative and yield to the specific call, while unrestricted general terms like \"northerly\" or \"about 20 chains\" become exact if nothing restricts them.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0005-0000-0000-000000000002', 'd2920410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Parol evidence: a narrow door</h3><p>Boundaries must be established in accordance with the <strong>written terms of the deed</strong>. Parol (oral) evidence may NOT be used to add, subtract, or vary the terms of a deed. It may be used only to:</p><ul><li>establish the location of an ambiguous Point of Beginning;</li><li>show where the line was actually run and marked; and</li><li>show fraud.</li></ul><p>In short, parol evidence explains an ambiguity in the writing; it does not rewrite the writing.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0005-0000-0000-000000000003', 'd2920410-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"The plat or map: When a description calls for a plat and the parties acted with reference to it, the plat becomes part of the description as if recited in the deed, and its monuments have equal dignity with those in the writing. But if there is a clear error in the call for the map, or the parties did not actually act with reference to it, the map is treated as surplusage (unnecessary matter)."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0005-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Locating errors</h3><p>If a description contains an error and the error can be <strong>isolated</strong>, the error is placed where it occurs — not smeared across the whole description. Before giving a distance or bearing control, the surveyor must investigate and eliminate the possibility of a <em>mistake</em>; the surveyor has an obligation to examine all reasonable avenues to rectify a discrepancy. When two factors conflict and nothing indicates which is correct, the first stated is preferred; when a number appears as both figures and words, the words control unless the contrary is proved.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0005-0000-0000-000000000005', 'd2920410-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"Basis of bearings: Unless stated otherwise, every bearing in a present-day metes-and-bounds description is presumed to refer to the same basis at the same point, and each line''s bearing is constant throughout its length. If one original line can be identified and was described by a measured magnetic bearing, the difference between the original record bearing and the present measured bearing is the correction to apply to the other record bearings of the same deed."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0005-0000-0000-000000000006', 'd2920410-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["Construe the whole instrument to give effect to every term; particular descriptions control general ones; the earliest of equal rights is preferred.","''To'' is a word of exclusion — the call after ''to'' controls; a called monument controls, and its bearing/distance become controlling only if the monument is lost.","Parol evidence may explain an ambiguous PoB, show where a line was run, or show fraud — but may not add, subtract, or vary deed terms.","A plat the parties acted upon becomes part of the description; an erroneous or unrelied-upon plat is surplusage.","An isolable error is placed where it occurs; words control over conflicting figures; the first-stated factor is preferred when nothing else decides."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0006-0000-0000-000000000000', 'd2920410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>When occupation differs from the record</h3><p>Reality often clouds retracement: fences, walls, and cultivation lines (lines of <strong>occupation</strong>) frequently do not coincide with the record line built from the operative descriptions. Doctrines such as <em>adverse possession, estoppel, practical location, acquiescence, and unwritten agreement</em> can cause ownership to follow the occupation line rather than the record line. Lines of occupation are often held by courts to be the boundary where circumstances dictate.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0006-0000-0000-000000000001', 'd2920410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Fact versus law — the surveyor''s limit</h3><p>Courts say: <strong>\"where the boundaries are is a question of fact; what the boundaries are is a question of law.\"</strong> A surveyor is a fact finder. The surveyor may sift the facts and opine that the record boundary is in one place and the occupation line in another — but the surveyor <em>cannot decide</em> that the occupation line has become the ownership boundary by an equitable doctrine. That is a legal conclusion only a court can make. Even an attorney cannot, on their own motion, declare the occupation line the boundary; the procedure of litigation must be followed.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0006-0000-0000-000000000002', 'd2920410-0000-0000-0000-000000000006', 'callout', '{"type":"warning","text":"Liability: A surveyor who quietly monuments the occupation line as ''the boundary'' may be liable for failing to disclose the conflict. Where occupation differs from record, the marketability of title is in doubt. The surveyor''s duty is to DISCLOSE the difference — show both the record line and the line of occupation on the plat — and advise the client to seek legal advice."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0006-0000-0000-000000000003', 'd2920410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>The reasonableness standard</h3><p>The significance of a difference between fence and record depends on scale and context. A fence one foot off the record line around a 500-acre farm probably does not make title unmarketable; the same one-foot difference around a quarter-acre residential lot likely does. The surveyor weighs the extent, nature, and history of the occupation — but reports it as evidence, leaving the ownership determination to the court.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0006-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Unwritten agreement</h3><p>An unwritten boundary agreement requires that (1) the adjoiners did not know where the true boundary was, (2) they agreed on a location and monumented it, and (3) they intended the marked line to be the true line. A surveyor has <strong>no authority to reform a deed</strong> without adjoiner approval; only a court can. Where the surveyor finds a provable unwritten agreement, the surveyor may only call attention to it, advise legal counsel, or attempt to have the adjoiners sign a written agreement — which converts the occupation line into a record line.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0006-0000-0000-000000000005', 'd2920410-0000-0000-0000-000000000006', 'callout', '{"type":"info","text":"Texas connection: Texas applies the strict, statutory adverse-possession tracks (Civ. Prac. & Rem. Code Ch. 16) and the ''visible, open, exclusive, and unequivocal'' possession standard (Madison v. Gordon). Acquiescence/agreed-boundary doctrines are applied narrowly, so the surveyor''s measured record location is typically the starting point, with possession disclosed as evidence."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0006-0000-0000-000000000006', 'd2920410-0000-0000-0000-000000000006', 'key_takeaways', '{"title":"Key Takeaways","items":["Lines of occupation can ripen into the ownership boundary through adverse possession, acquiescence, estoppel, or agreement.","Where the boundary is = question of fact (surveyor); what the boundary is = question of law (court).","A surveyor must disclose record-vs-occupation conflicts, not silently adopt the occupation line; otherwise liability and unmarketable title result.","Significance of a fence/record difference is judged by a reasonableness standard tied to scale and context.","A surveyor cannot reform a deed; a written boundary agreement among adjoiners turns occupation lines into record lines."]}'::jsonb, 6);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000001', 'Footsteps doctrine', 'The principle that a retracing surveyor must locate boundaries where the original surveyor actually ran the lines and set the corners; identifiable original monuments control over later measurements.', '"Follow in the footsteps of the original surveyor" — Stafford v. King.', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000002', 'Senior right', 'As between private parties, the earlier-created (senior) conveyance is superior to a later (junior) one; the senior takes the full measure of its description and the junior takes the remainder.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000003', 'Operative muniment of title', 'A document emanating from a grantor or authority that had both the title and the power to fix a boundary, and therefore operates to create an authoritative boundary (as opposed to a merely recorded but powerless document).', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000004', 'Three elements for resolving deed conflicts', '(1) Unwritten/possession rights that have ripened into legal title, (2) senior rights, (3) written intentions of the parties — applied in that order of authority.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000005', 'Sequential conveyance', 'Parcels created one after another with a time lapse between instruments; resolved by senior/junior rights, with the junior absorbing any excess or deficiency.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000006', 'Simultaneous conveyance', 'Several parcels created at the same instant from a common scheme (e.g., a recorded subdivision plat); all lots have equal standing and excess/deficiency is apportioned.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000007', 'Gap / hiatus', 'A strip of ground described by neither of two adjoining sequential deeds; it belongs to the original grantor/seller, which may be the State.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000008', 'Overlap', 'Ground described by two conflicting deeds. In a sequential scheme the overlap belongs to the senior parcel.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000009', 'Single proportionate measurement', 'Restoring a lost corner on a single line between two found monuments so that the corrected interval bears the same ratio to the corrected whole as the record interval bears to the record whole.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000010', 'Double proportionate measurement', 'Restoring a lost corner controlled in two directions from four surrounding found monuments, proportioning independently in each direction.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000011', 'Junior deed remainder rule', 'The junior grantee receives only what the grantor still owned after the senior conveyance — ''what is left over'' — absorbing any overlap loss or deficiency.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000012', 'Abutter (adjoiner) call', 'A call in a deed to the boundary of an adjoining tract; normally treated as senior, but not a conclusive indicator of seniority without a title search.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000013', 'Patent ambiguity rule', 'Ambiguities in a state-issued patent are resolved in favor of the State, because patents are quitclaim deeds giving no warranty — opposite of the private-deed rule.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000014', 'Construction against the grantor', 'In private transactions an ambiguous grant is read in favor of the grantee; but a reservation, and any public grant to a private party, is read in favor of the grantor.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000015', 'Dignity of calls', 'The ranked reliability of conflicting deed elements: natural monuments > artificial monuments > adjoiner calls > course > distance > area > coordinates, all subordinate to intent and footsteps.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000016', 'Natural monument', 'A naturally occurring boundary object such as a river, creek, lake, mountain, or rock; highest dignity among physical calls.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000017', 'Artificial monument', 'A human-made boundary marker such as an iron pipe, concrete monument, stake, fence corner, or road centerline; ranks below natural monuments.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000018', 'Least-likely-mistake rule', 'When deed elements conflict, adopt the element least likely to be affected by mistakes; the rationale behind the dignity hierarchy.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000019', 'Uncalled-for monument', 'A monument set after the deed was written; it does not control the boundary but may evidence possible unwritten rights.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000020', 'Controlling vs. informative call', 'A controlling call prevails in conflict; an informative call merely helps locate the controlling element (e.g., ''North 200.00 ft to a 2-inch iron pipe'' — the pipe controls, the bearing/distance inform).', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000021', 'Parol evidence rule (boundaries)', 'Oral evidence may not add to, subtract from, or vary the written terms of a deed; it may only locate an ambiguous PoB, show where a line was run/marked, or show fraud.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000022', 'Word ''to'' (exclusion)', 'In a deed call, ''to'' is a word of exclusion: the call preceding ''to'' is informative and the call after ''to'' is controlling.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000023', 'Surplusage', 'Unnecessary matter in a description, such as a called plat the parties did not actually rely on or that contains a clear error; it is disregarded.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000024', 'Particular controls general', 'A maxim of construction: a specific (e.g., metes-and-bounds) expression qualifies and controls a general or vague one when they conflict.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000025', 'Isolated error placement', 'When an error in a description can be isolated, it is placed where it occurs rather than distributed across the whole description.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000026', 'Magnetic bearing correction', 'If an original line is identified, the difference between its original record (magnetic) bearing and the present measured bearing is the correction applied to the other record bearings of the same deed.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000027', 'Line of occupation', 'The physical line of use (fence, wall, cultivation edge); it may or may not coincide with the record boundary and can, through unwritten doctrines, become the ownership line.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000028', 'Fact vs. law (boundaries)', '''Where the boundaries are'' is a question of fact for the surveyor; ''what the boundaries are'' is a question of law for the court.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000029', 'Marketable title', 'Title reasonably free from doubt and from claims that could form the basis of litigation; a fence/record conflict can render title unmarketable depending on scale.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920440-0000-0000-0000-000000000030', 'Unwritten boundary agreement', 'A boundary fixed when adjoiners, uncertain of the true line, agree on and monument a location intending it as the true line; a surveyor can disclose it but not reform the deed.', NULL, 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000001', 'A surveyor retracing a sequential conveyance finds the original iron pin called for in the deed, but it sits 2.3 ft from the position computed by an exact modern coordinate solution. Which position controls the corner?', 'multiple_choice', '["The found original iron pin, because the footsteps of the original surveyor control","The modern computed coordinate, because it is more accurate","The midpoint between the two positions","Whichever position gives the senior parcel its full record area"]'::jsonb, 'The found original iron pin, because the footsteps of the original surveyor control', 'Under the footsteps doctrine (Stafford v. King), an identifiable original monument controls over later, more precise measurements. Coordinates and modern computations are subordinate to the elements they were computed from. Splitting the difference and chasing record area both ignore the controlling found monument.', 'easy', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000002', 'Which of the three elements courts use to resolve deed conflicts may a surveyor NOT apply on the surveyor''s own authority?', 'multiple_choice', '["Unwritten/possession rights that have ripened into legal title","Senior rights","Written intentions of the parties","The dignity of calls"]'::jsonb, 'Unwritten/possession rights that have ripened into legal title', 'Validity of occupancy or property (unwritten) rights is a question of law for a court. A surveyor may apply senior rights and written intent (and the dignity of calls, which expresses intent), but may only disclose possible unwritten rights, not adjudicate them.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000003', 'True or False: The footsteps of the original surveyor, where they can be identified on the ground, override inconsistent field-note calls in the same description.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. Stafford v. King and Texas retracement doctrine hold that the original surveyor''s actual lines and corners, where ascertainable, control even over inconsistent field-note calls. The dignity hierarchy is invoked only when the footsteps cannot be retraced.', 'easy', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000004', 'Which scenario is the paradigm SIMULTANEOUS conveyance?', 'multiple_choice', '["Lots created at one instant by a recorded subdivision plat","A landowner deeds off the west 5 acres in 2008, then the east 5 acres in 2015","A Republic-era headright patent carved from the public domain","An owner sells a metes-and-bounds tract, reserving the remainder"]'::jsonb, 'Lots created at one instant by a recorded subdivision plat', 'Subdivision lots are created simultaneously and have equal dignity (no seniority); excess/deficiency is apportioned. The other options describe sequential carve-outs created over time, which are governed by senior/junior rights.', 'easy', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000005', 'In a sequential conveyance, a measured shortage is found between two controlling monuments. How is the deficiency allocated between the senior and junior parcels?', 'multiple_choice', '["The junior parcel absorbs the entire deficiency after the senior is made whole","The deficiency is prorated between senior and junior by record length","The senior parcel absorbs the deficiency because it is closer to the monument","The deficiency is split equally"]'::jsonb, 'The junior parcel absorbs the entire deficiency after the senior is made whole', 'In sequential conveyances senior rights govern: the senior takes its full description and the junior takes only the remainder, absorbing the whole excess or deficiency. Proration is reserved for simultaneous (equal-dignity) conveyances.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000006', 'Two adjoining sequential deeds, when plotted, leave a 4-ft-wide strip of ground described by neither deed. Who owns that gap?', 'multiple_choice', '["The original grantor/seller, which may be the State","The senior parcel","The junior parcel","It is split between the two adjoining owners"]'::jsonb, 'The original grantor/seller, which may be the State', 'A gap (hiatus) is land that was never conveyed, so it remains with the original grantor; where the grantor was the sovereign, it may belong to the State. Overlaps (not gaps) go to the senior parcel.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000007', 'True or False: Because subdivision lots are ''simultaneous,'' a surveyor can ignore the possibility of any senior right when retracing them.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. An original tract that was senior to others may later be subdivided, and that senior right survives. A title search back to the original formation of the conveyance is necessary to confirm no hidden senior right exists.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000008', 'Ambiguities in a patent issued by the State are resolved in favor of whom, and why?', 'multiple_choice', '["The State, because a patent is a quitclaim-type deed giving no warranty","The patentee/grantee, because ambiguities are construed against the grantor","Whichever party recorded first","The adjoining landowner with the senior call"]'::jsonb, 'The State, because a patent is a quitclaim-type deed giving no warranty', 'State patents are treated as quitclaim deeds with no warranty, so ambiguities are resolved in favor of the State. This is the opposite of the ordinary private-deed rule, where ambiguities are construed against the grantor and for the grantee.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000009', 'A deed call to ''the line of the adjoining Smith tract'' is generally treated as senior. When is that NOT a reliable indicator of seniority?', 'multiple_choice', '["When the adjoining tract is itself junior, which only a title search to the original conveyance reveals","Never — an adjoiner call is always senior","Only when the adjoiner call also gives a bearing and distance","Only in simultaneous conveyances"]'::jsonb, 'When the adjoining tract is itself junior, which only a title search to the original conveyance reveals', 'An abutter call is normally senior but is not always a correct criterion: the adjoiner may itself be junior. A title search back to the original formation of the conveyance is required to determine seniority reliably.', 'hard', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000010', 'Rank these conflicting calls from HIGHEST to LOWEST dignity: distance, natural monument, area, artificial monument.', 'multiple_choice', '["Natural monument > artificial monument > distance > area","Natural monument > distance > artificial monument > area","Artificial monument > natural monument > area > distance","Area > distance > artificial monument > natural monument"]'::jsonb, 'Natural monument > artificial monument > distance > area', 'The dignity order is natural monuments > artificial monuments > (adjoiner) > course > distance > area/quantity > coordinates. Natural objects are most reliable; area/quantity is among the weakest (''of no description'' by itself).', 'easy', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000011', 'A deed call reads ''North 200.00 feet to a 2-inch iron pipe.'' The pipe is found, called for, and undisturbed at 203.4 feet. Where is the corner?', 'multiple_choice', '["At the found iron pipe (203.4 ft), because a called, identifiable, undisturbed monument controls over distance","At 200.00 ft, because the recorded distance is exact","At the average, 201.7 ft","Wherever the area closes correctly"]'::jsonb, 'At the found iron pipe (203.4 ft), because a called, identifiable, undisturbed monument controls over distance', 'An artificial monument that is called for, identifiable, and undisturbed controls over a conflicting distance. The bearing and distance are informative — they tell you where to look for the pipe. They would become controlling only if the pipe were lost.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000012', 'True or False: A call to a monument, although normally controlling, may be rejected when all the other terms of the deed show the monument call was inserted in error.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. The dignity hierarchy is a set of rebuttable presumptions subordinate to intent. A call that would defeat the parties'' intentions is rejected regardless of its comparative dignity, including a monument call shown by the rest of the deed to be erroneous.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000013', 'Why do coordinates rank at the very bottom of the dignity of calls?', 'multiple_choice', '["Coordinates are computed from measurements of distance and angle and are therefore inferior to the elements they were computed from","Coordinates are always wrong","Coordinates are never recorded in deeds","Coordinates are senior to monuments"]'::jsonb, 'Coordinates are computed from measurements of distance and angle and are therefore inferior to the elements they were computed from', 'Coordinates are traditionally informational and are derived from underlying measurements, so they cannot be more reliable than those measurements. A precisely computed monument may be replaced by its coordinates, but the coordinate does not outrank a found monument.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000014', 'Under the parol evidence rule as applied to boundaries, parol evidence may be used to:', 'multiple_choice', '["Establish the location of an ambiguous Point of Beginning, show where a line was run, or show fraud","Add a new course to the deed that the parties forgot","Increase the acreage to match the grantor''s intent","Change a recorded bearing the surveyor believes is wrong"]'::jsonb, 'Establish the location of an ambiguous Point of Beginning, show where a line was run, or show fraud', 'Parol evidence may explain an ambiguity — locate an ambiguous PoB, show where the line was actually run and marked, or show fraud. It may NOT add, subtract, or vary the written terms of the deed.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000015', 'In the call ''...thence to the centerline of Maple Street,'' how does the word ''to'' affect the calls?', 'multiple_choice', '["''To'' is a word of exclusion: the call after ''to'' (the centerline) controls and the call before it informs","''To'' is a word of inclusion that adds both calls together","''To'' means the distance controls over the monument","''To'' has no legal effect"]'::jsonb, '''To'' is a word of exclusion: the call after ''to'' (the centerline) controls and the call before it informs', '''To'' is a word of exclusion. The call preceding ''to'' is informative; the call following ''to'' (here, the road centerline, an artificial monument) is controlling.', 'hard', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000016', 'A deed contains both ''12 acres'' in figures and ''twelve and one-half acres'' in words, and the conflict cannot otherwise be resolved. Which controls?', 'multiple_choice', '["The words (''twelve and one-half acres''), unless the contrary is proved","The figures (''12 acres'') always","Neither — area never controls anything","The smaller of the two values"]'::jsonb, 'The words (''twelve and one-half acres''), unless the contrary is proved', 'When a number appears as both figures and spelled-out words, the words control unless the contrary can be proved. (Note this is a tie-breaker for the quantity term itself; area/quantity remains a low-dignity element overall.)', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000017', 'A surveyor is convinced a long-standing fence has become the true boundary by adverse possession. What is the proper action?', 'multiple_choice', '["Disclose both the record line and the fence on the plat and advise the client to seek legal advice","Monument the fence as the boundary and omit the record line","Reform the deed to match the fence","Ignore the fence entirely"]'::jsonb, 'Disclose both the record line and the fence on the plat and advise the client to seek legal advice', 'Whether occupation has become ownership is a question of law for a court. The surveyor''s duty is to disclose the conflict (show both lines) and advise legal counsel — not to adjudicate the doctrine or silently adopt the fence, which risks liability and clouds marketability.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000018', 'Complete the maxim courts use to define the surveyor''s role: ''Where the boundaries ___ is a question of fact; what the boundaries ___ is a question of law.''', 'multiple_choice', '["are; are","were; will be","start; end","close; open"]'::jsonb, 'are; are', '''Where the boundaries are is a question of fact; what the boundaries are is a question of law.'' The surveyor (fact finder) locates the boundary; the court decides the legal effect of unwritten doctrines.', 'easy', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000019', 'True or False: A one-foot difference between a fence and the record line has the same effect on marketability of title regardless of the size of the parcel.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. A reasonableness standard applies. A one-foot fence offset around a 500-acre farm likely does not make title unmarketable, while the same offset around a quarter-acre residential lot likely does.', 'easy', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000006', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000020', 'Grantor O owns a tract with 400 ft of record frontage. O deeds the west 240 ft to A (2009), then deeds ''the remainder'' to B (2014). A resurvey between the controlling end monuments finds only 392 ft of frontage. How much frontage does B (junior) receive?', 'numeric_input', '[]'::jsonb, '152', 'Senior rights: A keeps the full 240 ft. B takes the remainder = 392 - 240 = 152 ft. The 8-ft deficiency falls entirely on the junior, B; it is not prorated.', 'medium', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920430-0000-0000-0000-000000000021', 'A deed call reads ''N 00° 00'' E, 150.00 ft to a found stone monument.'' The monument is found, called for, and undisturbed at a measured distance of 154.20 ft along that bearing. Treating the monument as controlling, what corrected distance (ft) should be used to reach the corner?', 'numeric_input', '[]'::jsonb, '154.20', 'The called, identifiable, undisturbed monument controls over the record distance, so the corrected distance is the measured distance to the monument, 154.20 ft. The record 150.00 ft is merely informative.', 'easy', 'd2920000-0000-0000-0000-000000000004', 'd2920410-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920460-0000-0000-0000-000000000001', 'Grantor O owns a tract with {{rec:f2}} ft of record frontage along a road. O first deeds the senior parcel, a width of {{senior:f2}} ft, to A. O then deeds ''the remainder'' to junior grantee B. A resurvey between the two controlling end monuments finds the true frontage is {{meas:f2}} ft. Applying senior rights (no proration), what frontage (ft) does junior parcel B receive?', 'numeric_input', '[]'::jsonb, '0', 'Senior rights govern a sequential conveyance: A keeps its full {{senior:f2}} ft, and the junior B absorbs the entire excess/deficiency, taking the remainder = {{meas:f2}} − {{senior:f2}} = {{_answer}} ft.', 'medium', 'd2920000-0000-0000-0000-000000000004', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920450-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920460-0000-0000-0000-000000000002', 'A line is described as bearing {{brg:dms}} for a record distance of {{rec:f2}} ft ''to a found {{mon}} monument.'' The monument is called for, identifiable, and undisturbed; it is found along the same bearing at a measured horizontal distance of {{meas:f2}} ft. Treating the monument as the controlling call, what corrected distance (ft) reaches the corner, and by how much does it exceed the record? Report the corrected distance.', 'numeric_input', '[]'::jsonb, '0', 'An artificial monument that is called for, identifiable, and undisturbed controls over a conflicting distance. The corrected distance is the measured distance to the monument, {{meas:f2}} ft; the record {{rec:f2}} ft becomes controlling only if the monument is lost.', 'medium', 'd2920000-0000-0000-0000-000000000004', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920450-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920460-0000-0000-0000-000000000003', 'A senior deed describes a parcel whose east line is at station {{e1:f2}} ft east of a common origin. The adjoining junior deed describes its west line at station {{w2:f2}} ft east of the same origin. Compute the width (ft) of the gap or overlap between the two deed lines (report a positive number for the magnitude).', 'numeric_input', '[]'::jsonb, '0', 'If the junior west line lies east of the senior east line, the strip between them is a gap (belongs to the seller/State); if it lies west, the deeds overlap (the overlap belongs to the senior). The width is the absolute difference of the two stations = {{_answer}} ft.', 'medium', 'd2920000-0000-0000-0000-000000000004', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920450-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920460-0000-0000-0000-000000000004', 'From a found controlling corner at coordinates (N {{n0:f2}}, E {{e0:f2}}), a deed line runs {{brg:dms}} (a bearing of {{az:f2}} degrees from north, in the NE quadrant) for the corrected distance of {{dist:f2}} ft to the next corner. Compute the EASTING (E) of the next corner.', 'numeric_input', '[]'::jsonb, '0', 'For a NE-quadrant bearing, the departure (change in easting) is dist × sin(bearing angle) = {{dist:f2}} × sin({{az:f2}}°) = {{dep:f2}} ft. Adding to the starting easting {{e0:f2}} gives E = {{_answer}} ft. (The northing would use dist × cos of the same angle.)', 'hard', 'd2920000-0000-0000-0000-000000000004', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920450-0000-0000-0000-000000000004', 0.05);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('d2920410-0000-0000-0000-000000000007', 'd2920000-0000-0000-0000-000000000004', 'Homework & Practice', '', ARRAY[]::text[], 7, 45, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, 'Module homework assignment(s) and practice problems.', ARRAY[]::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0007-0000-0000-000000000000', 'd2920410-0000-0000-0000-000000000007', 'text', '{"html":"<h2>Homework &amp; Practice</h2><p>Complete the homework below. You may submit a draft up to 48 hours before the deadline for instructor feedback. Use the randomized practice problems to prepare for the quiz.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0007-0000-0000-000000000001', 'd2920410-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Homework 1 — Sequential Conveyance Retracement and Conflict Resolution</h3><p><em>Type: computational</em></p><div>**Scenario.** In 1962 landowner O owned a single tract fronting 600.00 ft (record) along the north line of County Road 7, the tract running 300.00 ft deep. O made the following conveyances in order:<br/><br/>- **1962 — Parcel A (senior):** the west 200.00 ft of frontage, full depth, ''thence N 00° 00'' E 300.00 ft to a 1-inch iron pipe set this survey.''<br/>- **1968 — Parcel B:** the next 200.00 ft of frontage east of A, full depth.<br/>- **1975 — Parcel C (junior):** ''the remainder of the O tract lying east of Parcel B,'' full depth.<br/><br/>**Field data (your resurvey).** Between the two original controlling road-corner monuments (found, undisturbed), the measured frontage is **592.40 ft**. The 1-inch iron pipe called for at the NW interior corner is found, identifiable, and undisturbed, but it lies **N 00° 00'' E 304.10 ft** from the road corner (record was 300.00 ft).<br/><br/>**Tasks.**<br/>1. Identify whether these are sequential or simultaneous conveyances and state which rule (senior rights vs. apportionment) governs the frontage discrepancy.<br/>2. Compute the frontage each of A, B, and C receives. Show that the deficiency falls on the junior parcel only.<br/>3. For Parcel A''s west line, state whether the corner is held at the found iron pipe (304.10 ft) or at the record 300.00 ft, and justify your answer using the dignity of calls and the footsteps doctrine.<br/>4. Suppose a later survey reveals the 1975 deed to C and a 1977 deed to a neighbor both describe a 3.0-ft-wide strip on C''s east side (an overlap). State who owns the overlap and the principle that decides it.<br/>5. Cite *Stafford v. King* for one proposition you relied on, and note one Texas-specific consideration (GLO patent seniority or TBPELS retracement duty).</div>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920420-0007-0000-0000-000000000002', 'd2920410-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Homework 2 — Dignity of Calls and the Surveyor''s Disclosure Duty (written + applied)</h3><p><em>Type: mixed</em></p><div>**Part A — Dignity analysis.** For each call conflict below, state which element controls and why, and identify which call is merely informative:<br/><br/>1. ''N 45° 00'' E 100.00 ft to the centerline of Mill Creek'' — the creek centerline is found 6 ft short of the platted distance.<br/>2. ''thence along the east line of the Jones Survey'' vs. a recited bearing of ''S 02° W'' that diverges 1° from the Jones line.<br/>3. ''containing 5.00 acres, more or less'' vs. monumented corners that compute to 4.82 acres.<br/>4. A coordinate listed for a corner vs. a found, called-for concrete monument 0.4 ft away.<br/><br/>**Part B — Parol evidence.** A deed''s Point of Beginning is described only as ''the old oak at the corner of the Smith place,'' and the oak is gone. List what parol evidence the surveyor MAY use to re-establish the PoB and what parol evidence may NOT be used.<br/><br/>**Part C — Possession/responsibility memo.** You retrace a quarter-acre residential lot and find a board fence that encroaches 1.6 ft onto the record line for its full length; the fence has stood for 22 years. Write a short (150–250 word) professional memo to your client explaining: (i) why you will not simply monument the fence as the boundary, (ii) the fact-vs-law distinction, (iii) the marketability concern, and (iv) your recommended next step. Reference the reasonableness standard and the surveyor''s disclosure duty.</div>"}'::jsonb, 2);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0001-0000-0000-000000000000', 'd2920510-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Created in the same legal instant</h3><p>A <strong>simultaneously created boundary</strong> results when several parcels of land are created in the <em>same legal instant</em>, by the same person, persons, or agency, and by the same instrument. The classic example is a <strong>recorded subdivision plat</strong>: when the map is approved and recorded and lots are sold by reference to it, every lot springs into existence at once. Because they are born together, <strong>all parcels have equal standing</strong> — no lot can claim prior rights or seniority over any other. This is the fundamental difference from the sequential conveyances of Module 4, where parcels are carved off one at a time and senior/junior rights govern.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0001-0000-0000-000000000001', 'd2920510-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The three requirements</h3><p>For a simultaneous-conveyance situation to exist, the threshold requirement is that <strong>two or more parcels are created from a single parent parcel</strong> at one time. Brown states the recorded-plat case as three steps:</p><ul><li><strong>1.</strong> All divisions of the land are indicated and shown on a plat or map.</li><li><strong>2.</strong> The map is filed and approved.</li><li><strong>3.</strong> Parcels are sold with reference to the <strong>approved</strong> plat or map.</li></ul><p>When those conditions are met, the order in which the individual lots later <em>sell</em> is immaterial to seniority among them. A lot sold first is not senior to a lot sold last.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0001-0000-0000-000000000002', 'd2920510-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Equal dignity, but unwritten rights still prevail. Excesses and deficiencies in a subdivision are proportioned according to the frontage of each individual lot, with no regard for the time of transfer of one lot over another. But an unwritten right (adverse possession, acquiescence, estoppel) that has ripened into a legal right can still override the record — the surveyor discloses it and leaves the legal determination to a court."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0001-0000-0000-000000000003', 'd2920510-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Other ''treat as a subdivision'' transactions</h3><p>The recorded plat is the paradigm, but the simultaneous principle reaches any instrument that vests several parcels at once:</p><ul><li><strong>Proceedings in partition.</strong> A court decree partitioning co-owned land vests title in the various parties at the same time and by the same decree; none is senior to the other. Treat it as a subdivision.</li><li><strong>Heirs under a will.</strong> All devisees receiving land under a single will take with equal standing and no senior rights. Treat it as a subdivision.</li></ul><p>In each case the parcels are of equal dignity and excess/deficiency is apportioned, not assigned to a ''junior.''</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0001-0000-0000-000000000004', 'd2920510-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs / caution: Simultaneous-conveyance doctrine is general American boundary law and Texas applies it without material variation — the recorded subdivision plat is the paradigm, metes-and-bounds carve-outs are the sequential paradigm. But the doctrine is not universal: some states (e.g., Pennsylvania) do not recognize simultaneous conveyances at all. Always confirm the rule of the state where the land lies; relocation of subdivision boundaries must follow that state''s laws (federal subdivisions excepted)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0001-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A simultaneous boundary is created in the same legal instant, by the same party, by the same instrument — classically a recorded subdivision plat.","The three requirements: divisions shown on a plat, the map filed and approved, and parcels sold by reference to the approved plat.","All simultaneously created parcels are of equal dignity; no lot is senior, and the order of later sale is immaterial.","Partition decrees and devises by will are treated as subdivisions (equal standing, apportionment).","Excess/deficiency is proportioned by frontage, but ripened unwritten rights still prevail."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0002-0000-0000-000000000000', 'd2920510-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Protraction vs. survey-and-monumentation</h3><p>How interior lots are <em>located</em> depends on how they were <em>originally created</em>:</p><ul><li>If interior lots were created by <strong>protraction</strong> (drawn on paper, never staked on the ground), the lots are located by <strong>measurement from the subdivision boundaries</strong> according to the plat dimensions.</li><li>If interior lots were created by <strong>survey with monumentation</strong> (staked on the ground at the time of platting), then the <strong>original survey and its monuments control</strong> the lot locations — even over the plat''s stated dimensions.</li></ul><p>The intentions of the parties to the subdivision are paramount to all other considerations, informed by supplemental clauses in the deeds and by the applicable state subdivision laws.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0002-0000-0000-000000000001', 'd2920510-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Original lines are unalterable</h3><p>Once a lot, street, or block line within a subdivision has been <strong>established by the original surveyor</strong> and the land is sold in accordance with the original plat, those lines as originally marked and surveyed are <strong>unalterable except by resubdivision</strong>. A later surveyor is not empowered to place subdivision lines in any position other than those established by the original surveyor; if a later surveyor sets the lines erroneously, the lines must be re-established in their <em>original</em> position. (Brown traces this principle to the federal PLSS rule of the Land Act of February 11, 1805, that original lines and corners are unalterable by surveyors or courts.) The subdivision''s <strong>exterior</strong> boundary is the possible exception — it may still be subject to senior rights of adjoining tracts.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0002-0000-0000-000000000002', 'd2920510-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Monuments control the facts on the plat</h3><p>In a lot-and-block description, the <strong>subdivision monuments called for on the plat</strong> — or monuments set by others and known to perpetuate the position of the original monuments — control the position of the original lot lines, if they are <em>properly identified and undisturbed</em>. Original monuments set on the ground control the facts given on the plat (unless the intent is clearly otherwise): <strong>where the map and the facts on the ground are inconsistent, the map must yield to the ground</strong>. A monument''s markings, after due allowance for weathering and deterioration, should be substantially the same as the record describing it.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0002-0000-0000-000000000003', 'd2920510-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Not all monuments are original monuments. Monuments that later became ''title monuments'' by prescription, agreement, or estoppel cannot be used to determine or control the original lines of the subdivision — they only fix a title boundary between the affected owners. Likewise, uncalled-for monuments cannot be automatically accepted; if they fit the measured distances and directions they may be accepted by ''common report,'' but a monument that can positively be proved incorrect cannot be accepted no matter how many people rely on it."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0002-0000-0000-000000000004', 'd2920510-0000-0000-0000-000000000002', 'text', '{"html":"<h3>The street-line hierarchy and senior rights</h3><p>For locating street and lot lines, Brown lays out a fallback order: (1) <strong>natural monuments</strong> called for (a river, shoreline) are presumed to control; (2) then <strong>artificial monuments</strong> representing the lines actually run by the original surveyor; (3) then <strong>improvements</strong> (curbs, paving, fences) installed in accordance with the original survey monuments — but only while they were in fact built to those monuments; (4) then the <strong>plat width, distances, and angles</strong>; and as a last resort, the width <strong>scaled from the map</strong>. Throughout, original monuments set to control the subdivision boundary <strong>yield to senior rights</strong> in the event of an overlap, and where a <em>gap</em> exists between the subdivision and an adjoiner, the lines marked and surveyed control over a mere call for the adjoiner. Every rule here is rebuttable by contrary evidence.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0002-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', 'table', '{"headers":["Priority","Controlling evidence for a subdivision lot/street line"],"rows":[["1","Found original monuments (or reliable perpetuations of them), properly identified and undisturbed"],["2","Natural monuments called for (river, shoreline)"],["3","Artificial monuments / lines actually run by the original surveyor"],["4","Improvements built in accordance with the original survey monuments"],["5","Plat record: width, distances, and angles (proportion excess/deficiency here)"],["6","Width scaled from the map (last resort)"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0002-0000-0000-000000000006', 'd2920510-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Protracted lots are located by measurement from the subdivision boundary; surveyed-and-monumented lots are located by the original monuments.","Original lines established by the creating surveyor are unalterable except by resubdivision; an erroneous later line must be put back where the original was.","Found original monuments control over the plat; where map and ground disagree, the map yields to the ground.","Order of control: found monuments > natural monuments > artificial monuments/lines run > conforming improvements > plat record > scaled width.","The exterior boundary still yields to the senior rights of adjoining tracts."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000000', 'd2920510-0000-0000-0000-000000000003', 'text', '{"html":"<h3>When (and why) you proportion</h3><p>Within a subdivision, distance, direction, and area are <strong>subordinate to the intent of the subdivider</strong>: the lines are as marked and surveyed, and original monuments control. <strong>Excess or deficiency</strong> appears when newer, more precise measurements between original monument positions differ from the original record measurements. When no better evidence of the interior corner positions survives, that excess or deficiency is <strong>distributed in proportion to the record (linear) measurements</strong> between the original found monuments. Proportioning is genuinely a <strong>last resort</strong> — used only after found monuments, perpetuations, natural/artificial monuments, and conforming improvements have all been exhausted.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000001', 'd2920510-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Single proportionate measurement</h3><p>Single (one-dimensional) proportionate measurement restores interior corners on a <strong>single straight line between two found controlling monuments</strong>. The corrected length of each interval bears the same ratio to the corrected whole as the record interval bears to the record whole. Define the proportion factor <em>k</em> as the measured total divided by the record total; then each lot''s corrected frontage is its record frontage times <em>k</em>. When the lots have equal record frontage, every lot simply becomes the measured total divided by the number of lots.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000002', 'd2920510-0000-0000-0000-000000000003', 'equation', '{"latex":"k = \\dfrac{D_{meas}}{D_{rec}} \\qquad d_i^{\\,corr} = k\\, d_i^{\\,rec} = \\dfrac{D_{meas}}{D_{rec}}\\, d_i^{\\,rec}","label":"Single proportionate measurement (per-interval correction)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000003', 'd2920510-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Worked example (Hermansen block)</h3><p>A 1950 subdivision created six lots, each with a record frontage of <strong>100 ft</strong> (record block = 600 ft). A retracement finds the two original concrete block-corner monuments but no interior monuments, and the measured distance between them is <strong>596.44 ft</strong> — a deficiency of 3.56 ft. The proportion factor is <em>k</em> = 596.44 / 600 = 0.99407. Each equal lot''s corrected frontage is 100 × 0.99407 = <strong>99.41 ft</strong> (equivalently 596.44 / 6 = 99.41 ft). The 3.56-ft shortage is shared by all six lots, not dumped on the end lot.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000004', 'd2920510-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Cumulative proportion: distance to an interior corner</h3><p>To set an interior corner <em>i</em> lots in from a found end monument, do not multiply lot-by-lot and accumulate rounding — apply the factor to the <strong>cumulative record distance</strong>. The corrected distance from the found monument to the corner between lot <em>i</em> and lot <em>i</em>+1 is the measured total times the ratio of the cumulative record distance to that corner over the record total.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', 'equation', '{"latex":"X_i^{\\,corr} = D_{meas}\\cdot\\dfrac{\\sum_{j=1}^{i} d_j^{\\,rec}}{D_{rec}}","label":"Cumulative (single) proportion to interior corner i","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000006', 'd2920510-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"Stop at undisturbed monuments. Excess or deficiency cannot be distributed BEYOND any undisturbed original monument. In the Hermansen example, an original cedar stake survived at the lot 4/5 corner; an honest apportionment must proportion the record 0-to-400 ft segment to the measured distance to that stake, and the record 400-to-600 segment to the remainder — NOT proportion straight across the whole block as if the stake were absent. Failing to use a found interior monument is exactly how two surveyors end up 1.79 ft apart on the same block."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000007', 'd2920510-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Texas differs (PLSS): ''Single proportionate measurement'' is a federal-PLSS/BLM term from the Manual of Surveying Instructions for restoring lost section corners. Texas retained its own public domain at annexation and has no township-range grid, so Texas resolves most retracement by following the original surveyor''s footsteps and monuments, with proportioning used sparingly as a fallback. There is no controlling Texas Supreme Court case adopting ''single proportionate measurement'' by name; it enters Texas practice through accepted surveying methodology and expert testimony."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0003-0000-0000-000000000008', 'd2920510-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["Proportion only as a last resort, after found monuments and all better evidence are exhausted.","Single proportion factor k = measured total / record total; corrected lot = k times record lot.","For equal lots, corrected frontage = measured total / number of lots.","Find an interior corner with cumulative proportion: measured total times (cumulative record distance / record total).","Never distribute excess/deficiency across an undisturbed original interior monument — proportion each segment separately."]}'::jsonb, 8);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000000', 'd2920510-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Total surplus/shortage and per-lot adjustment</h3><p>The total excess or deficiency in a block is simply the measured total between controlling monuments minus the record total. When the lots have equal record frontage, the per-lot adjustment is that total divided by the number of lots (added for excess, subtracted for deficiency). For unequal lots the adjustment to each lot is the total surplus times that lot''s share of the record total. Either way the corrected frontages must sum back to the measured total — that is the check.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000001', 'd2920510-0000-0000-0000-000000000004', 'equation', '{"latex":"\\Delta = D_{meas}-D_{rec} \\qquad \\delta_i = \\Delta\\cdot\\dfrac{d_i^{\\,rec}}{D_{rec}} \\quad\\Longrightarrow\\quad d_i^{\\,corr}=d_i^{\\,rec}+\\delta_i","label":"Excess/deficiency distributed in proportion to record frontage","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000002', 'd2920510-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Blunder vs. distributed error</h3><p>Proportioning assumes the discrepancy is <strong>ordinary distributed measurement error</strong>. If instead the excess or deficiency was caused by an isolable <strong>mathematical error (blunder) in one lot</strong>, that error is given to the lot where it occurs — <em>\"an error should be placed where the error occurs, if it can be so ascertained.\"</em> And an error within one block is never prorated into another block: if Block 3 is 1 ft short and Block 2 is 1 ft long, you cannot give Block 2''s extra foot to Block 3. Excess or deficiency in the width of a <strong>street</strong> is normally not prorated either (though not all courts agree).</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000003', 'd2920510-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The remnant rule and the end lot</h3><p>Two end-lot rules matter. First, where the <strong>end lot''s frontage is not given</strong> on the plat (the interior lots carry the dimensions), all of the excess or deficiency is presumed to fall on that end lot. Second, where the surplus or shortage is deliberately thrown onto an <strong>irregularly shaped lot at the end</strong> of the block, the method is the <strong>remnant rule</strong> — accepted in few jurisdictions, and a trap for the unwary surveyor (Brown points to <em>Barrett v. Perkins</em>, 113 Minn. 480 (1911)). A considerable excess/deficiency in blocks adjoining a subdivision boundary is prorated only as a last resort, and any leftover is given to the lot on the subdivision boundary — it is normally safer to locate lots <strong>from the interior</strong> of a subdivision than from its outer boundary.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000004', 'd2920510-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Single-proportion restoration of one lost corner</h3><p>To restore a single <strong>lost corner</strong> that lies between two found corners on a line, proportion the record distances to the measured distance. If a lost corner has record distances <em>a</em> and <em>b</em> to the two found monuments (record span <em>a</em>+<em>b</em>) and the measured span between those monuments is <em>m</em>, the corrected distance from the first found monument to the lost corner is <em>m</em> × <em>a</em> / (<em>a</em>+<em>b</em>). The same ratio idea, applied to a single straight line, is the one-dimensional case you will use most often inside a block.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', 'equation', '{"latex":"X_{lost} = m\\cdot\\dfrac{a}{a+b}","label":"Single-proportion position of a lost corner between two found corners","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000006', 'd2920510-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Double proportionate measurement (concept)</h3><p>When a lost corner is controlled in <strong>two directions</strong> — as a PLSS section corner common to four sections is — it is restored by <strong>double proportionate measurement</strong>: proportion independently along the latitudinal (E–W) line between the nearest found corners and along the longitudinal (N–S) line between the nearest found corners, then bring the two proportioned positions together to fix the corner (with a small balancing of the differences). This is a <strong>federal BLM / PLSS construct</strong> for restoring lost public-land corners, not a routine subdivision tool. In a lot-and-block subdivision the one-dimensional single-proportion method along a line is almost always what applies.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000007', 'd2920510-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas differs (PLSS): Double proportionate measurement comes from the BLM Manual of Surveying Instructions and presupposes the federal township-range grid. Texas land was never federal public domain — it has no PLSS grid — so double proportion is a borrowed fallback with no marquee Texas case adopting it. In Texas, a ''lost'' corner is restored first from the original surveyor''s footsteps and the GLO original-survey record; proportioning of any kind is used only when those fail. Do not attribute a famous Texas case to double proportionate measurement."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0004-0000-0000-000000000008', 'd2920510-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Total Δ = measured total − record total; per-lot adjustment is Δ times the lot''s share of the record total (Δ/n for equal lots).","An isolable blunder is placed in the lot where it occurs; error in one block is never prorated into another, and street width is normally not prorated.","If the end lot''s dimension is omitted it absorbs the excess/deficiency; the remnant rule throws surplus onto an irregular end lot but is disfavored.","A single lost corner between two found corners is restored by m × a/(a+b) along the line.","Double proportionate measurement (two-direction restoration) is a BLM/PLSS method; in Texas it is a fallback with no controlling case."]}'::jsonb, 8);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0005-0000-0000-000000000000', 'd2920510-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Combined and ''part-of-a-lot'' descriptions</h3><p>Subdivision practice constantly produces <strong>combination descriptions</strong> — a deed conveys a <em>portion</em> of a platted lot, or a portion of a metes-and-bounds tract, by reference to the larger parcel plus added measurements. Brown supplies presumptions for reading these ''an <em>of</em>'' descriptions:</p><ul><li>Conveying a portion <strong>of a subdivision lot</strong>, the owner conveys the part called for measuring <strong>from the side line of the street</strong> (the original lot line). Vacations or openings of streets do not alter the original lot lines.</li><li>Conveying a portion <strong>of a metes-and-bounds tract</strong>, measurements run <strong>from the boundary line</strong>, even where that boundary line lies within a street.</li><li>When the ''of'' description is given by lineal measurement, the presumption is that the measurement is made <strong>at right angles</strong> to the boundary line it runs from, unless otherwise specified.</li></ul>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0005-0000-0000-000000000001', 'd2920510-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Fractions and dividing a lot into halves</h3><p>Fractional conveyances follow their own presumptions:</p><ul><li>When a <strong>fraction of the whole</strong> is conveyed — e.g., ''the west half'' — the conveyance is presumed to be based on <strong>area</strong> measurement unless stated otherwise.</li><li>When the easterly and westerly lot lines are shown parallel on the map and are in fact nearly parallel, the dividing line between the east and west halves is run on the <strong>mean bearing</strong> of the two side lines.</li><li>When those side lines are <strong>not parallel</strong> (and not cardinal), the dividing line between east and west halves is made to run <strong>north and south</strong>.</li><li>Where a deed conveys the ''east one-half of lot 1'' and a companion deed conveys ''lot 1, except the east one-half,'' the west line of the east half is commonly taken to be <strong>parallel with the east line of the lot</strong>, provided that east line is nearly cardinal.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0005-0000-0000-000000000002', 'd2920510-0000-0000-0000-000000000005', 'table', '{"headers":["Situation","Presumed construction"],"rows":[["Portion ''of'' a subdivision lot","Measure from the side line of the street (original lot line); street vacations don''t move it"],["Portion ''of'' a metes-and-bounds tract","Measure from the boundary line, even if it lies in a street"],["''Of'' by lineal measurement","Measurement is at right angles to the boundary it runs from, unless specified"],["Fraction of the whole (''west half'')","Based on area, unless stated otherwise"],["Side lines parallel on map","Divide on the mean bearing of the two side lines"],["Side lines not parallel / not cardinal","Run the dividing line north–south"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0005-0000-0000-000000000003', 'd2920510-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Laying off a given area</h3><p>When a stated <em>area</em> must be laid off without other qualifying terms: an area on the <strong>side of a tract</strong> is taken as a <strong>parallelogram</strong>; an area laid off <strong>on a given line</strong> is presumed a <strong>square</strong>; and an area laid off <strong>in a corner</strong> of a parcel is presumed to be as nearly a parallelogram with equal sides as the circumstances permit. These presumptions only fill gaps — express terms in the deed always govern.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0005-0000-0000-000000000004', 'd2920510-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"Good drafting practice. The scrivener should write each description as an individual creation, assuming a continuity of words and definitions throughout. Avoid deed calls measured from two different directions in the same description — they breed gaps, overlaps, and ambiguity. These are rules of construction (gap-fillers): the controlling rule remains the expressed intent of the parties read from the whole instrument."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0005-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"Texas differs / order of authority: These construction presumptions are general American boundary-law canons and Texas applies them, but in Texas they are strictly SUBORDINATE. Texas construes a deed by the intent expressed within the four corners (Stafford v. King; Bass v. Harper), follows the original surveyor''s footsteps, and applies the dignity of calls (natural > artificial > course > distance > quantity) before resorting to mechanical default canons. Use these presumptions only to fill genuine gaps the instrument leaves open."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0005-0000-0000-000000000006', 'd2920510-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["A portion ''of'' a subdivision lot is measured from the street side line; a portion ''of'' a metes-and-bounds tract from the boundary line — even in a street.","An ''of'' lineal measurement is presumed at right angles to the boundary unless specified.","A ''west half'' is presumed by area; divide parallel-sided lots on the mean bearing, non-parallel lots north–south.","Laid-off areas default to a parallelogram (side), a square (on a line), or near-equal-sided parallelogram (corner).","All such canons are gap-fillers, subordinate in Texas to expressed intent, footsteps, and the dignity of calls."]}'::jsonb, 6);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000001', 'Simultaneous conveyance', 'Several parcels created in the same legal instant by the same party and the same instrument (classically the lots of a recorded subdivision plat); all parcels are of equal dignity with no senior rights among them.', 'Born together → equal standing.', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000002', 'Equal dignity (of lots)', 'The principle that lots created simultaneously have equal standing, so no lot can claim seniority over another; excess and deficiency are apportioned rather than dumped on a ''junior'' lot.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000003', 'Three requirements for a simultaneous (plat) conveyance', '(1) all divisions shown on a plat/map, (2) the map filed and approved, (3) parcels sold with reference to the APPROVED plat or map.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000004', 'Proceedings in partition', 'A court decree dividing co-owned land that vests title in all parties at the same time and by the same decree; treated as a subdivision (no senior rights, apportion excess/deficiency).', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000005', 'Protraction', 'Creation of lots by drawing them on the plat without staking them on the ground; such lots are located by measurement from the subdivision boundaries per the plat dimensions.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000006', 'Original monument controls the plat', 'Rule that an undisturbed, properly identified original monument set on the ground controls the position of the lot line over the figures shown on the plat; where map and ground conflict, the map yields to the ground.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000007', 'Unalterable original lines', 'Once the original surveyor established a lot/street/block line and land sold by the plat, those lines are unalterable except by resubdivision; an erroneous later line must be re-established in its original position.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000008', 'Common report', 'Acceptance of a marker as correct because surveyors and the community have long relied on it, even though it cannot be positively proved; a marker proved to be incorrect cannot be accepted by common report.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000009', 'Title monument vs. original monument', 'A title monument fixes a boundary between owners by prescription, agreement, or estoppel; it cannot be used to determine or control the ORIGINAL lines of the subdivision, which only original monuments fix.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000010', 'Single proportionate measurement', 'One-dimensional restoration of interior corners on a straight line between two found controlling monuments; each interval''s corrected length equals its record length times (measured total / record total).', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000011', 'Proportion factor (k)', 'The ratio of the measured total distance to the record total distance between controlling monuments; multiply each record lot frontage by k to get its corrected frontage.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000012', 'Excess / deficiency', 'The difference between the newer measured distance and the original record distance between original monuments; distributed among the lots in proportion to their record measurements when no better evidence exists.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000013', 'No distribution beyond an undisturbed monument', 'Rule that excess or deficiency may not be prorated across any found, undisturbed original monument; each segment bounded by such monuments is proportioned independently.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000014', 'Proportioning is a last resort', 'Surveying maxim that proportionate measurement is used only after found monuments, perpetuations, natural and artificial monuments, and conforming improvements have all failed to fix the corner.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000015', 'Remnant rule', 'Method of throwing all of a block''s excess or deficiency onto an irregularly shaped lot at the end of the block; accepted in few jurisdictions and a recognized trap for surveyors.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000016', 'Error placed where it occurs', 'Rule that an excess or deficiency traceable to a mathematical blunder in one particular lot is assigned to that lot, rather than prorated among all lots, if the error can be ascertained.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000017', 'Double proportionate measurement', 'BLM/PLSS method for restoring a lost corner controlled in two directions, proportioning independently along the E–W and N–S lines between the nearest found corners; not a routine subdivision tool and not adopted by a marquee Texas case.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000018', 'Lost corner', 'An original corner whose position cannot be recovered from the original monument or any acceptable collateral evidence, so it must be restored by proportionate measurement; contrast an obliterated corner, which is recoverable.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000019', 'End-lot presumption', 'Where the plat omits the end lot''s dimension and gives only the interior lot dimensions, all of the block''s excess or deficiency is presumed to fall on the end lot.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000020', '''An of'' (part-of-a-lot) description', 'A description conveying a portion of a larger parcel by reference to it plus added measurements; measured from the street side line for a subdivision lot, or from the boundary line for a metes-and-bounds tract.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000021', 'Fractional conveyance presumption', 'When a fraction of the whole (e.g., ''the west half'') is conveyed, the division is presumed based on area unless the deed states otherwise.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000022', 'Mean-bearing division rule', 'When a lot''s side lines are shown and are in fact nearly parallel, the line dividing the lot into halves is run on the mean (average) bearing of the two side lines; if the sides are not parallel, the dividing line runs north–south.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000023', 'Laying-off-area presumptions', 'Absent qualifying terms, a given area on the side of a tract is a parallelogram, an area on a given line is a square, and an area in a corner is as near an equal-sided parallelogram as circumstances permit.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920540-0000-0000-0000-000000000024', 'Rule of construction (canon)', 'A default interpretive presumption used only to fill gaps the instrument leaves open; subordinate to the expressed intent of the parties, the footsteps of the original surveyor, and the dignity of calls.', NULL, 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000001', 'Which of the following best describes a ''simultaneously created'' boundary?', 'multiple_choice', '["Several parcels created in the same legal instant, by the same party, by the same instrument","Two adjoining tracts carved out of a parent tract several years apart","A boundary fixed by long acquiescence between two neighbors","A boundary established by adverse possession over the statutory period"]'::jsonb, 'Several parcels created in the same legal instant, by the same party, by the same instrument', 'A simultaneous conveyance creates several parcels at one legal instant by one instrument (the recorded plat is the paradigm), giving every parcel equal dignity. Carving tracts out years apart is sequential (senior/junior rights). Acquiescence and adverse possession are unwritten-rights doctrines, not methods of original simultaneous creation.', 'easy', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000002', 'In a recorded subdivision, the lot that was sold first is senior to the lots sold later and takes its full record dimension before the others are adjusted.', 'true_false', '["True","False"]'::jsonb, 'False', 'All lots in a recorded subdivision are created at the same instant and have equal standing; the order in which lots later sell is immaterial to seniority. Excess and deficiency are apportioned by frontage, not assigned by sale order.', 'easy', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000003', 'Which of the following is NOT one of the three requirements Brown gives for a simultaneous (plat) conveyance?', 'multiple_choice', '["Each lot must be physically monumented before any lot can be sold","All divisions of the land are indicated and shown on a plat or map","The map is filed and approved","Parcels are sold with reference to the approved plat or map"]'::jsonb, 'Each lot must be physically monumented before any lot can be sold', 'The three requirements are: divisions shown on a plat, the map filed and approved, and parcels sold by reference to the approved plat. Monumentation affects HOW lots are later located (survey-and-monument vs. protraction) but is not one of the three threshold requirements for a simultaneous conveyance to exist.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000004', 'A court decree of partition divides co-owned land among four owners. How are these resulting parcels treated for boundary-resolution purposes?', 'multiple_choice', '["As a subdivision — equal dignity, excess/deficiency apportioned","Sequentially, with the first-named party in the decree senior","As sequential conveyances ranked by deed-recording date","Each parcel is independent and never apportioned"]'::jsonb, 'As a subdivision — equal dignity, excess/deficiency apportioned', 'A partition decree vests title in all parties at the same time by the same decree, so none is senior. Brown directs that it be treated as a subdivision (equal dignity, apportionment). The same is true for heirs taking under a single will.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000005', 'True or False: Every state recognizes simultaneous conveyances and applies proportionate apportionment to subdivision lots.', 'true_false', '["True","False"]'::jsonb, 'False', 'Some states (Hermansen notes Pennsylvania) do not recognize simultaneous conveyances at all. Relocation of subdivision boundaries must follow the law of the state where the land lies, so the surveyor must confirm local rules.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000006', 'Interior lots of a subdivision were created by protraction (drawn on the plat, never staked). How are those lot lines located on the ground?', 'multiple_choice', '["By measurement from the subdivision boundaries per the plat dimensions","By the original interior monuments, which always exist for protracted lots","By scaling the recorded map regardless of the stated dimensions","By splitting the difference between adjoining deeds"]'::jsonb, 'By measurement from the subdivision boundaries per the plat dimensions', 'Protracted lots were never monumented, so they are located by measurement from the subdivision boundaries using the plat dimensions. Only lots created by survey-and-monumentation are located by their original interior monuments. Scaling is a last resort used when dimensions are missing.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000007', 'An undisturbed original iron pipe is found 0.4 ft off the position computed from the plat dimensions. What controls the lot corner?', 'multiple_choice', '["The found original monument — where the map and the ground disagree, the map yields to the ground","The plat dimension, because recorded figures are more precise than a weathered pipe","The average of the monument and the computed position","Whichever the current owner prefers"]'::jsonb, 'The found original monument — where the map and the ground disagree, the map yields to the ground', 'An undisturbed, properly identified original monument controls the position of the original lot line over the figures shown on the plat. The map must yield to the facts on the ground.', 'easy', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000008', 'A later surveyor discovers that a still-earlier surveyor placed a subdivision lot line in the wrong position relative to the original surveyor''s line. What is the correct treatment?', 'multiple_choice', '["Re-establish the line in its original position; a later surveyor cannot relocate the original line","Hold the later surveyor''s erroneous line because it was set in good faith","Split the difference between the two surveyors'' lines","Prorate the discrepancy across the whole block"]'::jsonb, 'Re-establish the line in its original position; a later surveyor cannot relocate the original line', 'Once the original surveyor establishes a line and land is sold by the plat, the line is unalterable except by resubdivision. A later surveyor is not empowered to relocate it; an erroneously set line must be put back where the original surveyor ran it.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000009', 'A fence between two lots became a recognized title boundary through years of acquiescence, but it does not match the original lot line. May the surveyor use that fence to determine the ORIGINAL subdivision lines?', 'multiple_choice', '["No — a monument that became a title monument by acquiescence/estoppel cannot fix the original subdivision lines","Yes — any long-accepted fence becomes an original monument","Yes, but only if both owners sign a boundary agreement","No, because fences can never affect a boundary in any way"]'::jsonb, 'No — a monument that became a title monument by acquiescence/estoppel cannot fix the original subdivision lines', 'Monuments that became ''title monuments'' by prescription, agreement, or estoppel fix a title boundary between the affected owners but cannot be used to determine or control the ORIGINAL lines of the subdivision. Only original monuments (or reliable perpetuations) fix the original lines.', 'hard', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000010', 'The original monuments of a subdivision boundary line overlap a senior adjoining tract. Which controls in the overlap?', 'multiple_choice', '["The senior adjoiner — the subdivision''s monuments yield to senior rights in an overlap","The subdivision monuments, because original monuments always control","The overlap is split evenly between the two owners","The junior subdivision, because its plat was recorded"]'::jsonb, 'The senior adjoiner — the subdivision''s monuments yield to senior rights in an overlap', 'Original monuments set to control a subdivision boundary still yield to senior rights in the event of an overlap. (In a GAP between the subdivision and an adjoiner, by contrast, the lines marked and surveyed control over a mere call for the adjoiner.)', 'hard', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000011', 'Proportionate measurement should be the surveyor''s first choice for locating any interior lot corner in a subdivision.', 'true_false', '["True","False"]'::jsonb, 'False', 'Proportioning is a last resort. Found original monuments, reliable perpetuations, natural and artificial monuments, and conforming improvements all control ahead of proportionate measurement. You proportion only when no better evidence of the interior corners survives.', 'easy', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000012', 'A block of 5 lots, each with record frontage 60.00 ft (record total 300.00 ft), is measured between found original block-corner monuments at 301.40 ft. Using single proportionate measurement, what is the corrected frontage of each (equal) lot, in feet?', 'numeric_input', '[]'::jsonb, '60.28', 'Proportion factor k = 301.40 / 300.00 = 1.004667. Each lot = 60.00 × 1.004667 = 60.28 ft (equivalently 301.40 / 5 = 60.28 ft). The 1.40-ft surplus is shared across all five lots.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000013', 'A block has 6 equal record lots of 100.00 ft (record total 600.00 ft) between two found end monuments measured at 596.44 ft. What is the corrected distance from the first found monument to the corner between lot 2 and lot 3, in feet?', 'numeric_input', '[]'::jsonb, '198.81', 'Cumulative record distance to the lot 2/3 corner = 200.00 ft. Corrected distance = 596.44 × (200.00 / 600.00) = 596.44 × 0.33333 = 198.81 ft. Use the cumulative proportion to avoid accumulating per-lot rounding.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000014', 'Why must a surveyor proportion each segment separately when an undisturbed original interior monument is found partway along the block?', 'short_answer', '[]'::jsonb, 'Because excess or deficiency cannot be distributed across (beyond) an undisturbed original monument; the found monument fixes that intermediate point, so each segment it bounds is proportioned independently.', 'Excess/deficiency cannot be distributed beyond any undisturbed original monument. The found interior monument is controlling evidence that fixes its corner; proportioning straight across it (ignoring it) is the error that put the 1970 and 2001 surveyors 1.79 ft apart in the Hermansen example.', 'hard', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000015', 'Between two found original monuments the record distance is 500.00 ft but the measured distance is 498.00 ft. A lot has a record frontage of 50.00 ft. What is its corrected frontage, in feet?', 'numeric_input', '[]'::jsonb, '49.80', 'k = 498.00 / 500.00 = 0.9960. Corrected frontage = 50.00 × 0.9960 = 49.80 ft. The 2.00-ft deficiency is distributed in proportion to record frontage.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000016', 'A block of 8 equal record lots of 50.00 ft (record total 400.00 ft) measures 403.20 ft between found end monuments. What is the per-lot adjustment (added to each record frontage), in feet?', 'numeric_input', '[]'::jsonb, '0.40', 'Total excess Δ = 403.20 − 400.00 = 3.20 ft. Per-lot adjustment = Δ / n = 3.20 / 8 = 0.40 ft. Each corrected lot = 50.40 ft, and 8 × 50.40 = 403.20 ft (check).', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000017', 'A block is measured 1.0 ft long overall, but the surveyor determines the entire 1.0 ft came from a single mis-recorded interior lot dimension. What is the correct treatment?', 'multiple_choice', '["Place the 1.0 ft in the lot where the error occurs; do not prorate it across the block","Prorate the 1.0 ft equally among all lots in the block","Give the entire 1.0 ft to the end lot under the remnant rule","Prorate the 1.0 ft into the adjoining block"]'::jsonb, 'Place the 1.0 ft in the lot where the error occurs; do not prorate it across the block', 'An error traceable to a blunder in one lot is placed where it occurs (''an error should be placed where the error occurs, if it can be so ascertained''). Proportioning assumes ordinary distributed error; an isolable blunder is not smeared across all lots, and never into another block.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000018', 'The ''remnant rule'' — throwing all excess or deficiency onto an irregularly shaped lot at the end of a block — is widely accepted and is the preferred method in most jurisdictions.', 'true_false', '["True","False"]'::jsonb, 'False', 'The remnant rule is accepted in FEW jurisdictions and Brown flags it as a trap for the unwary surveyor (Barrett v. Perkins). Proportioning by record frontage, not the remnant rule, is the general approach.', 'easy', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000019', 'A lost corner lies on a line between two found corners, with record distances of 300.00 ft and 200.00 ft to the two found monuments (record span 500.00 ft). The measured span between the found monuments is 505.00 ft. What is the corrected distance from the first found monument to the lost corner, in feet?', 'numeric_input', '[]'::jsonb, '303.00', 'Single-proportion: X = m × a/(a+b) = 505.00 × 300.00/500.00 = 505.00 × 0.60 = 303.00 ft. The 5.00-ft surplus is split in proportion to the record distances (3.00 ft to the first segment, 2.00 ft to the second).', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000020', 'Double proportionate measurement is primarily a method for which of the following?', 'multiple_choice', '["Restoring a lost PLSS corner controlled in two directions from four surrounding found corners","Dividing a subdivision lot into an east half and a west half","Distributing street-width excess among abutting lots","Determining senior rights between two sequential deeds"]'::jsonb, 'Restoring a lost PLSS corner controlled in two directions from four surrounding found corners', 'Double proportionate measurement is the BLM/PLSS method for a lost corner controlled in two directions, proportioning independently along the E–W and N–S lines between the nearest found corners. The other options are unrelated to it.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000021', 'When a subdivision plat gives dimensions for the interior lots but omits the dimension of the end lot, where is the block''s excess or deficiency presumed to fall?', 'multiple_choice', '["Entirely on the end lot whose dimension was omitted","Equally across all lots including the end lot","On the two lots nearest the block corners","It is given to the street"]'::jsonb, 'Entirely on the end lot whose dimension was omitted', 'When the end lot''s measurement is not given, all of the excess or deficiency is presumed to fall on that end lot — the interior lots hold their stated dimensions.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000022', 'A deed conveys ''the west 40 feet of Lot 7'' in a recorded subdivision. From where is the 40 feet measured?', 'multiple_choice', '["From the side line of the street (the original lot line); street vacations do not move it","From the centerline of the street fronting the lot","From the nearest set monument regardless of the lot line","From the geographic center of Lot 7"]'::jsonb, 'From the side line of the street (the original lot line); street vacations do not move it', 'For a portion ''of'' a subdivision lot, the measurement runs from the side line of the street — the original lot line. Vacations or openings of streets do not alter the original lot lines from which the measurement is made.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000023', 'A lot''s easterly and westerly side lines are NOT parallel and not cardinal. A deed conveys ''the east half'' of the lot. How is the dividing line drawn?', 'multiple_choice', '["It is made to run north and south","It is run on the mean bearing of the two side lines","It bisects the angle between the two side lines","It runs perpendicular to the front lot line"]'::jsonb, 'It is made to run north and south', 'When the side lines are not parallel (and not cardinal), the line dividing the lot into east and west halves is made to run north and south. The mean-bearing rule applies only when the side lines are shown parallel and are in fact nearly parallel.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000024', 'Absent qualifying terms, a stated area to be laid off ''on a given line'' is presumed to take what shape?', 'multiple_choice', '["A square","A parallelogram on the side of the tract","A near-equal-sided parallelogram in a corner","A circle of equal area"]'::jsonb, 'A square', 'An area laid off on a given line is presumed a square; an area on the side of a tract is a parallelogram; an area in a corner is as near an equal-sided parallelogram as circumstances permit. These are gap-filling presumptions only.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000025', 'In Texas, the rules of construction for combined descriptions (the ''of'' and ''half'' presumptions) override the expressed intent of the parties and the dignity of calls.', 'true_false', '["True","False"]'::jsonb, 'False', 'These canons are gap-fillers and are strictly subordinate. Texas construes a deed by the intent expressed within its four corners (Stafford v. King; Bass v. Harper), follows the original surveyor''s footsteps, and applies the dignity of calls before resorting to mechanical default presumptions.', 'medium', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920530-0000-0000-0000-000000000026', 'Why does Brown advise against writing a description with calls measured from two different directions?', 'short_answer', '[]'::jsonb, 'Because two-direction calls breed gaps, overlaps, and ambiguity; each description should be written as an individual creation with a continuity of words and definitions.', 'Calls run from two different directions in one description create internal conflicts (gaps and overlaps) that later surveyors must resolve. Good drafting writes each description as an individual creation assuming continuity of words and definitions.', 'easy', 'd2920000-0000-0000-0000-000000000005', 'd2920510-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920560-0000-0000-0000-000000000001', 'A block of {{n}} equal lots was platted, each with a record frontage of {{rec:f2}} ft (record total {{recTotal:f2}} ft). A resurvey finds the actual measured distance between the two original found block-corner monuments is {{meas:f2}} ft. Using single proportionate measurement, what is the corrected frontage (ft) of each lot?', 'numeric_input', '[]'::jsonb, '0', 'Single proportionate measurement distributes the {{surplus:f2}} ft excess/deficiency in proportion to record frontage. For equal lots the corrected frontage is the measured total divided by the number of lots: {{meas:f2}} ÷ {{n}} = {{_answer}} ft.', 'medium', 'd2920000-0000-0000-0000-000000000005', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920550-0000-0000-0000-000000000001', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920560-0000-0000-0000-000000000002', 'A block has {{n}} equal record lots of {{rec:f2}} ft each (record total {{recTotal:f2}} ft) between two found original end monuments measured at {{meas:f2}} ft. By single proportionate measurement, what is the corrected distance (ft) from the first found monument to the corner between lot {{i}} and lot {{i}}+1?', 'numeric_input', '[]'::jsonb, '0', 'Use cumulative proportion to avoid accumulating per-lot rounding: corrected distance = measured total × (cumulative record distance ÷ record total) = {{meas:f2}} × ({{cumRec:f2}} ÷ {{recTotal:f2}}) = {{_answer}} ft.', 'medium', 'd2920000-0000-0000-0000-000000000005', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920550-0000-0000-0000-000000000002', 0.03);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920560-0000-0000-0000-000000000003', 'A block of {{n}} equal record lots of {{rec:f2}} ft each (record total {{recTotal:f2}} ft) is measured at {{meas:f2}} ft between found original monuments. What is the per-lot adjustment (ft) that must be added to (or subtracted from) each record frontage?', 'numeric_input', '[]'::jsonb, '0', 'Total excess/deficiency Δ = {{meas:f2}} − {{recTotal:f2}} = {{delta:f2}} ft. For equal lots the per-lot adjustment is Δ ÷ n = {{delta:f2}} ÷ {{n}} = {{_answer}} ft (positive = add to each lot, negative = subtract).', 'easy', 'd2920000-0000-0000-0000-000000000005', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920550-0000-0000-0000-000000000003', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920560-0000-0000-0000-000000000004', 'A lost corner lies on a straight line between two found original corners. Its record distances to the two found monuments are {{a:f2}} ft and {{b:f2}} ft (record span {{recSpan:f2}} ft). The measured span between the found monuments is {{m:f2}} ft. By single proportionate measurement, what is the corrected distance (ft) from the first found monument to the lost corner?', 'numeric_input', '[]'::jsonb, '0', 'Single-proportion restoration: X = m × a/(a+b) = {{m:f2}} × {{a:f2}} ÷ {{recSpan:f2}} = {{_answer}} ft. The {{spanDelta:f2}} ft surplus/shortage in the span is split in proportion to the record distances a and b.', 'medium', 'd2920000-0000-0000-0000-000000000005', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920550-0000-0000-0000-000000000004', 0.03);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('d2920510-0000-0000-0000-000000000006', 'd2920000-0000-0000-0000-000000000005', 'Homework & Practice', '', ARRAY[]::text[], 6, 45, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, 'Module homework assignment(s) and practice problems.', ARRAY[]::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0006-0000-0000-000000000000', 'd2920510-0000-0000-0000-000000000006', 'text', '{"html":"<h2>Homework &amp; Practice</h2><p>Complete the homework below. You may submit a draft up to 48 hours before the deadline for instructor feedback. Use the randomized practice problems to prepare for the quiz.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0006-0000-0000-000000000001', 'd2920510-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 5A — Apportioning the Hermansen Block</h3><p><em>Type: computational</em></p><div>A 1950 subdivision created **six lots, each 100 ft wide** (record block = 600 ft), with the two block corners monumented by concrete monuments and each interior lot corner by a cedar stake. Work the following, showing all computations and a short written justification for each step.<br/><br/>1. **No interior monuments found.** A 1970 retracement finds only the two original concrete end monuments; the measured distance between them is **596.44 ft**. Apportion the block by single proportionate measurement: give the corrected frontage of each lot and the corrected distance from the west end monument to each interior lot corner. Confirm your corrected frontages sum to 596.44 ft.<br/>2. **One interior monument survives.** Now suppose the 1970 surveyor also found the **original cedar stake at the lot 4/5 corner**, measured 395.23 ft from the west concrete monument (and 201.21 ft to the east monument). Re-apportion: proportion the record 0–400 ft segment to 395.23 ft and the record 400–600 ft segment to 201.21 ft. Give the corrected frontage of every lot.<br/>3. **Compare and explain.** State the corrected lot 4 width from part 1 versus part 2, and explain in 3–5 sentences why ignoring the found cedar stake (part 1) produced a different answer — and which answer is correct under the rule that excess/deficiency cannot be distributed beyond an undisturbed original monument.<br/>4. **Documentation.** In 2–3 sentences, explain what the 1970 surveyor should have recorded (per Hermansen) so that a later surveyor would not reject the set monuments, and name two acceptable recording vehicles.</div>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920520-0006-0000-0000-000000000002', 'd2920510-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 5B — Construction of Combined Descriptions (written)</h3><p><em>Type: written</em></p><div>Answer each in a short paragraph, citing the controlling rule of construction and (where relevant) the paramount Texas principle that intent and the original surveyor''s footsteps govern.<br/><br/>1. A deed conveys ''the **east 50 feet of Lot 12**'' of a recorded subdivision; the street in front of Lot 12 was later vacated. From what line is the 50 ft measured, and does the vacation change the answer? Why?<br/>2. A grantor conveys ''the **west half of Lot 9**.'' The lot''s east and west side lines are shown parallel on the plat and are in fact nearly parallel. How is the dividing line drawn? How would your answer change if the side lines were clearly **not** parallel and not cardinal?<br/>3. A description requires laying off **two acres in the northeast corner** of a larger tract, with no qualifying terms. What shape is presumed, and why is this only a gap-filling presumption?<br/>4. **Texas overlay.** Explain in 4–6 sentences why these ''of'' and ''half'' presumptions are subordinate in Texas, identifying the order of authority a Texas court applies (expressed intent within the four corners, footsteps of the original surveyor, dignity of calls) before reaching a mechanical default canon. Note that Texas, having retained its public domain at annexation, has no PLSS grid, so PLSS-style double proportionate measurement is a borrowed fallback rather than a controlling Texas rule.</div>"}'::jsonb, 2);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0001-0000-0000-000000000000', 'd2920610-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Water as a boundary monument</h3><p>Natural water features — rivers, creeks, lakes, bays, and the Gulf — have served as ownership boundaries since the earliest land grants. Because water is a <strong>natural monument</strong>, it sits at the top of the dignity-of-calls hierarchy and controls over course, distance, and area. But a water boundary is unusual: it can <em>move</em>, the land beneath it may be owned by someone other than the upland owner, and the public may hold rights in the water even where a private party owns the bed. This module untangles those layers.</p><p>The vocabulary comes from Latin. A <strong>riparian</strong> owner (from <em>ripa</em>, river bank) owns land along the bank of a watercourse — a river, stream, or, in common usage, a lake. A <strong>littoral</strong> owner (from <em>litus</em>, seashore) owns land abutting a sea or ocean where the tide rises and falls. Surveyors and courts often use \"riparian\" loosely to cover both, but the precise distinction matters: the boundary rules and the public-trust burdens differ between flowing water and tidal water.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0001-0000-0000-000000000001', 'd2920610-0000-0000-0000-000000000001', 'table', '{"headers":["Term","Applies to","Root","Typical private boundary"],"rows":[["Riparian rights","Flowing watercourses — rivers, streams (and by usage, lakes)","Latin ripa = river bank","Center/thread if non-navigable; gradient boundary (bank) if navigable in Texas"],["Littoral rights","Static/tidal bodies — ocean, sea, Gulf, large lakes","Latin litus = seashore","Tidal high-water line (datum depends on the sovereign source of the grant in Texas)"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0001-0000-0000-000000000002', 'd2920610-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"No riparian boundary, no riparian rights. Riparian and littoral rights attach ONLY to a parcel that actually has a water boundary. A back lot that does not touch the water has no riparian rights — and if erosion later makes it riparian, its rights begin only then."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0001-0000-0000-000000000003', 'd2920610-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From Roman law to the Crown to the States</h3><p>The idea that the sovereign owns the beds of navigable waters is ancient. The <strong>Roman Civil Code (c. 500 AD)</strong> declared the beds of seas and rivers public property. Spanish law — <strong><em>Las Siete Partidas</em> (1265, compiled c. 1350)</strong> — gave the King ownership of the ocean bed up to the \"highest wash of the waves in winter,\" leaving private property only above that line. This <em>winter-high-water</em> concept is the seed of the Texas dual coastal datum you will meet in Lesson 4. In England, Lord Matthew Hale''s treatise <em>De Jure Maris</em> (c. 1666) placed the foreshore — the strip overflowed by ordinary tides — in the Crown.</p><p>Under English common law the Crown held title to the soil under tidewaters but the <strong>public''s rights of navigation and fishing could not be conveyed away</strong>. After the Revolution, the thirteen original colonies became sovereign successors to the Crown and took title to the beds of waters where the tide ebbed and flowed and to the beds of inland navigable waters. With the Constitution they ceded to the United States only the power to regulate interstate commerce and navigation — not title to the beds.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0001-0000-0000-000000000004', 'd2920610-0000-0000-0000-000000000001', 'accordion', '{"sections":[{"title":"The equal-footing doctrine","content":"<p>When new states entered the Union after 1789 they were admitted on an <strong>equal footing</strong> with the original states. Under <em>Pollard v. Hagan</em>, 44 U.S. 212 (1845), each new state therefore took title to the beds of its navigable waters as of the date of statehood, subject to federal regulation of commerce. The federal government, when it sold western public lands, <strong>reserved the navigable waters</strong> for the future states.</p>"},{"title":"Seven prior sovereigns — and why Texas is different","content":"<p>In the continental United States, seven prior sovereigns issued land grants: England, France, Spain, Holland, Russia, Mexico, and Texas. In the public-land states the <strong>United States</strong> was the grantor and reserved navigable waters to the states under equal footing. <strong>Texas is the exception:</strong> it entered the Union in 1845 retaining its own public domain. Texas land was never federal public domain, so a Texas water-boundary question traces back not to a federal patent but to one of four sovereigns of the soil — <strong>Spain, Mexico, the Republic of Texas, or the State of Texas</strong> — and the choice of boundary rule can turn on which one issued the grant.</p>"}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0001-0000-0000-000000000005', 'd2920610-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: Because Texas retained its public lands at annexation (1845) and was never on the federal PLSS, you must identify the SOVEREIGN SOURCE and DATE of the original grant before choosing a water-boundary rule. The same physical shoreline can be located differently for a Spanish/Mexican grant than for a Republic/State grant."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0001-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Riparian rights = flowing water (river/stream); littoral rights = static/tidal water (lake/sea/Gulf).","Riparian/littoral rights attach only to a parcel that actually borders the water — no water boundary, no rights.","The sovereign-owns-the-bed idea runs from Roman law through Spanish Siete Partidas and English common law into the American states via the equal-footing doctrine.","States took bed title at statehood; the U.S. reserved navigable waters when selling public lands — but Texas kept its own public domain and traces title to four sovereigns (Spain, Mexico, Republic, State)."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000000', 'd2920610-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Why navigability is the threshold question</h3><p>Before you can locate a water boundary or decide who owns the streambed, you must classify the water as <strong>navigable</strong> or <strong>non-navigable</strong>. The consequences are large. On a <strong>navigable</strong> stream the <strong>State of Texas owns the bed</strong>, holding it in trust for the public, and private title stops at the bank (the gradient boundary, Lesson 3). On a <strong>non-navigable</strong> stream the abutting owners take title to the <strong>center</strong> of the channel and there is no State-owned bed.</p><p>American courts long ago abandoned the old English rule that only tidal waters were navigable. In <em>The Daniel Ball</em>, 77 U.S. 557 (1870), the U.S. Supreme Court held that waters <strong>navigable in fact</strong> — usable as highways of commerce — are navigable in law, tide or no tide. That is the <strong>federal test</strong>: it looks at the waterway''s condition around the time of statehood and asks whether it was, or was susceptible of being, used for commerce.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000001', 'd2920610-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Texas adds a bright-line geometric test</h3><p>Texas keeps the commerce test but <strong>supplements</strong> it with a unique statutory rule. <strong>Tex. Nat. Res. Code §21.001(3)</strong> defines a \"navigable stream\" as one that <strong>\"retains an average width of 30 feet from its mouth up.\"</strong> The 30 feet is measured across the <strong>entire bed — from cut bank to cut bank — not the water flowing on any given day</strong>. So a creek that is dry for part of the year can still be legally navigable, and therefore public with a State-owned bed, purely because its average bed width is 30 feet or more.</p><p>The rule originates in an <strong>1837 act of the Republic of Texas</strong> that instructed surveyors <em>not to cross</em> such streams when laying out grants (so the bed would stay public). It carried into the old Revised Statutes and was recodified into §21.001. Because the test is geometric, a surveyor can often answer the navigability question with a tape and a calculation — frequently using historic vara measurements from the original GLO field notes.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000002', 'd2920610-0000-0000-0000-000000000002', 'equation', '{"latex":"W_{ft} = W_{vrs} \\times 2.77778 \\qquad \\text{navigable} \\iff W_{ft} \\ge 30","label":"Statutory 30-ft navigability test (1 vara = 33⅓ in = 2.77778 ft)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000003', 'd2920610-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Texas differs: Most states determine navigability ONLY by the commerce/navigable-in-fact test. Texas layers a bright-line statutory rule on top — average bed width of 30 feet (§21.001(3)). A small, non-commercial Texas creek can be \"statutorily navigable,\" making its bed State land, on width alone."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000004', 'd2920610-0000-0000-0000-000000000002', 'accordion', '{"sections":[{"title":"Ownership of beds — the rule in one line","content":"<p><strong>Navigable stream:</strong> the State of Texas owns the bed (in trust for the public); private patents run only to the gradient boundary. <strong>Non-navigable stream:</strong> the abutting owners own to the center/thread of the channel. Authority: <em>Motl v. Boyd</em>, 116 Tex. 82, 286 S.W. 458 (1926); <em>Brainard v. State</em>, 12 S.W.3d 6 (Tex. 2000); Tex. Nat. Res. Code Ch. 21.</p>"},{"title":"The 1929 \"Small Bill\" — a Texas curative statute","content":"<p>Many early Texas surveys and patents crossed streambeds, clouding title once the gradient-boundary cases established that the State owned navigable beds. The <strong>1929 \"Small Bill\"</strong> (historically Art. 5414a, Vernon''s Rev. Civ. Stat.) <strong>relinquished and quitclaimed the State''s interest in the BED SURFACE</strong> to the adjoining patentees/riparian owners and let owners short on upland make up acreage from the bed. <strong>But it reserved the minerals (and sand/gravel) to the State and expressly preserved the public''s and the State''s rights in the WATER.</strong> So along a navigable Texas stream the adjoining owner may now hold and pay taxes on the streambed surface, yet the public keeps navigation/recreation rights in the water and the State keeps the minerals.</p>"}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000005', 'd2920610-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Texas differs: The Small Bill (1929) is a Texas-specific curative statute born of the 1920s oil boom. Its hallmark — conveying the streambed SURFACE to private owners while SEVERING and RESERVING the minerals to the State — has no general common-law analog and still governs streambed mineral ownership in Texas title work."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', 'link_reference', '{"links":[{"url":"https://statutes.capitol.texas.gov/Docs/NR/htm/NR.21.htm","title":"Tex. Nat. Res. Code §21.001","type":"website","description":"Definitions, including the \"navigable stream\" 30-foot average-width rule."}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0002-0000-0000-000000000007', 'd2920610-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["Federal test: navigable-in-fact for commerce (The Daniel Ball). Texas ALSO uses a statutory test.","Tex. Nat. Res. Code §21.001(3): a stream is navigable if it retains an average bed width of 30 feet from the mouth up — measured bank to bank, not by the water present on a given day.","Navigable stream → State owns the bed (gradient boundary limits private title); non-navigable stream → abutting owners take to the center/thread.","The 1929 Small Bill relinquished the streambed SURFACE to riparian owners but reserved minerals to the State and preserved the public''s water rights."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0003-0000-0000-000000000000', 'd2920610-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Texas''s most distinctive boundary</h3><p>Once a stream is navigable and the State owns the bed, exactly <strong>where</strong> is the line between State bed and private upland? Most states answer \"the ordinary high-water mark\" — an observable vegetation or scour line. <strong>Texas does not.</strong> Texas locates the limit at the <strong>gradient boundary</strong>: a graded line along the bank lying <strong>midway between (i) the lower level of the flowing water that just reaches the foot of the cut bank, and (ii) the higher level that the water reaches without overtopping the cut bank.</strong> It is a <em>gradient</em> — a line that follows the slope of the bank along the stream — tied to the <strong>cut bank</strong> (also called the qualified or acceptable bank), not to a single high-water stain.</p><p>The cut bank is the relatively permanent, water-washed bank that separates the bed from the upland. Locating the gradient boundary is a specialized expert survey: it requires observing water levels, profiling the qualified bank, and interpolating a graded line — it is emphatically <strong>not</strong> a simple high-water line you can flag by eye.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0003-0000-0000-000000000001', 'd2920610-0000-0000-0000-000000000003', 'equation', '{"latex":"Z_{gb} = \\frac{Z_{low} + Z_{high}}{2}","label":"Gradient boundary elevation at a station = midway between the lower water level reaching the cut bank and the higher level not overtopping it","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0003-0000-0000-000000000002', 'd2920610-0000-0000-0000-000000000003', 'accordion', '{"sections":[{"title":"Oklahoma v. Texas, 260 U.S. 606 (1923)","content":"<p>The Red River boundary dispute that produced the method. To fix the Texas–Oklahoma line, the U.S. Supreme Court''s commissioner/surveyor <strong>Arthur A. Stiles</strong> developed the gradient boundary — a \"water-washed and relatively permanent elevation\" at the outer line of the river bed. Stiles later wrote the classic article <em>The Gradient Boundary — The Line Between Texas and Oklahoma Along the Red River</em>, 30 Tex. L. Rev. (1950).</p>"},{"title":"Motl v. Boyd, 116 Tex. 82, 286 S.W. 458 (1926)","content":"<p>The Texas Supreme Court adopted the gradient boundary as the division between public and private ownership along navigable streams. It defined the <strong>\"bed\"</strong> as the soil \"alternately covered and left bare ... adequate to contain [the water] at its average and mean stage during an entire year, <em>without reference to the extra freshets</em> ... <em>or the extreme droughts</em>.\" This \"average and mean annual stage\" idea is central: extreme floods and extreme dry spells are ignored.</p>"},{"title":"Brainard v. State, 12 S.W.3d 6 (Tex. 2000)","content":"<p>The leading modern application (Canadian River). The Court restated and refined the location method, describing the gradient boundary as the <strong>mid-height point of the lowest qualified (\"acceptable\") bank in the vicinity</strong>. Diversion Lake Club v. Heath, 126 Tex. 129 (1935), had earlier endorsed the gradient boundary as well.</p>"}]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0003-0000-0000-000000000003', 'd2920610-0000-0000-0000-000000000003', 'callout', '{"type":"warning","text":"Texas differs (the single most distinctive concept in this module): Virtually every other state fixes the riparian boundary at the ordinary high-water mark (OHWM). Texas uses a COMPUTED GRADIENT LINE at the mid-height of the qualified cut bank — requiring water-level observation, bank profiling, and gradient interpolation. Do not equate it with a simple high-water line."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0003-0000-0000-000000000004', 'd2920610-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Non-navigable streams: the medium filum aquae</h3><p>On a <strong>non-navigable</strong> stream there is no State bed and no gradient boundary. Title runs to the <strong>medium filum aquae</strong> — the \"middle thread\" or centerline of the stream. Where the two opposite banks belong to different owners, each owns to the thread; this is also expressed in federal law (43 U.S.C. §931: where opposite banks of a non-navigable stream belong to different persons, \"the stream and the bed thereof shall become common to both\"). The center can be defined as the center of the high-water marks, the center of the low-water marks, or the deepest channel (the <strong>thread</strong> or <strong>thalweg</strong>), depending on local law. When two adjoining deeds both call to a non-navigable stream and the channel later shifts gradually, the centerline boundary moves with it.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0003-0000-0000-000000000005', 'd2920610-0000-0000-0000-000000000003', 'table', '{"headers":["Stream class","Bed owner","Private boundary line","Authority"],"rows":[["Navigable (Texas)","State of Texas (public trust)","Gradient boundary (mid-height of qualified cut bank)","Motl v. Boyd; Brainard v. State; Oklahoma v. Texas"],["Non-navigable","Abutting owners to the center","Medium filum aquae (thread/thalweg)","43 U.S.C. §931; general Texas common law"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0003-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["The gradient boundary is the Texas limit of private title on a navigable stream: a graded line midway up the qualified cut bank, NOT the ordinary high-water mark.","It came from Oklahoma v. Texas (1923, Stiles) and was adopted for Texas public/private ownership in Motl v. Boyd (1926); refined as the mid-height of the lowest qualified bank in Brainard v. State (2000).","Motl v. Boyd defines the bed by the water''s average and mean annual stage, ignoring extreme freshets and droughts.","On non-navigable streams there is no State bed: owners take to the medium filum aquae (centerline/thread/thalweg)."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0004-0000-0000-000000000000', 'd2920610-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Tides and tidal datums</h3><p>The Moon''s gravitational pull raises tidal bulges on the near and far sides of the Earth, producing the daily ebb and flow. Because the Moon takes about 27.3 days to orbit and the tilt of its orbit cycles over <strong>18.6 years</strong>, a complete record of tidal behavior — the <strong>tidal epoch</strong> — spans 18.6 years. Tidal boundaries are statistical: they are the averages of repeated observations over that epoch, reduced to a precise elevation (a <strong>datum</strong>). <em>Borax Consolidated v. City of Los Angeles</em>, 296 U.S. 10 (1935), requires the use of these scientific averaging techniques to fix a tidal boundary; it established <strong>mean high water</strong> as the Anglo-American coastal boundary.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0004-0000-0000-000000000001', 'd2920610-0000-0000-0000-000000000004', 'table', '{"headers":["Datum","Definition"],"rows":[["Mean High Water (MHW) / mean high tide","The average of ALL the high-water marks over the 18.6-year tidal epoch."],["Mean Low Water (MLW)","The average of all the low-water marks over the epoch."],["Mean Higher High Water (MHHW)","The average of only the HIGHER of each day''s two high tides over the epoch (a more landward line)."],["Mean Lower Low Water (MLLW)","The average of only the lower of each day''s two low tides over the epoch."]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0004-0000-0000-000000000002', 'd2920610-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The Texas dual coastal rule</h3><p>On most American coasts the upland boundary is uniformly the <strong>mean high water</strong> line (<em>Borax</em>). Texas is <strong>dual</strong>. The seaward boundary of coastal upland — the line dividing private upland from State-owned tidal seabed — depends on the <strong>sovereign source of the grant</strong>:</p><ul><li><strong>Spanish/Mexican grants</strong> are bounded by the line of <strong>mean HIGHER high water (MHHW)</strong> — the more landward line. This reflects the civil law (<em>Las Siete Partidas</em>) that defined the shore by the reach of the highest, winter tides; the Texas Supreme Court translated that into the surveyable MHHW datum.</li><li><strong>Anglo-American grants — those under the Republic of Texas or the State of Texas</strong> — are bounded by the line of <strong>mean high tide / mean high water (MHW)</strong>, the ordinary high-water line.</li></ul><p>Because MHHW lies landward of MHW, a Spanish/Mexican coastal grant yields a <em>larger</em> State seabed and a <em>smaller</em> private upland than an otherwise identical Texas-law grant.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0004-0000-0000-000000000003', 'd2920610-0000-0000-0000-000000000004', 'accordion', '{"sections":[{"title":"Luttes v. State, 159 Tex. 500, 324 S.W.2d 167 (1959)","content":"<p>The controlling Texas authority on coastal upland boundaries. It concerned the 1829 Mexican \"Potrero de Buena Vista\" grant on the Laguna Madre. The Court held that the seaward boundary of a <strong>Spanish/Mexican</strong> grant is <strong>mean higher high water</strong>, distinguished from the <strong>mean high tide</strong> line that bounds grants made under Anglo-American (Texas) law. A coastal surveyor must therefore establish the chain of title back to the original sovereign <em>before</em> selecting the tidal datum.</p>"}]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0004-0000-0000-000000000004', 'd2920610-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas differs: The Anglo-American rule (Borax, 1935) uses mean high water everywhere. Texas is dual — mean high tide for its own-law grants, but the LANDWARD mean higher high water line for civil-law (Spanish/Mexican) grants (Luttes v. State). Always trace the chain of title to the original sovereign before choosing the coastal datum."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0004-0000-0000-000000000005', 'd2920610-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The Open Beaches Act and the rolling easement</h3><p>The <strong>Texas Open Beaches Act (TOBA)</strong> (originally 1959; now Tex. Nat. Res. Code Ch. 61) guarantees the public a free and unrestricted right of ingress, egress, and use of Gulf-front beaches. It recognizes a public easement over the <strong>dry beach between the line of mean low tide and the line of vegetation</strong> where a prescriptive, dedicated, or customary easement exists, and creates a <em>prima facie</em> presumption that this area is subject to a public easement. Historically the easement was said to <strong>\"roll\"</strong> landward as the vegetation line naturally migrated.</p><p><em>Severance v. Patterson</em>, 370 S.W.3d 705 (Tex. 2012), <strong>limited</strong> that doctrine. A public beach easement may <em>gradually</em> migrate with naturally shifting beaches, but it does <strong>not automatically roll onto previously private dry land after an avulsive event</strong> (such as a hurricane suddenly moving the vegetation line landward). After avulsion, the State must establish a <em>new</em> easement rather than rely on the old one rolling inland. The case imports the accretion/avulsion distinction (Lesson 5) directly into beach-access law.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0004-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Tidal datums are 18.6-year-epoch averages; Borax (1935) requires scientific averaging and sets mean high water as the Anglo-American coastal boundary.","MHHW (mean higher high water) averages only the higher daily high tide and lies LANDWARD of MHW.","Texas dual rule (Luttes v. State): Spanish/Mexican grants → MHHW; Republic/State grants → mean high tide (MHW). Trace the sovereign first.","TOBA gives the public an easement over the dry beach to the vegetation line; Severance v. Patterson stops the easement from automatically rolling onto private land after an AVULSIVE event."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000000', 'd2920610-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Water boundaries that move</h3><p>The general rule is that <strong>water boundaries follow the changing shoreline</strong> — but only when the change is gradual and imperceptible. The controlling variable is always <strong>gradual vs. sudden</strong>:</p><ul><li><strong>Accretion</strong> — the gradual, imperceptible accumulation of soil (alluvion) deposited by the water. The land formed belongs to the upland riparian/littoral owner, and the boundary moves outward.</li><li><strong>Reliction (dereliction)</strong> — the gradual, imperceptible recession or lowering of the water, exposing land that was once covered. Treated like accretion: the new land goes to the upland owner.</li><li><strong>Erosion</strong> — the gradual eating away of soil by the water. The boundary moves landward and the owner loses the eroded land (which becomes part of the bed).</li><li><strong>Avulsion</strong> — the <strong>sudden, perceptible</strong> removal of soil or shift of a channel (a flood cutting a new channel, a hurricane). The boundary is <strong>FIXED</strong> at its former location; title does not change merely because the water suddenly moved.</li></ul><p>The distinguishing feature is the <strong>time element</strong>: avulsion is sudden; accretion, reliction, and erosion are gradual.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000001', 'd2920610-0000-0000-0000-000000000005', 'table', '{"headers":["Process","Speed","Effect on boundary","Who gains/loses"],"rows":[["Accretion","Gradual","Boundary moves outward with the new shoreline","Upland owner gains the alluvion"],["Reliction","Gradual","Boundary moves outward as water recedes","Upland owner gains exposed land"],["Erosion","Gradual","Boundary moves landward","Upland owner loses; bed owner gains"],["Avulsion","Sudden","Boundary FIXED at former location","No change of title; ownership stays put"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000002', 'd2920610-0000-0000-0000-000000000005', 'callout', '{"type":"info","text":"Memory hook: GRADUAL moves the line; AVULSIVE fixes the line. An island suddenly cut off by avulsion stays with its original owner; land gradually added by accretion goes to the upland owner. Manmade/artificial accretion does NOT benefit the owner who caused it."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000003', 'd2920610-0000-0000-0000-000000000005', 'accordion', '{"sections":[{"title":"Avulsion after a boundary has already moved","content":"<p>If a navigable stream''s boundary has been moving by accretion/erosion and then an avulsion occurs, the <strong>moment of the avulsion fixes the ownership lines</strong>. The State that owned the bed before still owns it after; the abutting owners who owned to the banks before still own to the banks after; land left under the new channel is still owned by whoever owned it before — but that owner cannot block the new channel to navigation. On a non-navigable stream, owners who held to the center before continue to hold to the center of the (now dry) former bed.</p>"},{"title":"Manmade change and re-emerged land","content":"<p>Shoreline change caused directly by <strong>manmade</strong> works does not change title — a riparian owner may not benefit from accretion or avulsion that results from his own actions, and fill placed in State-owned tidelands belongs to the State. <strong>Re-emerged land</strong>: under the federal rule (followed by most states), if erosion destroys riparian lots and accretion later rebuilds them, the original owners reacquire their former rights as though never eroded; some states instead hold that the eroded lines are extinguished and the once-remote owner keeps the new accretion.</p>"}]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000004', 'd2920610-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Apportioning accretion among riparian owners</h3><p>When accretion forms in front of several owners on the same side of the water, the new land — and the valuable new water frontage — must be divided <strong>with equity and justice</strong>. Two goals guide the division: each owner should get a share of the new land in proportion to their holdings, and each should keep access to the water with a share of the <strong>new waterline in proportion to their share of the old waterline</strong>. Courts caution that \"no geometric theorem can be formulated to govern all cases\" and look to fairness, but several standard methods exist.</p><p>The method preferred by the federal government and a majority of states is the <strong>proportionate-shoreline method</strong> (<em>Johnston v. Jones</em>, 66 U.S. 109 (1862); BLM <em>Manual of Surveying Instructions</em>). It apportions the new frontage in the <strong>same ratio</strong> as the old frontage:</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000005', 'd2920610-0000-0000-0000-000000000005', 'equation', '{"latex":"S_i = \\left(\\frac{F_i}{\\sum F}\\right) \\times L_{new}","label":"Proportionate-shoreline method: each owner''s new-shoreline share S_i = (owner''s old frontage F_i / total old frontage) × total new shoreline length","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', 'table', '{"headers":["Method","How it divides","Best used when"],"rows":[["Proportionate shoreline","New frontage split in the same ratio as old frontage (Johnston v. Jones)","Federal/majority default; irregular or curving shorelines"],["Perpendicular","Line drawn perpendicular to the thread (streams) or to the new shoreline (wider bodies)","Fairly straight shores; also divides streambed when owners own the bed"],["Prolongation of property line","Side lines simply extended to the water","Rarely used"],["Proportionate acreage","Share of accreted AREA in proportion to total frontage","When the accreted land is more valuable than the frontage (used in Louisiana)"],["Round-lake (pie) / Long-lake","Lines to a center point (round lake) or perpendicular to the centerline (long lake)","Lakes, by shape"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0005-0000-0000-000000000007', 'd2920610-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["Accretion and reliction (gradual gains) go to the upland owner and move the boundary; erosion (gradual loss) moves it landward; avulsion (sudden) FIXES the boundary and changes no title.","The moment of an avulsion fixes ownership; manmade/artificial change does not benefit the owner who caused it.","Newly formed riparian land is divided with equity and justice — water frontage normally controls; ''no geometric theorem governs all cases.''","The proportionate-shoreline method (Johnston v. Jones; BLM Manual) is the federal/majority default: new frontage is split in the same ratio as the old frontage."]}'::jsonb, 7);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0006-0000-0000-000000000000', 'd2920610-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Owning the bank is not owning the water</h3><p>Everything so far has concerned <strong>boundaries</strong> — where the land ends and the water begins, and who owns the bed. A separate body of law governs the right to <strong>use</strong> the water itself, and in Texas the two are sharply divided. <strong>Owning the streambank does not give you a right to use the water</strong> beyond limited domestic and livestock use. Texas treats <strong>surface water</strong> and <strong>groundwater</strong> under two completely different regimes.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0006-0000-0000-000000000001', 'd2920610-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Surface water: State-owned, used by permit</h3><p>In Texas, <strong>surface water is owned by the State</strong> — every river, natural stream, lake, bay, and arm of the Gulf (Tex. Water Code Ch. 11, esp. §11.021). A private party acquires the right to use it only by <strong>appropriation under a State-issued permit</strong>, administered by the <strong>Texas Commission on Environmental Quality (TCEQ)</strong>, on a <strong>prior-appropriation</strong> basis — \"first in time, first in right.\" A streamside landowner keeps a limited right to take water for <strong>domestic and livestock</strong> use without a permit, but anything beyond that requires a permit.</p><p>Texas historically ran a confusing <strong>riparian/appropriation hybrid</strong>. The <strong>Water Rights Adjudication Act of 1967</strong> resolved decades of conflicting claims by merging recognized riparian claims into the single prior-appropriation permit system; claimants had to file by the deadline or have their rights folded into the unified framework.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0006-0000-0000-000000000002', 'd2920610-0000-0000-0000-000000000006', 'callout', '{"type":"warning","text":"Texas differs: Eastern states use pure riparian surface-water law; western states use prior appropriation. Texas is a historical HYBRID that was statutorily UNIFIED into appropriation in 1967. Bedrock point for surveyors and landowners: owning the streambank does NOT grant a right to use the water beyond domestic/livestock use — that requires a State (TCEQ) permit."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0006-0000-0000-000000000003', 'd2920610-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Groundwater: the rule of capture and ownership in place</h3><p>Groundwater follows a starkly different rule. Texas retains the <strong>rule of capture</strong> (the English \"absolute ownership\" rule): a landowner may pump and capture the water beneath his land — even to a neighbor''s detriment — generally <strong>without liability</strong>. The rule was adopted in <em>Houston &amp; Texas Central Railway Co. v. East</em>, 98 Tex. 146, 81 S.W. 279 (1904), which found no liability for draining a neighbor''s well through pumping.</p><p>Modern law adds a powerful overlay. In <em>Edwards Aquifer Authority v. Day</em>, 369 S.W.3d 814 (Tex. 2012), the Texas Supreme Court held that a landowner <strong>owns the groundwater in place</strong> as \"an exclusive and private property right ... of which he may not be deprived without a taking,\" protected by Tex. Const. art. I, §17 — much like oil and gas. <strong>Groundwater Conservation Districts (GCDs)</strong> may regulate pumping (Tex. Water Code Ch. 36), but regulation that cuts too deeply can be a <strong>compensable constitutional taking</strong>. The <strong>Edwards Aquifer Authority</strong> is the best-known of these districts.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0006-0000-0000-000000000004', 'd2920610-0000-0000-0000-000000000006', 'callout', '{"type":"warning","text":"Texas differs: Most states abandoned absolute capture for reasonable-use, correlative-rights, or the Restatement rule. Texas is a notable holdout that RETAINS the rule of capture while ALSO recognizing ownership in place (Edwards Aquifer Authority v. Day) — so over-regulation by a GCD can trigger takings liability."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0006-0000-0000-000000000005', 'd2920610-0000-0000-0000-000000000006', 'table', '{"headers":["","Surface water","Groundwater"],"rows":[["Ownership","Owned by the State of Texas","Owned in place by the landowner (Day, 2012)"],["Right to use","Appropriation permit (prior appropriation)","Rule of capture — pump what you can"],["Administered by","TCEQ","Groundwater Conservation Districts (e.g., Edwards Aquifer Authority)"],["Key authority","Water Code Ch. 11 (§11.021); 1967 Adjudication Act","H&TC Ry. v. East (1904); Edwards Aquifer Authority v. Day (2012); Water Code Ch. 36"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0006-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', 'key_takeaways', '{"title":"Key Takeaways","items":["Surface water in Texas is State-owned; use requires a TCEQ appropriation permit (prior appropriation), except limited domestic/livestock use.","The 1967 Water Rights Adjudication Act merged riparian claims into the unified appropriation permit system.","Groundwater follows the rule of capture (H&TC Ry. v. East, 1904): pump freely, generally without liability to neighbors.","Edwards Aquifer Authority v. Day (2012): the landowner owns groundwater in place; GCD over-regulation can be a compensable taking."]}'::jsonb, 6);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000001', 'Riparian rights', 'Rights, relative to the use of moving water (river or stream), that accrue to the owner of upland bordering that watercourse.', 'Latin ripa = river bank.', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000002', 'Littoral rights', 'Rights, relative to non-moving or tidal water (ocean, sea, Gulf, lake), that accrue to the owner of upland bordering that body.', 'Latin litus = seashore.', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000003', 'Equal-footing doctrine', 'New states are admitted on an equal footing with the original states and therefore take title to the beds of their navigable waters as of the date of statehood (Pollard v. Hagan, 1845).', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000004', 'Four sovereigns of the soil (Texas)', 'Every Texas title traces to Spain, Mexico, the Republic of Texas, or the State of Texas — Texas land was never federal public domain.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000005', 'Navigable stream (Texas statutory test)', 'Under Tex. Nat. Res. Code §21.001(3), a stream that retains an average width of 30 feet from its mouth up — measured across the entire bed, not the day''s flow.', 'A geometric, bright-line rule unique to Texas.', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000006', 'Navigable-in-fact (The Daniel Ball)', 'The federal test: waters usable, or susceptible of being used, as highways of commerce are navigable in law regardless of tide.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000007', 'Ownership of a navigable streambed (Texas)', 'The State of Texas owns the bed of a navigable stream in trust for the public; private title runs only to the gradient boundary.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000008', 'Small Bill (1929)', 'Texas curative statute (Art. 5414a) relinquishing the State''s interest in navigable streambed SURFACE to adjoining owners while reserving minerals/sand/gravel to the State and preserving public water rights.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000009', 'Gradient boundary', 'The Texas limit of private title on a navigable stream: a graded line along the bank midway between the lower water level reaching the cut bank and the higher level not overtopping it — the mid-height of the qualified cut bank.', 'Not the ordinary high-water mark.', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000010', 'Cut bank (qualified/acceptable bank)', 'The relatively permanent, water-washed bank separating the streambed from the upland, used to locate the gradient boundary.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000011', 'Motl v. Boyd (1926)', 'Texas Supreme Court case adopting the gradient boundary and defining the bed by the water''s average and mean annual stage, ignoring extreme freshets and droughts.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000012', 'Medium filum aquae', 'The ''middle thread'' or centerline of a non-navigable stream, to which abutting owners hold title; may be the thread/thalweg (deepest channel).', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000013', 'Tidal epoch', 'The 18.6-year period over which tidal observations are averaged to fix a tidal datum, reflecting the cycle of the Moon''s orbital tilt.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000014', 'Mean higher high water (MHHW)', 'The average of only the higher of each day''s two high tides over the tidal epoch; the more landward datum used for Texas Spanish/Mexican coastal grants.', 'Higher of the two daily highs.', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000015', 'Luttes v. State (1959)', 'Texas case establishing the dual coastal datum: Spanish/Mexican grants are bounded by mean higher high water, Anglo/Texas grants by mean high tide.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000016', 'Texas Open Beaches Act (TOBA)', 'Tex. Nat. Res. Code Ch. 61: guarantees public access to Gulf beaches and recognizes a public easement over the dry beach between mean low tide and the vegetation line.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000017', 'Severance v. Patterson (2012)', 'Texas case holding the public beach easement may roll with gradual change but does NOT automatically roll onto private land after an avulsive event (e.g., a hurricane).', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000018', 'Accretion', 'The gradual, imperceptible accumulation of soil (alluvion) deposited by water; the new land belongs to the upland owner and the boundary moves outward.', 'Alluvion is the deposit; accretion is the process.', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000019', 'Reliction', 'Dry land formed by the gradual, imperceptible recession or lowering of the water; treated like accretion (goes to the upland owner).', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000020', 'Erosion', 'The gradual eating away of soil by water; the boundary moves landward and the owner loses the eroded land to the bed owner.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000021', 'Avulsion', 'The sudden, perceptible removal of soil or shift of a channel; the boundary is FIXED at its former location and title does not change.', 'Sudden = boundary stays put.', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000022', 'Proportionate-shoreline method', 'Apportionment method (Johnston v. Jones; BLM Manual) dividing new water frontage among riparian owners in the same ratio as their old frontage.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000023', 'State ownership of surface water (Texas)', 'Under Tex. Water Code §11.021, all surface water in Texas (rivers, streams, lakes, bays, arms of the Gulf) is owned by the State; use requires a TCEQ appropriation permit.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000024', 'Prior appropriation', 'The ''first in time, first in right'' system by which Texas allocates the right to USE State-owned surface water through TCEQ permits.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000025', 'Rule of capture (groundwater)', 'The Texas rule that a landowner may pump and capture groundwater beneath his land, even to a neighbor''s harm, generally without liability (H&TC Ry. v. East, 1904).', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920640-0000-0000-0000-000000000026', 'Edwards Aquifer Authority v. Day (2012)', 'Texas case holding a landowner owns groundwater in place as a vested, constitutionally protected property right; over-regulation by a GCD can be a compensable taking.', NULL, 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000001', 'Which best describes the difference between riparian and littoral rights?', 'multiple_choice', '["Riparian rights attach to flowing watercourses (rivers/streams); littoral rights attach to static or tidal bodies (lakes, sea, Gulf).","Riparian rights attach to the ocean; littoral rights attach to rivers.","Riparian rights are public; littoral rights are private.","There is no legal difference; the terms are perfect synonyms."]'::jsonb, 'Riparian rights attach to flowing watercourses (rivers/streams); littoral rights attach to static or tidal bodies (lakes, sea, Gulf).', 'Riparian (Latin ripa, river bank) concerns moving water; littoral (Latin litus, seashore) concerns static/tidal water. The other options invert or deny the distinction; although ''riparian'' is loosely used for both, they are not legally identical.', 'easy', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000002', 'A back lot in a subdivision does not touch the lake but lies one lot behind a waterfront lot. Erosion later destroys the waterfront lot, leaving the back lot bordering the lake. What is true of the back lot''s riparian rights?', 'multiple_choice', '["It had no riparian rights until it became riparian by the erosion; rights attach only once a parcel actually borders the water.","It always had riparian rights because it was in a waterfront subdivision.","It can never acquire riparian rights because it was not originally riparian.","Riparian rights are personal and cannot attach to land at all."]'::jsonb, 'It had no riparian rights until it became riparian by the erosion; rights attach only once a parcel actually borders the water.', 'Riparian/littoral rights attach only to a parcel that actually has a water boundary. The back lot acquires those rights when it becomes riparian, not before; it does not keep or forever lack them based on its original position.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000003', 'Under the equal-footing doctrine, a state admitted after 1789 takes title to the beds of its navigable waters as of the date of statehood.', 'true_false', '["True","False"]'::jsonb, 'True', 'Pollard v. Hagan (1845): new states enter on an equal footing with the original states and take bed title to navigable waters at statehood, subject to federal regulation of commerce.', 'easy', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000004', 'Why must a Texas surveyor identify the original sovereign and date of a coastal or streamside grant before choosing a water-boundary rule?', 'short_answer', '[]'::jsonb, 'Because Texas land traces to four sovereigns (Spain, Mexico, Republic, State) and was never federal public domain; the boundary rule — especially the coastal datum — can differ depending on which sovereign issued the grant.', 'Texas retained its public lands at annexation and traces title to Spain, Mexico, the Republic, or the State. The coastal datum (and other rules) turn on the sovereign source — e.g., Spanish/Mexican grants use mean higher high water while Texas grants use mean high tide.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000005', 'Under Tex. Nat. Res. Code §21.001(3), a stream is statutorily ''navigable'' if it:', 'multiple_choice', '["Retains an average width of 30 feet, measured across the bed, from its mouth up.","Carries flowing water at least 30 days per year.","Is at least 30 feet deep at its mouth.","Has been declared navigable by the U.S. Army Corps of Engineers."]'::jsonb, 'Retains an average width of 30 feet, measured across the bed, from its mouth up.', 'Section 21.001(3) defines a navigable stream by average bed width of 30 feet from the mouth up — a geometric test measured bank to bank, not by days of flow, depth, or a federal declaration.', 'easy', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000006', 'A Texas creek is dry for several months each year but, measured cut bank to cut bank, averages 34 feet wide from its mouth up. Under Texas law, who owns the bed?', 'multiple_choice', '["The State of Texas, because the creek is statutorily navigable (≥30 ft average bed width) despite being seasonally dry.","The abutting owners to the center, because the creek is dry part of the year.","The federal government, because navigability is a federal question.","No one; a seasonally dry creek has no bed."]'::jsonb, 'The State of Texas, because the creek is statutorily navigable (≥30 ft average bed width) despite being seasonally dry.', 'The 30-foot test measures the bed, not the water present on a given day. A seasonally dry channel averaging ≥30 ft is statutorily navigable, so the State owns the bed (subject to the Small Bill''s surface relinquishment).', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000007', 'The 1929 Small Bill relinquished the State''s interest in navigable streambed surface to adjoining owners but reserved the minerals to the State.', 'true_false', '["True","False"]'::jsonb, 'True', 'The Small Bill (Art. 5414a) quitclaimed the streambed SURFACE to adjoining owners and let them make up short acreage, but it reserved minerals/sand/gravel to the State and preserved public water rights.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000008', 'On a non-navigable Texas stream whose opposite banks are owned by different people, how far does each owner''s title extend?', 'multiple_choice', '["To the center (medium filum aquae / thread) of the channel.","Only to the top of the bank on their side.","To the gradient boundary on their side.","Nowhere into the channel; the State owns the entire bed."]'::jsonb, 'To the center (medium filum aquae / thread) of the channel.', 'On non-navigable streams there is no State-owned bed; each abutting owner takes to the centerline/thread (43 U.S.C. §931). The gradient boundary and State bed apply only to navigable streams.', 'easy', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000009', 'The Texas gradient boundary on a navigable stream is best described as:', 'multiple_choice', '["A graded line at the mid-height of the qualified cut bank, midway between the lower water level reaching the bank and the higher level not overtopping it.","The ordinary high-water mark identified by the vegetation line.","The thread or thalweg of the deepest channel.","The line of mean higher high water."]'::jsonb, 'A graded line at the mid-height of the qualified cut bank, midway between the lower water level reaching the bank and the higher level not overtopping it.', 'Texas uses a computed gradient line at the mid-height of the qualified cut bank (Motl v. Boyd; Brainard v. State) — not the OHWM (used in most states), not the thalweg (non-navigable streams), and not MHHW (a coastal datum).', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000010', 'Most U.S. states fix the riparian boundary at the ordinary high-water mark, but Texas instead uses the gradient boundary.', 'true_false', '["True","False"]'::jsonb, 'True', 'The gradient boundary — a computed line at the mid-height of the qualified cut bank — is distinctively Texas. Virtually every other state uses the observable ordinary high-water mark.', 'easy', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000011', 'Which case originated the gradient boundary method, and in what dispute?', 'multiple_choice', '["Oklahoma v. Texas (1923) — the Red River boundary, where surveyor A.A. Stiles developed the method.","Luttes v. State (1959) — a Laguna Madre coastal grant.","Severance v. Patterson (2012) — a Galveston beach easement.","The Daniel Ball (1870) — a federal commerce navigability case."]'::jsonb, 'Oklahoma v. Texas (1923) — the Red River boundary, where surveyor A.A. Stiles developed the method.', 'Oklahoma v. Texas, 260 U.S. 606 (1923), fixed the Texas–Oklahoma line on the Red River; Stiles developed the gradient boundary there. Texas adopted it for public/private ownership in Motl v. Boyd (1926). The other cases concern coastal datums, beach easements, and federal navigability.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000012', 'In Motl v. Boyd, the ''bed'' of a navigable stream is defined by the water''s average and mean annual stage. What does this exclude?', 'multiple_choice', '["Extreme freshets (floods) and extreme droughts.","All flow except the single highest flood of record.","Any flow below mean low water.","Only manmade diversions."]'::jsonb, 'Extreme freshets (floods) and extreme droughts.', 'Motl v. Boyd defines the bed as the soil the water occupies at its average and mean annual stage, expressly disregarding extreme freshets and extreme droughts.', 'hard', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000013', 'Mean higher high water (MHHW) is computed by averaging:', 'multiple_choice', '["Only the higher of each day''s two high tides over the tidal epoch.","All high tides over the tidal epoch.","The lower of each day''s two low tides.","The midpoint of each day''s range."]'::jsonb, 'Only the higher of each day''s two high tides over the tidal epoch.', 'MHHW averages only the higher daily high; MHW averages ALL highs. Because it ignores the lower daily highs, MHHW lies landward of MHW.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000014', 'A coastal Texas tract derives from an 1829 Mexican grant. Under Luttes v. State, what datum bounds it on the seaward side, and is the private upland larger or smaller than under a State-of-Texas grant?', 'multiple_choice', '["Mean higher high water; the private upland is smaller (the State seabed is larger).","Mean high tide; the private upland is larger.","Mean lower low water; the private upland is larger.","Mean high water; identical to a State grant."]'::jsonb, 'Mean higher high water; the private upland is smaller (the State seabed is larger).', 'Luttes: Spanish/Mexican grants are bounded by MHHW (the landward line), so the private upland is smaller and the State seabed larger than under a Texas grant bounded by mean high tide (MHW).', 'hard', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000015', 'The tidal epoch over which tidal datums are averaged is:', 'multiple_choice', '["18.6 years.","27.3 days.","12.42 hours.","100 years."]'::jsonb, '18.6 years.', 'The 18.6-year epoch reflects the cycle of the Moon''s orbital tilt. 27.3 days is the orbital period and 12.42 hours is the interval between high and low tides, but the averaging epoch is 18.6 years.', 'easy', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000016', 'Under Severance v. Patterson, a public beach easement automatically rolls landward onto previously private dry land immediately after a hurricane shifts the vegetation line.', 'true_false', '["True","False"]'::jsonb, 'False', 'Severance held the easement may roll with GRADUAL change but does NOT automatically roll onto private land after an AVULSIVE event (e.g., a hurricane); the State must establish a new easement.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000017', 'Two lots, B and E, both call to a non-navigable river that forms their common boundary. Over years the channel shifts gradually. What happens to the common boundary?', 'multiple_choice', '["The boundary moves with the channel; gradual accretion/erosion shifts the centerline boundary.","The boundary stays fixed at the original channel location.","The State takes ownership of the abandoned channel.","Both lots lose all river frontage."]'::jsonb, 'The boundary moves with the channel; gradual accretion/erosion shifts the centerline boundary.', 'Gradual, imperceptible change moves a water boundary. With the river as the common (centerline) boundary, the line follows the slowly shifting channel.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000018', 'Two lots, B and E, both call to a river forming their common boundary. During a single flood the river suddenly cuts a new channel (an avulsion). What happens to the common boundary?', 'multiple_choice', '["The boundary is fixed at the river''s former location; avulsion does not change title or move the boundary.","The boundary instantly relocates to the new channel.","Ownership of both lots transfers to the State.","The lots must be re-platted and re-deeded."]'::jsonb, 'The boundary is fixed at the river''s former location; avulsion does not change title or move the boundary.', 'Avulsion is sudden and perceptible: the boundary is fixed at the former channel location and title does not change, in contrast to gradual change which moves the line.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000019', 'An island suddenly forms in a stream during a flood (avulsion). Who owns it?', 'multiple_choice', '["Whoever owned that bed/soil immediately before the avulsion; sudden change does not transfer title.","The upland riparian owner nearest the island, as accretion.","Always the State, regardless of stream class.","It becomes unowned public domain."]'::jsonb, 'Whoever owned that bed/soil immediately before the avulsion; sudden change does not transfer title.', 'Because avulsion does not change ownership, the island belongs to whoever owned that soil before the event — e.g., the bed owner (the State on a navigable stream, or the center owners on a non-navigable stream). It is not treated as accretion to an upland owner.', 'hard', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000020', 'Land gradually added to the upland by the imperceptible deposit of soil (alluvion) belongs to the upland riparian owner.', 'true_false', '["True","False"]'::jsonb, 'True', 'Accretion — gradual, imperceptible deposit of alluvion — inures to the upland owner and moves the boundary outward.', 'easy', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000021', 'Which apportionment method is the federal/majority default for dividing newly accreted land among riparian owners?', 'multiple_choice', '["The proportionate-shoreline method (Johnston v. Jones).","The prolongation-of-property-line method.","The proportionate-acreage method (Louisiana).","The round-lake (pie) method."]'::jsonb, 'The proportionate-shoreline method (Johnston v. Jones).', 'The proportionate-shoreline method, recommended by the BLM Manual and used by the federal government and a majority of states, splits the new frontage in the same ratio as the old. The others are situational alternatives.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000022', 'A riparian owner builds a jetty that causes sand to accumulate (artificial accretion) in front of his lot. Does he gain title to that new land?', 'short_answer', '[]'::jsonb, 'No. A riparian owner may not benefit from accretion (or avulsion) that results from his own manmade actions; manmade shoreline change does not change title in his favor.', 'Shoreline change resulting directly from the owner''s own manmade works does not work an ownership change in his favor; the rule rewarding accretion applies to natural deposition, not self-induced fill.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000023', 'In Texas, who owns surface water (rivers, lakes, bays), and how does a private party get the right to use it?', 'multiple_choice', '["The State owns it; a private party uses it only by a TCEQ appropriation permit (with limited domestic/livestock use exempt).","The adjoining landowner owns it outright and may use it freely.","The federal government owns it; the EPA issues use permits.","It is unowned; anyone may take any amount."]'::jsonb, 'The State owns it; a private party uses it only by a TCEQ appropriation permit (with limited domestic/livestock use exempt).', 'Tex. Water Code §11.021: surface water is State-owned; use requires a TCEQ appropriation permit under prior appropriation, except limited domestic/livestock use. Owning the bank does not grant a use right.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000024', 'Texas groundwater follows the rule of capture, and under Edwards Aquifer Authority v. Day the landowner also owns the groundwater in place.', 'true_false', '["True","False"]'::jsonb, 'True', 'Texas retains the rule of capture (H&TC Ry. v. East, 1904) and Day (2012) recognizes ownership in place as a vested, constitutionally protected right; over-regulation by a GCD can be a compensable taking.', 'medium', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920630-0000-0000-0000-000000000025', 'A landowner pumps so heavily that his neighbor''s well goes dry. Under the Texas rule of capture, is he liable to the neighbor?', 'multiple_choice', '["Generally no — under the rule of capture a landowner may capture groundwater beneath his land even to a neighbor''s detriment, without liability.","Yes — Texas uses the reasonable-use rule, which forbids harming a neighbor.","Yes — pumping that dries a neighbor''s well is automatically a taking.","Only if the neighbor''s well predates his by 10 years (prior appropriation)."]'::jsonb, 'Generally no — under the rule of capture a landowner may capture groundwater beneath his land even to a neighbor''s detriment, without liability.', 'H&TC Ry. v. East adopted the rule of capture; generally there is no liability for draining a neighbor''s well by pumping. Prior appropriation governs SURFACE water, not groundwater, and reasonable-use is the rule Texas notably rejected for groundwater.', 'hard', 'd2920000-0000-0000-0000-000000000006', 'd2920610-0000-0000-0000-000000000006', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920660-0000-0000-0000-000000000001', 'An original GLO field note reports the average bed width of a stream, cut bank to cut bank, as {{wvrs:f2}} varas. Convert this average width to feet to apply the Texas statutory navigability test of Tex. Nat. Res. Code §21.001(3). (1 vara = 33⅓ in = 2.77778 ft.) What is the average bed width in feet?', 'numeric_input', '[]'::jsonb, '0', 'Convert varas to feet (× 2.77778): {{wvrs:f2}} vrs = {{_answer}} ft. Under §21.001(3) the stream is statutorily navigable (State-owned bed, gradient boundary) only if this average bed width is at least 30 ft; otherwise it is non-navigable and owners take to the center thread.', 'easy', 'd2920000-0000-0000-0000-000000000006', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920650-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920660-0000-0000-0000-000000000002', 'Three riparian owners share one side of a slowly accreting shore. Their ORIGINAL frontages on the old waterline are A = {{fa:f2}} ft, B = {{fb:f2}} ft, and C = {{fc:f2}} ft. Accretion has lengthened the NEW waterline to {{lnew:f2}} ft total. Using the proportionate-shoreline method (new frontage split in the same ratio as old frontage), how many feet of the NEW waterline are allotted to owner B?', 'numeric_input', '[]'::jsonb, '0', 'The proportionate-shoreline method (Johnston v. Jones; BLM Manual) gives each owner the same share of the NEW waterline as of the OLD. B''s share = (B''s frontage ÷ total old frontage) × new waterline = ({{fb:f2}} ÷ {{ftot:f2}}) × {{lnew:f2}} = {{_answer}} ft.', 'medium', 'd2920000-0000-0000-0000-000000000006', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920650-0000-0000-0000-000000000002', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920660-0000-0000-0000-000000000003', 'Gradual accretion has built a band of new land in front of a riparian lot. The lot''s water frontage is {{front:f2}} ft and the new alluvion extends an average of {{depth:f2}} ft outward from the old waterline to the new one. Treating the band as frontage × average depth, how many ACRES of accreted land has the riparian owner gained? (1 acre = 43,560 sq ft.)', 'numeric_input', '[]'::jsonb, '0', 'Accretion gradually added land that belongs to the upland owner. Area = frontage × average accretion depth = {{front:f2}} × {{depth:f2}} = {{area_sf:f2}} sq ft = {{_answer}} acres (÷ 43,560).', 'medium', 'd2920000-0000-0000-0000-000000000006', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920650-0000-0000-0000-000000000003', 0.005);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('d2920610-0000-0000-0000-000000000007', 'd2920000-0000-0000-0000-000000000006', 'Homework & Practice', '', ARRAY[]::text[], 7, 45, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, 'Module homework assignment(s) and practice problems.', ARRAY[]::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0007-0000-0000-000000000000', 'd2920610-0000-0000-0000-000000000007', 'text', '{"html":"<h2>Homework &amp; Practice</h2><p>Complete the homework below. You may submit a draft up to 48 hours before the deadline for instructor feedback. Use the randomized practice problems to prepare for the quiz.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0007-0000-0000-000000000001', 'd2920610-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Homework 1 — Fisherman Acres: Water Boundaries and Shoreline Change</h3><p><em>Type: written</em></p><div>Use the Fisherman Acres Subdivision diagram (provided) to answer the problems below. **Answer ONLY FIVE of the six problems (1–6).** Each is worth 2 points: one point for the answer, one for the explanation. For each, state the rule and apply it to the facts.<br/><br/>> **Authority note.** Apply general water-boundary doctrine. For any problem turning on a code rule, you may reference **California Civil Code §§670 and 830** as a comparison model: §670 — the State owns land below ordinary high-water mark bordering tidewater and below a navigable lake or stream; §830 — absent contrary grant intent, the upland owner takes to ordinary high-water mark on tidewater, to low-water mark on a non-tidal navigable lake/stream, and to the **middle** of any other (non-navigable) water. **Then contrast the result with the Texas rule** (gradient boundary on navigable streams; medium filum aquae on non-navigable streams; State-owned navigable beds) so you can see how the choice of jurisdiction changes the boundary.<br/><br/>1. The deeds for **Lot B** and **Lot E** both call to **Salmon River**. If the channel **gradually** changed location, what effect, if any, would this have on the common boundary of the two lots? Briefly explain.<br/><br/>2. The deeds for **Lot B** and **Lot E** both call to **Salmon River**. The channel changed location during the **1997 ''El Niño'' flood** (an avulsive event). What effect, if any, would this have on the common boundary? Briefly explain.<br/><br/>3. The deed for **Lot A** calls to **Bass Bay**. Describe the **northerly** property line of Lot A. Briefly explain.<br/><br/>4. The deed for **Lot C** calls to **Trout Lake**. Describe the **southerly** boundary of Lot C. Briefly explain.<br/><br/>5. The deeds for **Lot C** and **Lot D** both call to **Bear Creek**. Describe the **easterly** boundary of Lot C. Briefly explain.<br/><br/>6. If **Pike Island** was formed during the **1997 ''El Niño'' flood**, who would own the island? Briefly explain.<br/><br/>**In your write-up, for every answer add one sentence stating how the result would change (or not) if the parcel were in Texas** — e.g., a navigable Salmon River bed would be State-owned with the private boundary at the gradient boundary, and an avulsively formed Pike Island would stay with the pre-flood bed owner.</div>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920620-0007-0000-0000-000000000002', 'd2920610-0000-0000-0000-000000000007', 'text', '{"html":"<h3>Homework 2 — Parcels A–G: Describing the Water Boundary Line</h3><p><em>Type: written</em></p><div>Use the parcel diagram (provided). **For only FIVE of parcels A through G**, (i) **describe the water boundary line** of that parcel, and (ii) **where applicable, describe any limitations on ownership** (for example, a State-owned bed, a public-trust easement, public navigation rights, a mineral reservation, or a use-permit requirement). 2 points each.<br/><br/>For each parcel you choose, structure your answer as:<br/><br/>- **Classify the water.** Riparian (flowing stream) or littoral (lake/sea/Gulf)? Navigable or non-navigable? Tidal or non-tidal?<br/>- **Locate the boundary.** State the exact line (e.g., **medium filum aquae** / center thread for a non-navigable stream; the **gradient boundary** for a navigable Texas stream; **mean high tide** for a Texas tidal grant or **mean higher high water** for a Spanish/Mexican tidal grant; low-water or high-water mark as the diagram and any stated jurisdiction require).<br/>- **Note ownership limits.** E.g., the State owns the bed of a navigable stream (public trust); the 1929 Small Bill may have relinquished the bed surface but reserved minerals and public water rights; a Gulf-front parcel carries a TOBA public-beach easement to the vegetation line; surface-water USE requires a TCEQ appropriation permit even though the bank is privately owned.<br/><br/>Write each description as you would for an opinion to a client''s attorney: rule, application to the parcel, and conclusion.</div>"}'::jsonb, 2);
INSERT INTO learning_modules (id, title, description, difficulty, estimated_hours, order_index, status, tags, is_academic, acc_course_id, is_published, review_status, estimated_minutes, difficulty_level)
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0001-0000-0000-000000000000', 'd2920710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What a description has to do</h3><p>A <strong>metes-and-bounds description</strong> is a written instrument that fixes the limits of one unique parcel of land by reciting a continuous chain of measured lines around its perimeter, returning to where it began. The deed that contains it transfers an interest in real property, so the description carries a heavy burden: it <strong>must make the parties'' intentions clear, must positively identify and locate one unique parcel, and must specify that parcel''s size, shape, and position.</strong> If the lands are not sufficiently described, the conveyance can be <em>void for lack of locatability</em>. As Dr. Elgin puts it, practically all of our boundary problems can be traced back to poorly written descriptions — so the surveyor who crafts one must understand surveying math, the legal principles of boundary location, and the legal meaning of words and phrases.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0001-0000-0000-000000000001', 'd2920710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Metes vs. bounds</h3><p>The two halves of the name describe two different ways of fixing a line:</p><ul><li><strong>Metes</strong> are <em>measures</em> — the bearings (directions) and distances of consecutive lines: “thence N 42°10'' E, 247.27 feet.” A pure <strong>metes description</strong> fixes the parcel entirely by recited courses and distances. This pure form has little practical application today.</li><li><strong>Bounds</strong> are <em>adjoiners</em> — recital calls to record or physical lines, objects, or neighboring parcels that confine the parcel: “bounded on the south by State Highway No. 1; east by Freeman Addition.” A pure <strong>bounds description</strong> relies entirely on what surrounds the tract.</li></ul><p>Most modern descriptions are <strong>combination (metes-and-bounds) descriptions</strong>: they recite bearings and distances <em>together with</em> bounding references to adjoiners, right-of-way lines, and monuments, returning to the point of beginning. These are the easiest to write but the hardest to retrace, because the two kinds of call can conflict — which is exactly when the priority (dignity) of calls must be applied.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0001-0000-0000-000000000002', 'd2920710-0000-0000-0000-000000000001', 'table', '{"headers":["Type","How the boundary is fixed","Typical use"],"rows":[["Metes","Recited bearings and distances of consecutive lines","Rare today; historic field notes"],["Bounds","Recital calls to adjoiners / physical objects","Rare today by a professional surveyor"],["Metes & bounds (combination)","Courses + bounding references + monuments, back to POB","Most common after an original survey or resurvey"],["Aliquot part (PLSS)","Reference to a GLO sectional plat (“NW1/4 of the SE1/4”)","PLSS states — NOT Texas"],["Lot & block (by reference)","Reference to a recorded subdivision plat","Platted subdivisions"],["Strip","A width centered on a described centerline","Roads, right-of-way, and utility easements"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0001-0000-0000-000000000003', 'd2920710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The parts of a description</h3><p>A complete written description has a predictable skeleton, and writing or reading it in order keeps it unambiguous:</p><ul><li><strong>Caption (preamble).</strong> The opening statement of general location — county and state, city, and the larger tract within which the parcel lies. It locates the reader and <em>limits the extent</em> of what follows.</li><li><strong>Body.</strong> The working core: a tie to a point of commencement, the <strong>point of beginning (POB)</strong>, then the sequence of courses (calls for monuments, bearings and distances, and bounds), and a <strong>closing call</strong> back “to the point of beginning.”</li><li><strong>Area / quantity.</strong> A statement of acreage, almost always followed by “more or less.”</li><li><strong>Limiting and augmenting clauses.</strong> “EXCEPTING THEREFROM,” “RESERVING THEREFROM,” “SUBJECT TO,” and “TOGETHER WITH” clauses that withhold, reserve, recognize, or add rights.</li><li><strong>Basis of bearing and certification.</strong> The stated bearing datum and the surveyor''s seal/signature.</li></ul>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0001-0000-0000-000000000004', 'd2920710-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"A boundary line can be created by words in a legal document alone. That written line is as binding and as legal as if it had been run on the ground by a surveyor. This is why a description must be self-sufficient: words can create a boundary, so the words must be unambiguous."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0001-0000-0000-000000000005', 'd2920710-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Foundational principles</h3><p>A few settled principles govern how descriptions create and control boundaries:</p><ul><li><strong>Freedom to create, limited by others'' rights.</strong> A landowner may create any boundary desired <em>as long as it does not infringe on an adjoiner or a senior right.</em></li><li><strong>The original survey controls.</strong> The lines and corners of the <em>original</em> survey control the location of a parcel; lines are presumed run in accordance with the rules and minimum standards in existence <em>when they were created.</em></li><li><strong>Words speak as of their own date.</strong> Words, their meanings, and recited distances are interpreted as of the <em>date of the description</em>, not the date of a later retracement (so “varas” in an 1850 field note still means varas).</li><li><strong>Monuments must be called for.</strong> For a corner and its monument to control, the corner must be called for in the conveyance and the monument identified at the time the conveyance was made.</li><li><strong>Tax deeds are not source documents.</strong> Tax statements and tax deeds are incomplete and must not be relied on as the primary source of a property description.</li></ul>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0001-0000-0000-000000000006', 'd2920710-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A description must make intent clear, identify and locate one unique parcel, fix its size/shape/position, and not create gaps or overlaps — or the conveyance may be void.","Metes are measures (bearings and distances); bounds are adjoiners. Most modern descriptions combine the two.","Every description has a caption, a body (POC → POB → courses → closing call), an area statement, optional clauses, a basis of bearing, and certification.","Words alone can create a binding boundary; the lines and corners of the original survey control its location, interpreted as of the date written."]}'::jsonb, 6);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0002-0000-0000-000000000000', 'd2920710-0000-0000-0000-000000000002', 'text', '{"html":"<h3>The caption: getting located</h3><p>The <strong>caption</strong> (or preamble) is the first element of a description and appears first on the page. It recites the <em>general</em> location of the parcel and <em>limits the extent</em> of what the body may convey. In PLSS states a caption reads like “That part of the Northwest Quarter of the Northwest Quarter of Section 12, Township ___, Range ___, [County and State], described as follows:”. The caption also serves the title industry as an index entry. A well-formed caption is generally descriptive of the area but includes enough information that there is <em>no possibility of mis-locating the land.</em></p><p>The caption and body interact. In general the <strong>body controls if it conflicts with the caption</strong> (the body is the “more particularly described” part, and the particular controls the general). But a caption can be <em>limiting</em>: if it says “All that part of the NW1/4 of the NW1/4 … described as follows,” a body that wanders beyond that quarter-quarter may not convey the extra land, because the caption sounds limiting.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0002-0000-0000-000000000001', 'd2920710-0000-0000-0000-000000000002', 'callout', '{"type":"warning","text":"Texas differs (PLSS): Texas has no township–range PLSS grid. Texas land was never federal public domain; titles trace to a sovereign grant (Spain, Mexico, the Republic, or the State) administered by the General Land Office. So a Texas caption is keyed to the original land-grant survey and abstract number — e.g., “situated in the John Doe Survey, Abstract No. 123, [County] County, Texas” — not to Section/Township/Range. The abstract number is the spine of Texas land identification."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0002-0000-0000-000000000002', 'd2920710-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Commencing versus beginning</h3><p>Descriptions distinguish two starting points:</p><ul><li>A <strong>point of commencement (POC)</strong> is a well-established, easily found point on the ground — often a section/survey corner or other monument of record — that <em>may not be a corner of the parcel.</em> You commence there because it is reliably locatable, then run a tie line to the parcel.</li><li>The <strong>point of beginning (POB)</strong> (sometimes “true point of beginning”) is an actual corner of the parcel being described. A description should have <strong>one and only one</strong> POB. If commencement is itself a corner of the parcel, you can note it is “being also the point of beginning.” If the description does not close back on the POB, the ending point is differentiated as a <strong>point of terminus (POT).</strong></li></ul><p>Modern guidance favors “Commencing at …” on essentially all descriptions, proceeding to the “Point of Beginning,” and reserving “BEGINNING” for the one true start. This avoids any confusion over which point is the true point of beginning.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0002-0000-0000-000000000003', 'd2920710-0000-0000-0000-000000000002', 'accordion', '{"sections":[{"title":"Worked caption + commencement (PLSS-style example from the slides)","content":"<p><em>“That part of the Northwest Quarter of the Northwest Quarter of Section 12, Township (number), Range (number), (County &amp; State) described as follows: Commencing at the northwest corner of said Northwest Quarter of the Northwest Quarter; thence on an assumed bearing of South 00 degrees 10 minutes 00 seconds West along the west line of said Northwest Quarter of the Northwest Quarter 330.00 feet to the point of beginning; thence South 89 degrees 50 minutes 00 seconds East 660.00 feet; … to the point of beginning.”</em></p><p>Notice the structure: caption (general location) → commencement at a found corner → a tie course (330.00 ft) to reach the <strong>POB</strong> → the body of courses → closing call. The “assumed bearing” phrase states the basis of bearing. In Texas, the caption would instead read “situated in the [grantee] Survey, Abstract No. ___, [County] County, Texas,” and the commencement would tie to a corner of that original GLO survey.</p>","open":false}]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0002-0000-0000-000000000004', 'd2920710-0000-0000-0000-000000000002', 'text', '{"html":"<h3>Tie to control — the Texas way</h3><p>A description is only as locatable as its tie to known control. By Texas convention the POB and at least one controlling corner are <strong>tied back to a corner of the original GLO survey/abstract</strong>, so the parcel can be re-located independently of the surveyor''s own work. The governing rule, 22 TAC §138.91, requires that courses be “referenced … to an identifiable and monumented line or an established geodetic system.” Today that basis of bearing is usually grid — the Texas State Plane Coordinate System on the NAD83 datum, by zone — while many historic descriptions used magnetic or assumed bearings (a known source of rotation discrepancies in retracement). The statutory hook is Occupations Code §1071.002, which defines “state land surveying” to include “determining by survey the location or relocation of original land grant boundaries and corners.”</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0002-0000-0000-000000000005', 'd2920710-0000-0000-0000-000000000002', 'key_takeaways', '{"title":"Key Takeaways","items":["The caption locates and limits the parcel; the body controls a conflicting caption, but a limiting caption can cap what the body conveys.","A POC is a reliably found point that may not be a parcel corner; the POB is the one true corner where the perimeter starts. Use “Commencing at” then “Point of Beginning.”","Texas captions key to the original GLO survey + abstract number, not Section/Township/Range — Texas has no PLSS grid.","Tie the POB and a controlling corner to the original survey and state the basis of bearing (today usually Texas State Plane / NAD83), per 22 TAC §138.91."]}'::jsonb, 5);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000000', 'd2920710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Two ways to state a direction</h3><p>A <strong>course</strong> is the direction of a line. Surveyors state direction two ways:</p><ul><li>A <strong>quadrant bearing</strong> is measured from the North–South meridian, never exceeding 90°, and named for its quadrant: <strong>N __° __'' __” E</strong> (or SE, SW, NW). Example: <em>N 42°10'' E</em> means 42°10'' east of due north.</li><li>An <strong>azimuth</strong> is measured clockwise from north through a full circle, 0° to 360°. North = 0° (or 360°), East = 90°, South = 180°, West = 270°.</li></ul><p>Deeds are written in bearings; computations are often easier in azimuths. You must move fluently between them.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000001', 'd2920710-0000-0000-0000-000000000003', 'table', '{"headers":["Quadrant","Bearing angle β (from N or S)","Azimuth from north"],"rows":[["NE","N β E","Az = β"],["SE","S β E","Az = 180° − β"],["SW","S β W","Az = 180° + β"],["NW","N β W","Az = 360° − β"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000002', 'd2920710-0000-0000-0000-000000000003', 'equation', '{"latex":"\\text{Az}_{\\text{back}} = \\text{Az}_{\\text{forward}} \\pm 180^{\\circ}","label":"Back-azimuth (reverse course): add 180° if the forward azimuth is < 180°, subtract 180° if it is ≥ 180°","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000003', 'd2920710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Worked conversion</h3><p>Take the course <strong>S 30° 00'' E</strong> (SE quadrant). Its azimuth is 180° − 30° = <strong>150°</strong>. Walking the line the other way (the <em>back course</em>), the azimuth is 150° + 180° = <strong>330°</strong>, which is N 30° 00'' W — the same line, opposite direction. A back bearing always flips both letters: the reverse of S 30° E is N 30° W. This matters because a deed line and the adjoiner''s deed line are the <em>same line described from opposite ends</em>; they should be exact reverses.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000004', 'd2920710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Latitude and departure</h3><p>Every course can be resolved into two rectangular components: its <strong>latitude</strong> (north–south component, +N / −S) and its <strong>departure</strong> (east–west component, +E / −W). Using the bearing <em>angle</em> β (the number in the quadrant bearing) and the distance <em>D</em>:</p><ul><li><strong>Latitude = D × cos β</strong> (sign: + for a North bearing, − for a South bearing)</li><li><strong>Departure = D × sin β</strong> (sign: + for an East bearing, − for a West bearing)</li></ul><p>Latitudes and departures are the bridge from a written course to coordinates: add a course''s latitude to a point''s northing and its departure to the easting to get the next point. They are also the basis of the closure check in the next lesson.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000005', 'd2920710-0000-0000-0000-000000000003', 'equation', '{"latex":"\\text{Lat} = D\\cos\\beta \\qquad \\text{Dep} = D\\sin\\beta","label":"Latitude and departure of a course (β = quadrant bearing angle, D = distance)","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000006', 'd2920710-0000-0000-0000-000000000003', 'text', '{"html":"<h3>Sequencing the body</h3><p>The body recites the calls <strong>in order</strong>, running around the perimeter in either a clockwise or a counter-clockwise direction, with each course beginning “thence” (“then from there”). A few craft rules from the standards:</p><ul><li>State the basis of bearing.</li><li>Run consistently one direction around the figure; do not jump around.</li><li>Bearings and distances are sometimes called <em>finger pointings</em> — they tell the retracing surveyor where to look for the actual corner/monument that controls.</li><li>End every course with a semicolon; the caption ends with a colon; the whole description ends with a period.</li><li>Spell bearings out and capitalize them; do not capitalize a general directional word like “northerly.” Follow the area with “more or less.”</li></ul>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', 'callout', '{"type":"info","text":"“More or less” after a distance or area is deliberate: it signals that the figure is a supporting (informative) call, not a controlling bound, so that a found monument can still control over the recited number. Surveyors often treat bearings and distances as guides to the controlling monuments rather than as the boundary itself."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0003-0000-0000-000000000008', 'd2920710-0000-0000-0000-000000000003', 'key_takeaways', '{"title":"Key Takeaways","items":["A quadrant bearing is N/S __° E/W (≤ 90°); an azimuth is clockwise from north 0–360°. Convert by quadrant; the back course is azimuth ± 180° and flips both bearing letters.","Latitude = D·cosβ (± N/S) and Departure = D·sinβ (± E/W) resolve a course into N–S and E–W components and let you carry coordinates around the parcel.","The body runs the calls in order, clockwise or counter-clockwise, each starting “thence,” with a stated basis of bearing.","Bearings/distances are “finger pointings” to the controlling monuments; “more or less” keeps recited numbers from outranking a found monument."]}'::jsonb, 8);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000000', 'd2920710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Closure: the figure must come back</h3><p>A metes-and-bounds description traces a closed polygon. If you start at the POB, sum every course''s latitude and every course''s departure, and walk all the way around, you should end exactly back at the POB. In a perfect figure the sum of all latitudes is zero and the sum of all departures is zero. In a real (or recited) traverse they rarely close perfectly; the small leftover is the <strong>misclosure.</strong></p><ul><li><strong>Closure in latitude</strong> = ΣLat (should be 0)</li><li><strong>Closure in departure</strong> = ΣDep (should be 0)</li><li><strong>Linear misclosure</strong> = √(ΣLat² + ΣDep²) — the straight-line gap between the computed end point and the POB</li></ul><p>A description that does not mathematically close, with no gap or overlap, is legally defective. (The deed in <em>Karr v. Ray</em> literally would not close until the parties agreed two bearings had been written W instead of E.)</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000001', 'd2920710-0000-0000-0000-000000000004', 'equation', '{"latex":"\\text{Linear misclosure} = \\sqrt{\\left(\\textstyle\\sum \\text{Lat}\\right)^2 + \\left(\\textstyle\\sum \\text{Dep}\\right)^2}","label":"Linear misclosure of a traverse","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000002', 'd2920710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>The three sufficiency requirements</h3><p>To be legally sufficient a description must satisfy three tests, all reinforced by 22 TAC §138.91, which requires “a definite and unambiguous identification of the location of such boundaries”:</p><ul><li><strong>It must close.</strong> The calls must return to the POB forming a closed figure with no gap or overlap. For a Texas Category 1A survey a separate <em>closure report</em> is submitted, and traverse/closure tolerances are set by 22 TAC §138.83 (Precision and Accuracy) and the TSPS Manual of Practice.</li><li><strong>It must be locatable.</strong> A competent surveyor must be able to go to the ground and re-establish the lines from the writing — which requires a tie to control, monument calls, and a basis of bearing.</li><li><strong>It must be unambiguous.</strong> It must describe one and only one parcel, with intent clear on its face.</li></ul>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000003', 'd2920710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Ambiguity, and how it is cured</h3><p>Classic doctrine distinguished a <strong>latent ambiguity</strong> (not visible on the face of the description but appearing when it is applied to the ground — curable with extrinsic evidence) from a <strong>patent ambiguity</strong> (an ambiguity so severe the parties'' intent cannot be determined). The modern tendency is to <em>uphold</em> the validity of a deed if it is at all possible to arrive at the parties'' intent, and to allow almost any extrinsic evidence to help <em>locate</em> the lands described — not to change what is written, but to aid in locating it.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000004', 'd2920710-0000-0000-0000-000000000004', 'table', '{"headers":["Common defect","Why it is a problem"],"rows":[["Does not close","Leaves a gap/overlap; figure is mathematically and legally defective"],["No tie to control / no basis of bearing","Not locatable; cannot be re-established on the ground"],["A corner placed on a curved line","A boundary (property) corner should not be set on a curved line"],["Relying on a tax deed","Tax deeds are incomplete and are not a proper source description"],["Conflicting calls (monument vs. bearing vs. distance)","Requires applying the dignity of calls to resolve"],["Vague/gone monument (“the old oak”)","Latent ambiguity; needs extrinsic evidence or may fail"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000005', 'd2920710-0000-0000-0000-000000000004', 'text', '{"html":"<h3>Dignity of calls — the tie-breaker</h3><p>When calls in one description conflict, they are ranked by reliability (“dignity”), highest to lowest: <strong>natural monuments → artificial monuments → adjoinder → course (bearing) → distance → quantity/area.</strong> This is a rule of construction that always yields to the parties'' <em>intent</em> and to the <em>footsteps of the original surveyor.</em> It is why a found, called-for, undisturbed monument controls over a conflicting distance, and why a stated acreage is the weakest call of all — a check, not a control.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000006', 'd2920710-0000-0000-0000-000000000004', 'accordion', '{"sections":[{"title":"Texas case: State v. Franks (113 S.W.2d 589, Tex. Civ. App. 1937) — footsteps & senior rights","content":"<p>The Texas court fixed the north line of the senior <strong>Ransom House Survey</strong> by crediting surveyor Atkinson, who “followed the footsteps of the original surveyor as carefully, closely, and accurately as might be expected,” while rejecting later surveys that did <em>not</em> follow those footsteps. The court restated the settled rule that <em>“a junior survey must be made to conform to and harmonize with the lines and calls for older surveys, because the boundaries of the older surveys cannot be extended or varied to satisfy the calls of a junior survey.”</em> The lesson for description-writing: a new junior description must respect the senior boundary and the original surveyor''s footsteps — it cannot enlarge itself by its own recited courses.</p>","open":false}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', 'callout', '{"type":"warning","text":"Texas standards note: The old 22 TAC Chapter 663 surveying standards were REPEALED. After HB 1523 (86th Leg., 2019) merged the surveying board into TBPELS, the standards were re-codified (eff. 2021) into 22 TAC Chapter 138, “Compliance and Professionalism for Surveyors.” The Professional and Technical Standards are in 22 TAC Ch. 138, Subchapter E (§§138.81 et seq.). Any material citing §663 is outdated for 2026."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0004-0000-0000-000000000008', 'd2920710-0000-0000-0000-000000000004', 'key_takeaways', '{"title":"Key Takeaways","items":["Sum the latitudes and departures; the linear misclosure = √(ΣLat² + ΣDep²). A description that will not close (no gap/overlap) is defective.","Sufficiency = close + locatable + unambiguous, all required by 22 TAC §138.91; closure tolerances live in §138.83 and the TSPS Manual.","The modern tendency favors upholding a deed and using extrinsic evidence to locate (not rewrite) ambiguous lands.","When calls conflict, apply the dignity of calls (natural → artificial → adjoinder → course → distance → area), subordinate to intent and the original surveyor''s footsteps."]}'::jsonb, 8);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives)
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000000', 'd2920710-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Vara-based historic descriptions</h3><p>Many original Texas field notes are written in <strong>varas</strong> (abbreviated “vrs.”). Texas law fixed the vara at <strong>exactly 33⅓ inches</strong> by Art. 5730, Revised Civil Statutes (Acts of 1919, eff. June 17, 1919). Because words and distances speak as of the date written, a retracing surveyor must convert the historic varas to feet — and must reconcile the often magnetic or assumed historic bearing basis to a modern datum.</p><ul><li>1 vara = 33⅓ in = <strong>2.7778 ft</strong> (equivalently, varas × 2.7778 = feet; feet × 0.36 = varas)</li><li>Example: “S 45° E, 950 vrs” = 950 × 2.7778 ≈ <strong>2,638.9 ft</strong></li></ul><p>Larger historic units: 1 labor = 1,000,000 sq varas ≈ 177.1 acres; 1 league (sitio) = 25 labors ≈ 4,428 acres.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000001', 'd2920710-0000-0000-0000-000000000005', 'callout', '{"type":"warning","text":"Texas differs: The vara is essentially unique to Texas and former Spanish-grant areas. Its historical value varied (Spanish “Vara de Burgos” ~32.9 in; Mexican vara ~32.99 in), but Texas statutorily uses 33⅓ in. Do not blindly apply a foreign vara value to a Texas grant — the resulting acreage will be wrong."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000002', 'd2920710-0000-0000-0000-000000000005', 'equation', '{"latex":"\\text{feet} = \\text{varas} \\times 2.7778 \\qquad \\text{varas} = \\text{feet} \\times 0.36","label":"Vara ↔ feet (Texas statutory vara = 33⅓ in)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000003', 'd2920710-0000-0000-0000-000000000005', 'text', '{"html":"<h3>The General Land Office</h3><p>The <strong>General Land Office (GLO)</strong> is the custodian of Texas''s original land-grant records — patents, field notes, sketches, and maps — dating to the Spanish/Mexican period. A surveyor retracing an original survey must consult the GLO record to locate the <em>original grant boundaries and corners</em>, then follow the original surveyor''s footsteps on the ground. A <strong>patent</strong> is the instrument that severs land from the sovereign. Original surveys of state land, and corrections to original grant boundaries, require a <strong>Licensed State Land Surveyor (LSLS)</strong>, a higher GLO-issued credential than RPLS.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000004', 'd2920710-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Who may write a description, and under what standards</h3><p>The governing statute is Occupations Code Chapter 1071 (the Professional Land Surveying Practices Act). Only a <strong>Registered Professional Land Surveyor (RPLS)</strong> (or an LSLS) may prepare a metes-and-bounds description, delineate and monument boundaries, and seal and sign the survey. The administrative standards are in <strong>22 TAC Part 6, Chapter 138</strong>, with the Professional and Technical Standards in Subchapter E:</p><ul><li><strong>§138.83</strong> — Precision and Accuracy (traverse/positional tolerances; closure)</li><li><strong>§138.87</strong> — Monumentation (set monuments of a stable, permanent nature; document found vs. set, marked traceably to the registrant)</li><li><strong>§138.91</strong> — Survey Drawing / Written Description / Report (unambiguous identification; state which monuments were found and which placed; reference courses to a monumented line or geodetic system)</li></ul><p>Survey categories (such as the highest-standard <strong>Category 1A</strong> land-title survey) are defined by the TSPS Manual of Practice, which the TBPELS rules incorporate by reference.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000005', 'd2920710-0000-0000-0000-000000000005', 'text', '{"html":"<h3>Closing clauses, area, and certification</h3><p>After the body closes back to the POB, finish the description with the proper appendages:</p><ul><li><strong>Area:</strong> “containing 22.99 acres, more or less.” Texas treats stated area as the least reliable element — a check, not a control.</li><li><strong>EXCEPTING THEREFROM</strong> withholds a part not intended to be conveyed (an important device for preserving a senior right — an exception is always part of the thing granted).</li><li><strong>RESERVING THEREFROM</strong> keeps a right or easement for the grantor or a stated third party (a reservation is a newly created thing).</li><li><strong>SUBJECT TO</strong> recognizes an existing right (a mineral right, recorded easement, etc.); <strong>TOGETHER WITH</strong> adds an appurtenant right.</li><li><strong>Call for the survey:</strong> modern practice ends with “… per plat of Survey No. ____ dated __/__/____ by ____ Surveying,” plus the basis of bearing and the surveyor''s seal and signature.</li></ul>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000006', 'd2920710-0000-0000-0000-000000000005', 'accordion', '{"sections":[{"title":"Model description (adapted from a surveyed tract)","content":"<p><em>“A fractional part of the [grantee] Survey, Abstract No. ___, [County] County, Texas, described as follows: Commencing at [a found corner of said survey]; thence [tie course] to a point on the [right-of-way / adjoiner line], the point of beginning of the herein described tract; thence N 87°17'' W, 1002.20 feet along [said north line]; thence S 1°10'' E, 611.11 feet along [said corporate limits]; thence S 73°51''30” E, 667.58 feet to the aforesaid [right-of-way]; thence northerly, 972.40 feet along the arc of a curve, concave westerly, with a radius of 975.00 feet, the chord of which is N 1°45'' W, 932.60 feet, all along said right-of-way to the point of beginning. Above described tract contains 22.99 acres, more or less, per plat of Survey Number ____ dated [date], by [firm]. Basis of bearing: Texas State Plane, NAD83. END OF DESCRIPTION.”</em></p><p>Note the structure: Texas caption (survey + abstract) → commencement at a found corner → POB at an adjoiner → ordered courses (including a curve recited by arc, radius, and chord) bounding on a road right-of-way → closing call → area “more or less” → call for the survey → basis of bearing → certification.</p>","open":false}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', 'link_reference', '{"links":[{"url":"https://texreg.sos.state.tx.us/public/readtac$ext.ViewTAC?tac_view=4&ti=22&pt=6&ch=138","title":"22 TAC Part 6, Ch. 138 — Compliance and Professionalism for Surveyors","type":"website","description":"TBPELS surveying standards (Subch. E: Professional and Technical Standards, §§138.81 et seq.) — current 2026 chapter; replaces repealed Ch. 663"},{"url":"https://statutes.capitol.texas.gov/Docs/OC/htm/OC.1071.htm","title":"Tex. Occupations Code Ch. 1071 — Professional Land Surveying Practices Act","type":"website","description":"Licensure (RPLS / LSLS) and definitions, incl. §1071.002 (“state land surveying”)"},{"url":"https://www.glo.texas.gov/history/archives/","title":"Texas General Land Office — Land Grant Archives","type":"website","description":"Custodian of original Spanish/Mexican/Republic/State grants, patents, and field notes"}]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0005-0000-0000-000000000008', 'd2920710-0000-0000-0000-000000000005', 'key_takeaways', '{"title":"Key Takeaways","items":["Texas field notes in varas convert at 1 vara = 2.7778 ft (feet × 0.36 = varas); use the statutory 33⅓-in vara, never a foreign value, and reconcile the historic bearing basis.","The GLO holds the original grant records a retracing surveyor must consult; state-land originals require an LSLS, and patents sever land from the sovereign.","Only an RPLS/LSLS may prepare and seal a Texas description, under 22 TAC Ch. 138 Subch. E (§§138.83, .87, .91) — not the repealed §663.","Finish with the area “more or less,” the right EXCEPTING/RESERVING/SUBJECT TO/TOGETHER WITH clauses, a call for the survey, the basis of bearing, and certification."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000001', 'Metes-and-bounds description', 'A written description that fixes a unique parcel by reciting a continuous series of bearings, distances, monuments, and bounding calls around the perimeter, returning to the point of beginning.', 'Metes = measures; bounds = adjoiners.', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000002', 'Metes', 'The measures of a description — the bearings (directions) and distances of the consecutive lines that make up the perimeter.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000003', 'Bounds', 'Recital calls to record or physical lines, objects, or adjoining parcels that confine (bound) the limits of the tract being described.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000004', 'Caption (preamble)', 'The opening statement of a description reciting the general location (county/state, city, larger tract) and limiting the extent of what follows in the body.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000005', 'Combination metes-and-bounds description', 'A description that recites bearings and distances together with bounding references to adjoiners, right-of-way, and monuments — the most common modern form, and the one where priority of calls matters most.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000006', 'Point of commencement (POC)', 'A well-established, easily found point on the ground used to start a description; it may not be an actual corner of the parcel. A tie course leads from the POC to the point of beginning.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000007', 'Point of beginning (POB)', 'An actual corner of the parcel being described, where the perimeter run starts and to which it closes. A description should have exactly one POB.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000008', 'Point of terminus (POT)', 'The differentiated ending point used when a description (such as a strip or line description) does not close back on the same point at which it began.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000009', 'Abstract number', 'The identifying number the Texas GLO assigns to an original land-grant survey; it is the spine of Texas land identification and is recited in the caption of a Texas description (e.g., “Abstract No. 123”).', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000010', 'Basis of bearing', 'The stated reference to which all bearings in a description are oriented — an identifiable monumented line or an established geodetic system (today, commonly the Texas State Plane Coordinate System, NAD83); must be stated per 22 TAC §138.91(c).', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000011', 'Quadrant bearing', 'A direction measured from the north or south meridian, not exceeding 90°, named for its quadrant: N __° __'' __” E, S __ E, S __ W, or N __ W.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000012', 'Azimuth', 'A direction measured clockwise from north through a full 360° circle (N=0°, E=90°, S=180°, W=270°).', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000013', 'Back azimuth (back bearing)', 'The direction of a line viewed from the opposite end: azimuth ± 180°. The back bearing reverses both letters (the reverse of S 30° E is N 30° W).', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000014', 'Latitude (of a course)', 'The north–south component of a course, equal to distance × cos(bearing angle); positive for North bearings, negative for South.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000015', 'Departure (of a course)', 'The east–west component of a course, equal to distance × sin(bearing angle); positive for East bearings, negative for West.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000016', 'Thence', '“Then from there” — the word that introduces each successive course in the body of a description.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000017', 'Closure', 'The requirement that a description''s courses return exactly to the point of beginning, forming a closed figure; in a perfect traverse ΣLat = 0 and ΣDep = 0.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000018', 'Linear misclosure', 'The straight-line gap between the computed end point of a traverse and the point of beginning, equal to √(ΣLat² + ΣDep²).', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000019', 'Sufficiency (of a description)', 'The three legal requirements that a description must close, must be locatable on the ground, and must unambiguously describe one unique parcel.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000020', 'Latent vs. patent ambiguity', 'Latent ambiguity does not appear on the face of a description but emerges when it is applied (curable with extrinsic evidence); patent ambiguity is so severe the parties'' intent cannot be determined.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000021', 'Dignity (priority) of calls', 'The reliability ranking used to resolve conflicting calls: natural monuments > artificial monuments > adjoinder > course (bearing) > distance > quantity/area — all subordinate to intent and the original surveyor''s footsteps.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000022', 'Category 1A survey', 'The highest-standard boundary/land-title survey in Texas (defined by the TSPS Manual of Practice and incorporated by the TBPELS rules); requires a certification of substantial compliance and a separate closure report.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000023', 'Vara', 'The historic Texas unit of length, fixed by statute at exactly 33⅓ inches (2.7778 ft); abbreviated “vrs.” in field notes. 1 labor = 1,000,000 sq varas ≈ 177.1 ac; 1 league ≈ 4,428 ac.', '36 varas = exactly 100 ft; feet × 0.36 = varas.', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000024', 'Patent', 'The instrument that severs land from the sovereign (the State of Texas or, historically, the Republic), completing an original land grant; issued and archived by the GLO.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000025', 'Licensed State Land Surveyor (LSLS)', 'A higher GLO-issued Texas credential (above RPLS) required to survey land in which the State or Permanent School Fund has an interest and to relocate original land-grant boundaries and corners.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000026', 'EXCEPTING THEREFROM', 'A clause that withholds from the conveyance a part of the thing granted (always part of the described tract); an important device for preserving a senior right.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000027', 'RESERVING THEREFROM', 'A clause by which the grantor keeps a newly created right or easement (for the grantor or a stated third party) out of the land conveyed.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('d2920740-0000-0000-0000-000000000028', '22 TAC Chapter 138', 'The current (2021–) Texas Administrative Code chapter “Compliance and Professionalism for Surveyors”; its Subchapter E (§§138.81 et seq.) holds the surveying standards — it replaced the repealed Ch. 663.', NULL, 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', 'land-law', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000001', 'In a land description, what is the difference between “metes” and “bounds”?', 'multiple_choice', '["Metes are the measures (bearings and distances); bounds are the adjoiners (calls to neighboring lines/objects)","Metes are natural monuments; bounds are artificial monuments","Metes are the area; bounds are the perimeter","Metes are used in Texas; bounds are used only in PLSS states"]'::jsonb, 'Metes are the measures (bearings and distances); bounds are the adjoiners (calls to neighboring lines/objects)', 'Metes = measures (the bearings and distances of consecutive lines); bounds = adjoiners (recital calls to record/physical lines or neighboring parcels). The other options confuse these with monuments, area, or jurisdiction.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000002', 'A deed''s metes-and-bounds description is so vague that a surveyor cannot locate the parcel on the ground. What is the most serious legal consequence?', 'multiple_choice', '["The conveyance may be void for lack of locatability","The grantor automatically keeps the minerals","The acreage controls over all other calls","The county must re-survey the parcel for free"]'::jsonb, 'The conveyance may be void for lack of locatability', 'Every conveyance of real property requires a sufficient description; if the lands are not sufficiently described the conveyance can be void for lack of locatability. The other options are not legal consequences of an insufficient description.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000003', 'True or False: A boundary line created only by words in a legal document is less binding than one a surveyor physically runs on the ground.', 'true_false', '["True","False"]'::jsonb, 'False', 'A boundary line may be created by words in a legal document, and that line is as binding and as legal as if it had been run on the ground by a surveyor. This is exactly why descriptions must be unambiguous.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000004', 'Which document should a surveyor NOT rely on as the primary source of a property description?', 'multiple_choice', '["A tax statement or tax deed","A warranty deed","A recorded subdivision plat","An original GLO field note"]'::jsonb, 'A tax statement or tax deed', 'Tax statements and tax deeds are not complete deeds; they must not be used as the basis for a survey or legal document or as the primary source of a property description. The other three are proper source documents.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000001', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000005', 'A description reads “Commencing at the northwest corner of said survey; thence S 00°10'' W, 330.00 feet to the point of beginning; thence …” Which statement is correct?', 'multiple_choice', '["The northwest corner is the point of commencement and is not a corner of the parcel; the parcel begins 330 ft away at the POB","The northwest corner is the point of beginning and a corner of the parcel","There are two points of beginning in this description","The 330.00-foot course is a perimeter boundary of the parcel"]'::jsonb, 'The northwest corner is the point of commencement and is not a corner of the parcel; the parcel begins 330 ft away at the POB', '“Commencing at” marks the POC (a reliably found point, here a survey corner), and the 330-ft tie course leads to the POB — the first true corner of the parcel. The tie course is not part of the perimeter, and a description has only one POB.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000006', 'Why does a Texas caption recite an original survey name and an abstract number instead of Section/Township/Range?', 'multiple_choice', '["Texas land was never federal public domain, so it has no PLSS grid; titles are keyed to original GLO land-grant surveys and abstract numbers","Texas law forbids using the metric system","Abstract numbers are easier to remember than section numbers","Section/Township/Range is reserved for water boundaries in Texas"]'::jsonb, 'Texas land was never federal public domain, so it has no PLSS grid; titles are keyed to original GLO land-grant surveys and abstract numbers', 'Texas retained its public lands at annexation and was never federal public domain, so it has no township–range PLSS grid. Land is organized by original land-grant surveys administered by the GLO, identified by abstract number, which the caption recites.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000007', 'Under 22 TAC §138.91, the courses in a description must be referenced to what?', 'multiple_choice', '["An identifiable and monumented line or an established geodetic system","The surveyor''s truck odometer","The nearest interstate highway","Magnetic north only"]'::jsonb, 'An identifiable and monumented line or an established geodetic system', '22 TAC §138.91(c) requires courses to be referenced to an identifiable and monumented line or an established geodetic system (today commonly the Texas State Plane Coordinate System, NAD83). Magnetic north alone is the historic, less reliable basis the rule moved away from.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000008', 'When a limiting caption (“All that part of the NW1/4 of the NW1/4 … described as follows”) conflicts with a body that runs beyond that quarter-quarter, what is the likely result?', 'multiple_choice', '["The limiting caption may cap the conveyance, so the land beyond the quarter-quarter may not pass","The body always controls, so all the extra land passes regardless","The deed is automatically void","The acreage statement decides the conflict"]'::jsonb, 'The limiting caption may cap the conveyance, so the land beyond the quarter-quarter may not pass', 'Although the body generally controls a conflicting caption, a caption that sounds limiting (“all that part of …”) can restrict what is conveyed; land beyond the recited quarter-quarter may not pass even if the body describes it.', 'hard', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000002', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000009', 'Convert the bearing S 35° 00'' W to an azimuth measured clockwise from north.', 'numeric_input', '[]'::jsonb, '215', 'A southwest bearing converts as Az = 180° + β = 180° + 35° = 215°.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000010', 'A course has a forward azimuth of 70°. What is its back azimuth?', 'numeric_input', '[]'::jsonb, '250', 'Because the forward azimuth is less than 180°, add 180°: 70° + 180° = 250°.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000011', 'The reverse (back) bearing of a line whose forward bearing is N 22° 30'' E is:', 'multiple_choice', '["S 22° 30'' W","N 22° 30'' W","S 67° 30'' W","N 67° 30'' E"]'::jsonb, 'S 22° 30'' W', 'A back bearing keeps the same angle but flips both letters: the reverse of N 22°30'' E is S 22°30'' W (the same line viewed from the opposite end).', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000012', 'For a course bearing N 60° 00'' E with a distance of 200.00 ft, which expressions give its latitude and departure?', 'multiple_choice', '["Lat = 200·cos 60° (north), Dep = 200·sin 60° (east)","Lat = 200·sin 60° (north), Dep = 200·cos 60° (east)","Lat = 200·tan 60°, Dep = 200·cot 60°","Lat = 200·cos 60° (east), Dep = 200·sin 60° (north)"]'::jsonb, 'Lat = 200·cos 60° (north), Dep = 200·sin 60° (east)', 'Latitude (N–S component) = D·cosβ and departure (E–W component) = D·sinβ, where β is the bearing angle. The N and E signs come from the NE quadrant.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000013', 'Compute the departure (east–west component, in feet) of a course bearing N 53° 00'' E for a distance of 150.00 ft. Report magnitude to two decimals.', 'numeric_input', '[]'::jsonb, '119.80', 'Departure = D·sinβ = 150.00 × sin(53°) = 150.00 × 0.79864 ≈ 119.80 ft (eastward, since the bearing is to the East).', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000014', 'True or False: In a quadrant bearing such as N 42°10'' E, the angle 42°10'' is measured from due East.', 'true_false', '["True","False"]'::jsonb, 'False', 'A quadrant bearing is measured from the north or south meridian, not from east or west. N 42°10'' E is 42°10'' measured east of due north.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000003', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000015', 'A traverse has ΣLat = +0.30 ft and ΣDep = −0.40 ft. What is the linear misclosure (ft, two decimals)?', 'numeric_input', '[]'::jsonb, '0.50', 'Linear misclosure = √(ΣLat² + ΣDep²) = √(0.30² + 0.40²) = √(0.09 + 0.16) = √0.25 = 0.50 ft.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000016', 'Which three requirements must a metes-and-bounds description satisfy to be legally sufficient?', 'multiple_choice', '["It must close, be locatable on the ground, and be unambiguous","It must be notarized, recorded, and indexed","It must state the price, the date, and the grantor","It must use varas, list minerals, and avoid curves"]'::jsonb, 'It must close, be locatable on the ground, and be unambiguous', 'Sufficiency requires that the description close (no gap/overlap), be locatable by a competent surveyor, and unambiguously describe one parcel — all reinforced by 22 TAC §138.91. The other lists describe recording mechanics or unrelated content.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000017', 'Which call is the WEAKEST (lowest dignity) when calls in one description conflict?', 'multiple_choice', '["Quantity / area","Natural monument","Artificial monument","Course (bearing)"]'::jsonb, 'Quantity / area', 'The dignity of calls ranks natural monument > artificial monument > adjoinder > course > distance > quantity/area. Stated acreage is the least reliable — a check, not a control.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000018', 'A called-for, identifiable, undisturbed iron pipe is found 4.1 ft beyond the record distance of 300.00 ft along the same bearing. Applying the dignity of calls, what controls the corner location?', 'multiple_choice', '["The found monument (the corner is held at the pipe, ~304.1 ft)","The record distance (the corner is held at exactly 300.00 ft)","The stated area of the parcel","The midpoint between the pipe and the record distance"]'::jsonb, 'The found monument (the corner is held at the pipe, ~304.1 ft)', 'An artificial monument that is called for, identifiable, and undisturbed controls over a conflicting distance. The corner is held at the found pipe; the record 300.00 ft becomes controlling only if the monument is lost.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000019', 'True or False: In Texas, the current surveying standards of practice are found in 22 TAC §663.', 'true_false', '["True","False"]'::jsonb, 'False', 'Chapter 663 was repealed. After HB 1523 (2019) created TBPELS, the standards were re-codified into 22 TAC Chapter 138 (Subch. E, §§138.81 et seq.), effective 2021. Citing §663 in 2026 is outdated.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000020', 'In State v. Franks (Tex. Civ. App. 1937), which surveyor''s work did the court credit in fixing the senior survey''s north line?', 'multiple_choice', '["The surveyor who followed the footsteps of the original surveyor and began from recognized original corners","The surveyor with the newest GPS equipment","The surveyor who used the largest claimed acreage","The junior survey, because it was more clearly written"]'::jsonb, 'The surveyor who followed the footsteps of the original surveyor and began from recognized original corners', 'The court adopted Atkinson''s retracement because he began from recognized corners and followed the footsteps of the original surveyor; it rejected surveys that did not. A junior survey must conform to the senior''s lines and calls.', 'hard', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000004', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000021', 'A historic Texas field note calls “N 10° E, 500 varas.” Convert the distance to feet (two decimals), using the statutory vara.', 'numeric_input', '[]'::jsonb, '1388.90', 'Using the statutory vara of 33⅓ in = 2.7778 ft: 500 × 2.7778 = 1388.90 ft.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000022', 'Who is custodian of Texas''s original land-grant records (patents, field notes, sketches) that a surveyor must consult when retracing an original survey?', 'multiple_choice', '["The General Land Office (GLO)","The federal Bureau of Land Management (BLM)","The county tax assessor","The Texas Department of Transportation"]'::jsonb, 'The General Land Office (GLO)', 'The Texas GLO holds the original land-grant archive. The BLM keeps federal PLSS records (irrelevant in Texas, which retained its public lands); the tax assessor and TxDOT are not grant-record custodians.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000023', 'Which clause is the correct device to withhold from a conveyance a parcel previously sold, thereby preserving a senior right?', 'multiple_choice', '["EXCEPTING THEREFROM","TOGETHER WITH","SUBJECT TO","RESERVING THEREFROM"]'::jsonb, 'EXCEPTING THEREFROM', '“EXCEPTING THEREFROM” omits a part of the thing granted and is an important device for preserving senior rights. “Reserving” keeps a new right/easement; “subject to” recognizes an existing right; “together with” adds a right.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000024', 'True or False: Because the Spanish vara measured about 32.9 inches, a Texas surveyor should use 32.9 inches when converting Texas grant varas.', 'true_false', '["True","False"]'::jsonb, 'False', 'Texas fixed the vara by statute at exactly 33⅓ inches (Art. 5730, 1919). Applying a foreign vara value (Spanish ~32.9 in, Mexican ~32.99 in) to a Texas grant yields wrong distances and acreage.', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000025', 'Under Texas law, who may prepare and seal a metes-and-bounds description and monument the boundary?', 'multiple_choice', '["A Registered Professional Land Surveyor (RPLS) or Licensed State Land Surveyor (LSLS)","Any licensed real estate broker","The county clerk","A professional engineer with no surveying license"]'::jsonb, 'A Registered Professional Land Surveyor (RPLS) or Licensed State Land Surveyor (LSLS)', 'Under Occupations Code Ch. 1071, only an RPLS (or LSLS) may prepare/seal a description and delineate/monument boundaries. State-land originals specifically require the LSLS credential.', 'easy', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('d2920730-0000-0000-0000-000000000026', 'Why does Texas treat a stated acreage (area) as the least reliable element of a description?', 'multiple_choice', '["It is the lowest call in the dignity hierarchy — a check on the work, not a control over monuments, courses, or distances","Because acreage cannot be computed accurately","Because Texas measures area only in varas","Because the GLO ignores acreage entirely"]'::jsonb, 'It is the lowest call in the dignity hierarchy — a check on the work, not a control over monuments, courses, or distances', 'In the dignity of calls, quantity/area ranks below monuments, course, and distance. It serves as a check, not a control, which is why area is followed by “more or less.”', 'medium', 'd2920000-0000-0000-0000-000000000007', 'd2920710-0000-0000-0000-000000000005', ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920760-0000-0000-0000-000000000001', 'A deed course is recited as {{quad}} {{ang}} degrees {{min}} minutes (a bearing of {{ang}}°{{min}}'' measured from the {{ns}} meridian toward the {{ew}}). Express this course as an AZIMUTH measured clockwise from north, in decimal degrees.', 'numeric_input', '[]'::jsonb, '0', 'Convert the quadrant bearing {{quad}} ({{base:f2}}°) to azimuth using the rule for its quadrant. The azimuth is {{_answer}}°. (Its back-azimuth would be this ± 180°.)', 'easy', 'd2920000-0000-0000-0000-000000000007', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920750-0000-0000-0000-000000000001', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920760-0000-0000-0000-000000000002', 'A course bears {{nsword}} {{ang}} degrees {{ewword}} for a distance of {{dist:f2}} feet. Compute the magnitude of its {{which}} (the {{axis}} component), in feet.', 'numeric_input', '[]'::jsonb, '0', 'Resolve the course into components: latitude = D·cosβ and departure = D·sinβ, with β = {{ang}}° and D = {{dist:f2}} ft. The requested {{which}} has magnitude {{_answer}} ft. Its sign would be {{nsword}}/{{ewword}} depending on the quadrant.', 'medium', 'd2920000-0000-0000-0000-000000000007', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920750-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920760-0000-0000-0000-000000000003', 'After summing the latitudes and departures of all courses in a closed traverse, a surveyor finds a closure in latitude of ΣLat = {{sumLat:f2}} feet and a closure in departure of ΣDep = {{sumDep:f2}} feet. Compute the linear misclosure (the straight-line gap back to the point of beginning), in feet.', 'numeric_input', '[]'::jsonb, '0', 'The linear misclosure is the hypotenuse of the latitude and departure closures: √({{sumLat:f2}}² + {{sumDep:f2}}²) = {{_answer}} ft. In a perfect figure both sums (and the misclosure) would be zero.', 'medium', 'd2920000-0000-0000-0000-000000000007', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920750-0000-0000-0000-000000000003', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('d2920760-0000-0000-0000-000000000004', 'A triangular parcel has a base of {{base:f2}} feet along a road and a perpendicular height (depth) of {{height:f2}} feet. Compute its area in ACRES (1 acre = 43,560 square feet).', 'numeric_input', '[]'::jsonb, '0', 'A triangle''s area is (base × height) / 2 = ({{base:f2}} × {{height:f2}})/2 = {{sqft:f2}} sq ft. Dividing by 43,560 sq ft/acre gives {{_answer}} acres (which the description would state “more or less”).', 'medium', 'd2920000-0000-0000-0000-000000000007', NULL, ARRAY['land-law','boundary-law','texas','nmsu-sur292','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'd2920750-0000-0000-0000-000000000004', 0.01);
INSERT INTO learning_lessons (id, module_id, title, content, key_takeaways, order_index, estimated_minutes, resources, videos, tags, status, is_published, review_status, content_migrated, description, learning_objectives) VALUES ('d2920710-0000-0000-0000-000000000006', 'd2920000-0000-0000-0000-000000000007', 'Homework & Practice', '', ARRAY[]::text[], 6, 45, '[]'::jsonb, '[]'::jsonb, ARRAY['land-law','boundary-law','texas','nmsu-sur292']::text[], 'published', true, 'approved', true, 'Module homework assignment(s) and practice problems.', ARRAY[]::text[]);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0006-0000-0000-000000000000', 'd2920710-0000-0000-0000-000000000006', 'text', '{"html":"<h2>Homework &amp; Practice</h2><p>Complete the homework below. You may submit a draft up to 48 hours before the deadline for instructor feedback. Use the randomized practice problems to prepare for the quiz.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0006-0000-0000-000000000001', 'd2920710-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 1 — Write and Check a Texas Metes-and-Bounds Description</h3><p><em>Type: computational</em></p><div>**Scenario.** You have surveyed a rectangular 4.00-acre tract carved from the parent tract in the **John Doe Survey, Abstract No. 123, Travis County, Texas**. Your basis of bearing is the Texas State Plane Coordinate System (Central Zone, NAD83). The found southwest corner of the original survey is your point of commencement. From that corner you run **N 00° 00'' E, 250.00 feet** to the southwest corner of your tract (the point of beginning). The tract is a rectangle **417.42 feet (east–west)** by **417.42 feet (north–south)**; its south and north lines bear due East/West and its east and west lines bear due North/South. A 1-inch iron rod is set at each of the four tract corners.<br/><br/>**Tasks.**<br/>1. **Write the complete description.** Include: a proper Texas caption (survey + abstract + county); a “Commencing at …” tie to the POB; the four bounding courses run clockwise (each as a bearing + distance + “to a 1-inch iron rod set”), each ending in a semicolon; a closing call to the point of beginning; the area in acres “more or less”; the basis of bearing; and an “END OF DESCRIPTION.” Follow the composition standards (capitalize and spell out bearings; do not capitalize general directions; colon after the caption, period at the end).<br/>2. **Verify closure.** Compute the latitude and departure of each of the four courses and show that ΣLat = 0 and ΣDep = 0 (a perfect rectangle). Then compute the linear misclosure and confirm it is 0.00 ft.<br/>3. **Verify the area.** Show that 417.42 × 417.42 sq ft ÷ 43,560 ≈ 4.00 acres, justifying the “more or less.”<br/>4. **Convert to varas.** Re-state the 417.42-foot south line in varas (to two decimals) using the statutory Texas vara, as an original 1850s field note might have written it.<br/>5. **Compliance check.** Identify which subsections of 22 TAC Ch. 138 your description satisfies (unambiguous identification; found vs. set monuments; reference to a monumented line/geodetic system) and state who (RPLS or LSLS) is required to seal it, and why.</div>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('d2920720-0006-0000-0000-000000000002', 'd2920710-0000-0000-0000-000000000006', 'text', '{"html":"<h3>Homework 2 — Critique a Defective Description (written + applied)</h3><p><em>Type: mixed</em></p><div>Below is a (deliberately flawed) draft description. Read it critically, then complete the analysis.<br/><br/>> *“That part of Section 12 in the county, beginning at the old oak at the corner of the Smith place; thence about 60 rods to a cedar tree; thence S 30° W to a stake; thence East 400 feet, more or less, to the iron pipe; thence back to the beginning. Containing 5 acres per the tax statement.”*<br/><br/>**Part A — Sufficiency audit (written).** For each of the three sufficiency requirements (must close, must be locatable, must be unambiguous), state whether this description passes or fails and exactly why. Quote the offending language.<br/><br/>**Part B — Defect list.** List at least **five** specific defects, drawing on the composition standards and principles from the module (examples to look for: no caption tie to a GLO survey/abstract, vague/gone monument as the POB, “about” distances, missing basis of bearing, reliance on a tax statement for area, a directional run that may not close, a corner potentially placed on a curve, etc.). For each defect, name the rule it violates.<br/><br/>**Part C — Dignity-of-calls scenario.** Suppose on the ground you find the called-for iron pipe 6.0 ft beyond the recited “400 feet.” State which call controls and why, citing the dignity-of-calls hierarchy and the role of the original surveyor''s footsteps (reference *State v. Franks* or *Stafford v. King*).<br/><br/>**Part D — Rewrite (applied).** Rewrite the description correctly for a Texas parcel: invent reasonable values, give it a proper Texas caption (survey + abstract + county), a “Commencing at” tie to a found corner, four clean courses with monument calls run clockwise, a closing call, an area “more or less,” a stated basis of bearing, a call for the survey, and certification language. Keep it to one parcel and make sure it closes.</div>"}'::jsonb, 2);
